// ─── SUPABASE PROFILE HELPERS ─────────────────────────────────────────────────
async function loadRemoteProfile(userId) {
  try {
    const { data, error } = await supabase
      .from("profiles")
      .select("*")
      .eq("id", userId)
      .single();
    if (error || !data) return null;
    return {
      prs:           data.prs           || {},
      macroGoals:    data.macro_goals   || {},
      macroToday:    data.macro_today   || {},
      sleepDays:     data.sleep_days    || [],
      sleepTarget:   data.sleep_target  || 8,
      lastResetDate: data.last_reset_date || "",
      lastSleepLog:  data.last_sleep_log  || null,
      calories:      data.kailu_goals?.calories || null,
      tdee:          data.kailu_goals?.tdee || null,
      ...(data.kailu_goals || {}),
    };
  } catch { return null; }
}

async function saveRemoteProfile(userId, profile) {
  if (!userId) return;
  try {
    await supabase.from("profiles").upsert({
      id:              userId,
      macro_goals:     profile.macroGoals   || {},
      macro_today:     profile.macroToday   || {},
      sleep_days:      profile.sleepDays    || [],
      sleep_target:    profile.sleepTarget  || 8,
      last_reset_date: profile.lastResetDate || "",
      last_sleep_log:  profile.lastSleepLog  || null,
      prs:             profile.prs          || {},
      kailu_goals:     {
        calories: profile.calories,
        tdee:     profile.tdee,
        macroGoals: profile.macroGoals,
        sleepTarget: profile.sleepTarget,
        reasoning:  profile.reasoning,
      },
    }, { onConflict: "id" });
  } catch (_) {}
}


