// ─── CIRCADIAN INTELLIGENCE ───────────────────────────────────────────────────
function getCircadianState() {
  const h = new Date().getHours();
  if (h >= 5  && h < 8)  return { phase:"Cortisol Surge",       icon:"◉", color:"#FF6B35", advice:"Peak neural activation. Ideal for heavy compound lifts.",       window:"PRIME" };
  if (h >= 8  && h < 11) return { phase:"Anabolic Window",      icon:"⬡", color:"#30D158", advice:"Testosterone at daily peak. Optimal for hypertrophy training.",  window:"PEAK"  };
  if (h >= 11 && h < 14) return { phase:"Cognitive Peak",       icon:"⟡", color:"#5AC8FA", advice:"Dopamine elevated. Best window for skill acquisition.",          window:"HIGH"  };
  if (h >= 14 && h < 17) return { phase:"Thermogenic High",     icon:"◈", color:"#C9A84C", advice:"Core temperature at maximum. Explosive performance available.",  window:"HIGH"  };
  if (h >= 17 && h < 20) return { phase:"Second Wind",          icon:"◣", color:"#0A84FF", advice:"Aerobic capacity peaks. Optimal for cardio protocols.",          window:"PEAK"  };
  if (h >= 20 && h < 23) return { phase:"GH Preparation",       icon:"◑", color:"#BF5AF2", advice:"Growth hormone pre-surge. Prioritize recovery protocols.",       window:"PREP"  };
  return                        { phase:"Cellular Repair",       icon:"∞", color:"#C9A84C", advice:"Deep repair cycle active. Prioritize sleep quality.",            window:"REST"  };
}

function useBioClock() {
  const [state, setState] = useState(getCircadianState());
  useEffect(() => {
    const id = setInterval(() => setState(getCircadianState()), 60000);
    return () => clearInterval(id);
  }, []);
  return state;
}

// ─── WEEK AHEAD FORECAST ──────────────────────────────────────────────────────
function getBioScoreForecast(currentScore, doneThisWeek) {
  const compliance = Math.min((doneThisWeek || 3) / 4, 1);
  const projected  = Math.min(99, Math.round(currentScore * (0.84 + compliance * 0.22)));
  const delta      = projected - currentScore;
  const trend      = delta >= 4 ? "up" : delta <= -4 ? "down" : "steady";
  const msgs = {
    up:     `On your current streak, your bio-score should reach ${projected} by end of week — keep it going.`,
    steady: `You're holding strong at ${currentScore}. One more session could push you to ~${projected}.`,
    down:   `If you miss another session, your score could dip to ${projected}. One workout puts you right back on track.`,
  };
  return { projected, delta, trend, message: msgs[trend] };
}

// ─── VELOCITY NARRATIVE ────────────────────────────────────────────────────────
function getVelocityNarrative(velocityLog) {
  if (!velocityLog || velocityLog.length < 2) return null;
  const speeds = velocityLog
    .map(v => typeof v === "number" ? v : (v.speed || v.velocity || 0))
    .filter(s => s > 0);
  if (speeds.length < 2) return null;
  const first = speeds[0];
  const last  = speeds[speeds.length - 1];
  const drop  = first > 0 ? Math.round(((first - last) / first) * 100) : 0;
  const peak  = Math.max(...speeds);
  const peakIdx = speeds.indexOf(peak) + 1;
  if (drop >= 25) return {
    headline: "Your body hit its limit — in a good way.",
    detail:   `Speed dropped ${drop}% from your first rep to your last. That kind of drop means you fully loaded the muscle — exactly what drives growth. Plan an extra rest day before hitting this movement again.`,
    icon: "⚡", color: "#FF6B35",
  };
  if (drop >= 10) return {
    headline: "Solid session. Load was right.",
    detail:   `You peaked around rep ${peakIdx}. Speed fell ${drop}% through the session — healthy fatigue that tells us the weight was dialed in. Try adding 5% more next time.`,
    icon: "◉", color: "#30D158",
  };
  return {
    headline: "You had more in the tank.",
    detail:   `Speed only dropped ${drop}% — your body wasn't fully pushed today. Try bumping the weight or adding a set next session to get more out of it.`,
    icon: "◈", color: "#0A84FF",
  };
}

