// ─── CIRCADIAN WORKOUT WARNINGS ────────────────────────────────────────────────
function getCircadianWorkoutWarning() {
  const h = new Date().getHours();
  if (h >= 21 || h < 5) return {
    level: "warn", icon: "◑", color: "#FF6B35",
    title: "Late-Night Session",
    msg:   "Training this late raises your stress hormones right when they should be winding down. Try to keep tonight's session shorter and lighter if you can.",
  };
  if (h >= 5 && h < 8) return {
    level: "prime", icon: "◉", color: "#30D158",
    title: "Prime Window Open",
    msg:   "Your cortisol is at its natural daily peak right now — the best possible time for heavy lifting. Make the most of it.",
  };
  return null;
}
function getSupplementTimingNote(biology) {
  const h = new Date().getHours();
  const bottleneck = biology?.bottleneck;
  if (bottleneck === "sleep" && h >= 18) return {
    icon: "◑", color: "#FF9F0A",
    msg: "Your main supplements work best earlier in the day. Taking them now might make it harder to sleep tonight.",
  };
  if (bottleneck === "fog" && h >= 5 && h < 10) return {
    icon: "⬡", color: "#30D158",
    msg: "This is the best window for your focus supplements — your brain chemistry is most receptive right now.",
  };
  return null;
}

function getTimeGreeting(name) {
  const h = new Date().getHours();
  const n = name ? name.split(" ")[0] : null;
  const suffix = n ? `, ${n}` : "";
  if (h >= 5  && h < 12) return `Good morning${suffix}`;
  if (h >= 12 && h < 17) return `Good afternoon${suffix}`;
  if (h >= 17 && h < 21) return `Good evening${suffix}`;
  return `Late session${suffix}`;
}

