// ─── BIO-LOGIC MANIFEST ──────────────────────────────────────────────────────
// Protein multiplier (g per kg bodyweight) per archetype goal
const PROTEIN_MULTIPLIER = {
  vtaper:       1.8,   // lean-mass preservation + lat hypertrophy
  abs:          1.6,   // cut-phase protein sparing
  density:      2.2,   // maximum hypertrophy phase
  athletic:     1.9,   // performance + rapid recovery
  glutes:       1.8,   // posterior chain hypertrophy
  hourglass:    1.6,   // recomposition protocol
  lean_athlete: 1.9,   // recomp + athletic output
  tone_define:  1.5,   // lean phase, moderate hypertrophy
};

// Clinical optimal daily doses (evidence-based thresholds)
const CLINICAL_OPTIMAL = {
  creatine_g:    5,     protein_g_per_kg: 1.8,  omega3_g:     3,
  nad_mg:      300,     vitamin_d_iu:  4000,     magnesium_mg: 400,
  zinc_mg:      25,     collagen_g:      15,
};

function calcProteinReq(weightKg, archetypeId) {
  const mult = PROTEIN_MULTIPLIER[archetypeId] || 1.8;
  return {
    min:     Math.round(weightKg * 1.2),
    optimal: Math.round(weightKg * mult),
    max:     Math.round(weightKg * 2.4),
    mult,
  };
}

function calcHypertrophyScore(perfData) {
  if (!perfData?.all) return null;
  const bench = perfData.all.bench || 0;
  const squat = perfData.all.squat || 0;
  const bw    = perfData.all.bw    || 0;
  if (!bw || bw < 50) return null;
  const benchRatio = bench / bw;
  const squatRatio = squat / bw;
  let score = 58;
  if (benchRatio >= 1.5) score += 16;
  else if (benchRatio >= 1.0) score += 9;
  else if (benchRatio >= 0.75) score += 4;
  if (squatRatio >= 2.0) score += 16;
  else if (squatRatio >= 1.5) score += 10;
  else if (squatRatio >= 1.0) score += 5;
  return Math.min(score, 98);
}

function calcLogicCitation(archetypeId, perfData) {
  if (!perfData?.all) return null;
  const bench = perfData.all.bench || 0;
  const squat = perfData.all.squat || 0;
  const bw    = perfData.all.bw    || 0;
  if (!bw || bw < 50) return null;
  const bwKg  = Math.round(bw * 0.4536);
  const req   = calcProteinReq(bwKg, archetypeId);
  const benchRatio = (bench / bw).toFixed(2);
  const totalLoad  = bench + squat;
  const demand = bench > 0 ? Math.round((bench/bw - 0.75)*35) : 0;
  return (
    `At ${bw}lbs (${bwKg}kg), your clinical protein target is ${req.optimal}g/day `
    + `(${req.mult}g×kg for ${archetypeId.replace('_',' ')} protocol). `
    + (bench > 0
       ? `Your bench-to-bodyweight ratio is ${benchRatio}×, placing your eccentric demand `
         + `${demand > 0 ? demand+'% above' : 'at'} the ${archetypeId.replace('_',' ')} baseline `
         + `— increasing BCAA requirement by ${Math.max(0, Math.round(bwKg * (req.mult - 1.2)))}g/day above minimum.`
       : `Complete your strength baseline to unlock full deficit analysis.`)
  );
}


