// ─── Action types ────────────────────────────────────────────────────────────
const EnvActions = {
  // config
  SET_THEME:        "SET_THEME",
  SET_STORE_NAME:   "SET_STORE_NAME",

  // mode
  SET_MODE:         "SET_MODE",               // { mode, lockedBy? }
  NFC_TAP:          "NFC_TAP",                // { mode, location }
  RESET_MODE:       "RESET_MODE",             // → personal, default

  // flow
  SET_SCREEN:       "SET_SCREEN",
  SET_BIOLOGY:      "SET_BIOLOGY",
  SET_ARCHETYPE:    "SET_ARCHETYPE",
  SET_PERF_DATA:    "SET_PERF_DATA",
  SET_USER:         "SET_USER",

  // inventory
  SET_INVENTORY:    "SET_INVENTORY",
  TOGGLE_INVENTORY: "TOGGLE_INVENTORY",       // { modeKey, arcId, prodId }

  // bio-logic (Phase 3 foundations — safe to dispatch now)
  BIO_LOGIC_UPDATE: "BIO_LOGIC_UPDATE",       // { patch }  — deep-ish merge
  BIO_LOGIC_LOG:    "BIO_LOGIC_LOG",          // { kind, amount, unit, note? }

  // bio-pal (Phase 3)
  BIOPAL_TOGGLE:    "BIOPAL_TOGGLE",
  BIOPAL_SEND:      "BIOPAL_SEND",            // { role, text, intent?, appliedDelta? }
  BIOPAL_PROCESSING:"BIOPAL_PROCESSING",      // { processing }

  // schedule (agentic)
  SCHEDULE_SET_PENDING: "SCHEDULE_SET_PENDING",   // { items }
  SCHEDULE_LOCK:        "SCHEDULE_LOCK",          // commits pending into items
  SCHEDULE_ADD_ITEM:    "SCHEDULE_ADD_ITEM",      // { item }
  SCHEDULE_CLEAR:       "SCHEDULE_CLEAR",
};

// ─── Reducer ─────────────────────────────────────────────────────────────────
function envReducer(state, action) {
  switch (action.type) {
    // ── Config ─────────────────────────────────────
    case EnvActions.SET_THEME: {
      const next = typeof action.theme === "function"
        ? action.theme(state.theme)
        : action.theme;
      return { ...state, theme: next };
    }
    case EnvActions.SET_STORE_NAME:
      return { ...state, storeName: action.storeName };

    // ── Mode & context ─────────────────────────────
    case EnvActions.SET_MODE:
      return {
        ...state,
        mode:         action.mode,
        modeLockedBy: action.lockedBy || "manual",
      };
    case EnvActions.NFC_TAP:
      return {
        ...state,
        mode:         action.mode,
        modeLockedBy: "nfc",
        location:     action.location || state.location,
      };
    case EnvActions.RESET_MODE:
      return {
        ...state,
        mode:         "personal",
        modeLockedBy: "default",
        location:     null,
      };

    // ── Flow ───────────────────────────────────────
    case EnvActions.SET_SCREEN:
      return { ...state, screen: action.screen };
    case EnvActions.SET_BIOLOGY:
      return { ...state, biology: action.biology };
    case EnvActions.SET_ARCHETYPE:
      return { ...state, archetypeId: action.archetypeId };
    case EnvActions.SET_PERF_DATA:
      return { ...state, perfData: action.perfData };
    case EnvActions.SET_USER:
      return { ...state, user: action.user };

    // ── Inventory ──────────────────────────────────
    case EnvActions.SET_INVENTORY:
      return { ...state, inventory: action.inventory };
    case EnvActions.TOGGLE_INVENTORY: {
      const { modeKey, arcId, prodId } = action;
      const inv = state.inventory;
      return {
        ...state,
        inventory: {
          ...inv,
          [modeKey]: {
            ...(inv[modeKey] || {}),
            [arcId]: ((inv[modeKey] || {})[arcId] || []).map(p =>
              p.id === prodId ? { ...p, active: !p.active } : p
            ),
          },
        },
      };
    }

    // ── Bio-Logic ──────────────────────────────────
    case EnvActions.BIO_LOGIC_UPDATE:
      return {
        ...state,
        bioLogic: { ...state.bioLogic, ...(action.patch || {}) },
      };
    case EnvActions.BIO_LOGIC_LOG: {
      const entry = {
        at:     Date.now(),
        kind:   action.kind,
        amount: action.amount,
        unit:   action.unit,
        note:   action.note || "",
      };
      const nutri = state.bioLogic.nutrition;
      const patched = { ...nutri, log: [entry, ...(nutri.log || [])].slice(0, 200) };
      // Fold known macros into cumulative totals
      if (["protein","carbs","fat","fiber","water"].includes(action.kind)) {
        patched[action.kind] = (nutri[action.kind] || 0) + (Number(action.amount) || 0);
      }
      return {
        ...state,
        bioLogic: { ...state.bioLogic, nutrition: patched },
      };
    }

    // ── Bio-Pal ────────────────────────────────────
    case EnvActions.BIOPAL_TOGGLE:
      return {
        ...state,
        biopal: { ...state.biopal, open: typeof action.open === "boolean" ? action.open : !state.biopal.open },
      };
    case EnvActions.BIOPAL_SEND: {
      const msg = {
        role:          action.role || "user",
        text:          action.text || "",
        intent:        action.intent || null,
        appliedDelta:  action.appliedDelta || null,
        at:            Date.now(),
      };
      return {
        ...state,
        biopal: {
          ...state.biopal,
          messages: [...state.biopal.messages, msg].slice(-80),
        },
      };
    }
    case EnvActions.BIOPAL_PROCESSING:
      return {
        ...state,
        biopal: { ...state.biopal, processing: !!action.processing },
      };

    // ── Schedule ───────────────────────────────────
    case EnvActions.SCHEDULE_SET_PENDING:
      return {
        ...state,
        schedule: { ...state.schedule, pending: action.items || [] },
      };
    case EnvActions.SCHEDULE_LOCK: {
      const pending = state.schedule.pending || [];
      const stamped = pending.map((it, i) => ({
        id:        it.id || `s${Date.now()}_${i}`,
        locked:    true,
        createdAt: Date.now(),
        ...it,
      }));
      return {
        ...state,
        schedule: { items: stamped, pending: null },
      };
    }
    case EnvActions.SCHEDULE_ADD_ITEM: {
      const item = {
        id:        action.item?.id || `s${Date.now()}`,
        locked:    true,
        createdAt: Date.now(),
        ...(action.item || {}),
      };
      return {
        ...state,
        schedule: { ...state.schedule, items: [...state.schedule.items, item] },
      };
    }
    case EnvActions.SCHEDULE_CLEAR:
      return { ...state, schedule: { items: [], pending: null } };

    default:
      return state;
  }
}

// ─── Context ─────────────────────────────────────────────────────────────────
const EnvContext = createContext(null);

// ─── Provider ────────────────────────────────────────────────────────────────
function EnvProvider({ children, initialOverrides }) {
  const [state, dispatch] = useReducer(
    envReducer,
    initialOverrides
      ? { ...INITIAL_ENV_STATE, ...initialOverrides }
      : INITIAL_ENV_STATE
  );

  // Memoise convenience action creators so screens don't recreate closures.
  const api = useMemo(() => ({
    setTheme:       (theme)      => dispatch({ type: EnvActions.SET_THEME,       theme }),
    toggleTheme:    ()           => dispatch({ type: EnvActions.SET_THEME,       theme: (t) => t === "dark" ? "light" : "dark" }),
    setStoreName:   (storeName)  => dispatch({ type: EnvActions.SET_STORE_NAME,  storeName }),

    setMode:        (mode, lockedBy) => dispatch({ type: EnvActions.SET_MODE,    mode, lockedBy }),
    nfcTap:         (mode, location) => dispatch({ type: EnvActions.NFC_TAP,     mode, location }),
    resetMode:      ()           => dispatch({ type: EnvActions.RESET_MODE }),

    goto:           (screen)     => dispatch({ type: EnvActions.SET_SCREEN,      screen }),
    setBiology:     (biology)    => dispatch({ type: EnvActions.SET_BIOLOGY,     biology }),
    setArchetype:   (archetypeId)=> dispatch({ type: EnvActions.SET_ARCHETYPE,   archetypeId }),
    setPerfData:    (perfData)   => dispatch({ type: EnvActions.SET_PERF_DATA,   perfData }),
    setUser:        (user)       => dispatch({ type: EnvActions.SET_USER,        user }),

    setInventory:   (inventory)  => dispatch({ type: EnvActions.SET_INVENTORY,   inventory }),
    toggleInventory:(modeKey, arcId, prodId) =>
                                    dispatch({ type: EnvActions.TOGGLE_INVENTORY, modeKey, arcId, prodId }),

    bioLogicUpdate: (patch)      => dispatch({ type: EnvActions.BIO_LOGIC_UPDATE, patch }),
    bioLogicLog:    (entry)      => dispatch({ type: EnvActions.BIO_LOGIC_LOG,    ...entry }),

    biopalToggle:   (open)       => dispatch({ type: EnvActions.BIOPAL_TOGGLE,    open }),
    biopalSend:     (msg)        => dispatch({ type: EnvActions.BIOPAL_SEND,      ...msg }),
    biopalProcessing:(processing)=> dispatch({ type: EnvActions.BIOPAL_PROCESSING, processing }),

    scheduleSetPending: (items)  => dispatch({ type: EnvActions.SCHEDULE_SET_PENDING, items }),
    scheduleLock:       ()       => dispatch({ type: EnvActions.SCHEDULE_LOCK }),
    scheduleAdd:        (item)   => dispatch({ type: EnvActions.SCHEDULE_ADD_ITEM, item }),
    scheduleClear:      ()       => dispatch({ type: EnvActions.SCHEDULE_CLEAR }),
  }), []);

  const value = useMemo(() => ({ state, dispatch, ...api }), [state, api]);

  return (
    <EnvContext.Provider value={value}>
      {children}
    </EnvContext.Provider>
  );
}

// ─── Hooks ───────────────────────────────────────────────────────────────────
function useEnv() {
  const ctx = useContext(EnvContext);
  if (!ctx) {
    // Fail loudly in dev; in production, return a shallow mock so a missing
    // Provider doesn't take down an individual component.
    console.warn("useEnv() called outside <EnvProvider/>");
    return { state: INITIAL_ENV_STATE, dispatch: () => {} };
  }
  return ctx;
}

function useEnvState() {
  return useEnv().state;
}
function useEnvDispatch() {
  return useEnv().dispatch;
}

