// ─── MOBILE VIEWPORT META INJECTOR ───────────────────────────────────────────
// Injects essential mobile/PWA meta tags if not already present in index.html.
(function injectMobileMeta() {
  if (typeof document === "undefined") return;
  const ensure = (name, content, isName = true) => {
    const sel = isName ? `meta[name="${name}"]` : `meta[${name}]`;
    if (!document.querySelector(sel)) {
      const m = document.createElement("meta");
      if (isName) m.name = name; else m.setAttribute(name.split("=")[0], name.split("=")[1] || "");
      m.content = content;
      document.head.appendChild(m);
    }
  };
  ensure("viewport",      "width=device-width, initial-scale=1, viewport-fit=cover, maximum-scale=1");
  ensure("theme-color",   "#0A0A0B");
  ensure("mobile-web-app-capable", "yes");
  ensure("apple-mobile-web-app-capable", "yes");
  ensure("apple-mobile-web-app-status-bar-style", "black-translucent");
  // Content Security Policy — tighten before prod (adjust src as needed)
  const cspContent = [
    "default-src 'self'",
    "script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net https://cdn.mxpnl.com https://js.stripe.com",
    "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
    "font-src 'self' https://fonts.gstatic.com",
    "img-src 'self' data: https:",
    "connect-src 'self' https://*.supabase.co https://api.stripe.com https://api.mixpanel.com wss://*.supabase.co",
    "frame-src https://js.stripe.com",
  ].join("; ");
  if (!document.querySelector('meta[http-equiv="Content-Security-Policy"]')) {
    const csp = document.createElement("meta");
    csp.httpEquiv = "Content-Security-Policy";
    csp.content   = cspContent;
    document.head.appendChild(csp);
  }
  // X-Frame-Options via meta (belt-and-suspenders; real enforcement is server-side)
  ensure("referrer", "strict-origin-when-cross-origin");
})();

