// ─── NEURAL MESH BACKGROUND ───────────────────────────────────────────────────
function NeuralMesh({ theme, accentColor, density = 12 }) {
  const T = D[theme];
  const nodes = useMemo(() => {
    const pts = [];
    for (let i = 0; i < density; i++) {
      pts.push({ x: 5 + Math.random() * 90, y: 5 + Math.random() * 90, delay: Math.random() * 3 });
    }
    return pts;
  }, [density]);
  const edges = useMemo(() => {
    const e = [];
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i+1; j < nodes.length; j++) {
        const d = Math.hypot(nodes[i].x-nodes[j].x, nodes[i].y-nodes[j].y);
        if (d < 38) e.push({ x1:nodes[i].x, y1:nodes[i].y, x2:nodes[j].x, y2:nodes[j].y });
      }
    }
    return e;
  }, [nodes]);
  const ac = accentColor || T.blue;
  return (
    <svg viewBox="0 0 100 100" preserveAspectRatio="xMidYMid slice"
      style={{ position:"absolute", inset:0, width:"100%", height:"100%", pointerEvents:"none" }}>
      {edges.map((e, i) => (
        <line key={i} x1={`${e.x1}%`} y1={`${e.y1}%`} x2={`${e.x2}%`} y2={`${e.y2}%`}
          stroke={ac} strokeWidth=".12" strokeOpacity=".22"/>
      ))}
      {nodes.map((n, i) => (
        <circle key={i} cx={`${n.x}%`} cy={`${n.y}%`} r=".35"
          fill={ac} style={{ animation:`os_neural ${2+n.delay}s ease-in-out infinite`, animationDelay:`${n.delay}s` }}/>
      ))}
    </svg>
  );
}

