// Default fallback
const DEFAULT_MILESTONES = PROTOCOL_MILESTONES.mass_builder;

// ── Body silhouette SVG (used inside A/B comparison) ─────────────────────────
function BodySilhouette({ t, color, cx=55, isRVN=false, week, id="" }) {
  const easeRVN = x => 1 - Math.pow(1-x, 2.2);
  const curve   = isRVN ? easeRVN(t) : t;

  const shoulderGain = isRVN ? 20 : 10;
  const waistLoss    = isRVN ? 8  : 4;
  const chestGain    = isRVN ? 18 : 9;
  const armGain      = isRVN ? 7  : 3.5;

  const sw = 34 + shoulderGain * curve;
  const ww = 30 - waistLoss    * curve;
  const cw = 36 + chestGain    * curve;
  const aw = 13 + armGain      * curve;

  const sL = cx - sw/2; const sR = cx + sw/2;
  const wL = cx - ww/2; const wR = cx + ww/2;
  const cL = cx - cw/2; const cR = cx + cw/2;

  const glowPx    = isRVN ? 6 + curve * 16 : 2;
  const glowAlpha = isRVN ? Math.round((0.25 + curve*0.5)*255).toString(16).padStart(2,"0") : "33";
  const bodyOp    = isRVN ? 0.72 + curve*0.22 : 0.38 + curve*0.2;

  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center" }}>
      <svg width={110} height={195} viewBox="0 0 110 195"
        style={{ overflow:"visible", filter:`drop-shadow(0 0 ${glowPx}px ${color}${glowAlpha})` }}>
        <defs>
          <radialGradient id={`bg${id}`} cx="50%" cy="40%">
            <stop offset="0%" stopColor={color} stopOpacity={isRVN ? 0.45+curve*0.4 : 0.15}/>
            <stop offset="100%" stopColor={color} stopOpacity={0}/>
          </radialGradient>
          {isRVN && (
            <filter id={`aura${id}`}>
              <feGaussianBlur stdDeviation={2+curve*4} result="blur"/>
              <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
          )}
        </defs>
        {isRVN && curve > 0.1 && (
          <ellipse cx={cx} cy={97} rx={sw*0.65} ry={80}
            fill={`url(#bg${id})`} opacity={curve*0.45}/>
        )}
        {/* Head */}
        <circle cx={cx} cy={20} r={12+curve*(isRVN?2.5:1)} fill={color} opacity={bodyOp}/>
        {/* Neck */}
        <rect x={cx-4} y={32} width={8} height={8} fill={color} opacity={bodyOp-0.1}/>
        {/* Torso */}
        <path d={`M ${sL} 40 Q ${cL} 55 ${wL} 93 Q ${cx-ww*0.6} 112 ${wL+4} 122 L ${wR-4} 122 Q ${cx+ww*0.6} 112 ${wR} 93 Q ${cR} 55 ${sR} 40 Z`}
          fill={`url(#bg${id})`} stroke={color} strokeWidth={isRVN?1.7:1.1} opacity={bodyOp}
          filter={isRVN&&curve>0.25?`url(#aura${id})`:undefined}/>
        {/* Arms */}
        <path d={`M ${sL+3} 45 Q ${cx-sw*0.56} 65 ${cx-sw*0.46} 92 Q ${cx-sw*0.44} 106 ${cx-sw*0.37} 120`}
          stroke={color} strokeWidth={aw} strokeLinecap="round" fill="none" opacity={bodyOp-0.05}/>
        <path d={`M ${sR-3} 45 Q ${cx+sw*0.56} 65 ${cx+sw*0.46} 92 Q ${cx+sw*0.44} 106 ${cx+sw*0.37} 120`}
          stroke={color} strokeWidth={aw} strokeLinecap="round" fill="none" opacity={bodyOp-0.05}/>
        {/* Legs */}
        <path d={`M ${wL+4} 122 Q ${cx-ww*0.5} 134 ${cx-ww*0.4} 140 L ${cx-ww*0.3} 183`}
          stroke={color} strokeWidth={14+curve*(isRVN?3:1.5)} strokeLinecap="round" fill="none" opacity={bodyOp-0.1}/>
        <path d={`M ${wR-4} 122 Q ${cx+ww*0.5} 134 ${cx+ww*0.4} 140 L ${cx+ww*0.3} 183`}
          stroke={color} strokeWidth={14+curve*(isRVN?3:1.5)} strokeLinecap="round" fill="none" opacity={bodyOp-0.1}/>
        {/* Striations — RVN only */}
        {isRVN && curve > 0.42 && [[cx-7,52,cx-3,68],[cx+7,52,cx+3,68],[cx-9,65,cx-5,80],[cx+9,65,cx+5,80]].map(([x1,y1,x2,y2],i) => (
          <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={color} strokeWidth={0.9} opacity={(curve-0.38)*1.5}/>
        ))}
        {/* Pulse rings — RVN only at high progress */}
        {isRVN && curve > 0.58 && <>
          <circle cx={cx} cy={82} r={sw*0.58} fill="none" stroke={color} strokeWidth={0.5} opacity={(curve-0.5)*0.5} strokeDasharray="3 4"/>
          <circle cx={cx} cy={82} r={sw*0.72} fill="none" stroke={color} strokeWidth={0.35} opacity={(curve-0.5)*0.3} strokeDasharray="2 5"/>
        </>}
      </svg>
      {/* Week label */}
      <div style={{ fontSize:9, fontWeight:900, color, letterSpacing:".06em", marginTop:2 }}>
        {week===0?"START":week===12?"PEAK":`WK ${week}`}
      </div>
      {isRVN && curve > 0.01 && (
        <div style={{ fontSize:7.5, fontWeight:800, color, opacity:.7, letterSpacing:".1em" }}>
          {curve>0.7?"BIO-OPTIMIZED ✦":curve>0.42?"ACCELERATING ◉":"PRIMING →"}
        </div>
      )}
    </div>
  );
}

