// ── ABBioComparison main component ────────────────────────────────────────────
function ABBioComparison({ archetypeId, theme, color }) {
  const T = D[theme];
  const ac = color || T.blue;
  const [week, setWeek] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [popupMs, setPopupMs] = useState(null);
  const [selectedSupps, setSelectedSupps] = useState(new Set());
  const [activeMilestone, setActiveMilestone] = useState(null);
  const scrollLock = useRef(null);

  // After every render triggered by the slider, restore the scroll position
  // so AnimatePresence mounts don't jump the page
  useEffect(() => {
    if (scrollLock.current) {
      const { el, top } = scrollLock.current;
      el.scrollTop = top;
      scrollLock.current = null;
    }
  });

  const lockScroll = (e) => {
    let el = e.target.parentElement;
    while (el && el !== document.body) {
      const ov = window.getComputedStyle(el).overflowY;
      if (ov === "auto" || ov === "scroll") {
        scrollLock.current = { el, top: el.scrollTop };
        break;
      }
      el = el.parentElement;
    }
  };

  const milestones = PROTOCOL_MILESTONES[archetypeId] || PROTOCOL_MILESTONES.mass_builder;

  const archLabels = {
    mass_builder:"Mass Builder", core_definition:"Core Definition",
    athletic_performance:"Athletic Performance", longevity:"Cellular Longevity",
    fat_loss:"Fat Loss", muscle_build:"Muscle Build",
    smoothie:"Smoothie Formula", vtaper:"V-Taper", abs:"Abs Definition",
    density:"Lean Mass Density", athletic:"Athletic Power",
  };
  const label = archLabels[archetypeId] || "Performance Protocol";

  const easeRVN = x => 1 - Math.pow(1-x, 2.2);
  const t    = week / 12;
  const rvnT = easeRVN(t);
  const stdT = t;
  const rvnPct = Math.round(rvnT * 100);
  const stdPct = Math.round(stdT * 100);
  const advDelta = Math.round((rvnT - stdT) * 100);

  const runAnimation = () => {
    if (animating) return;
    setAnimating(true); setWeek(0); setPopupMs(null); setActiveMilestone(null);
    let w = 0;
    const MILESTONE_WEEKS = new Set([3, 6, 9, 12]);
    const WEEK_SPEED = 520;
    const PAUSE_DURATION = 2800;
    const step = () => {
      w++; setWeek(w);
      if (MILESTONE_WEEKS.has(w)) {
        setPopupMs(w);
        setActiveMilestone(milestones.findIndex(m => m.week === w));
        if (w < 12) {
          setTimeout(() => { setPopupMs(null); setTimeout(step, 200); }, PAUSE_DURATION);
        } else {
          setTimeout(() => setAnimating(false), PAUSE_DURATION);
        }
      } else {
        if (w < 12) setTimeout(step, WEEK_SPEED);
        else setAnimating(false);
      }
    };
    setTimeout(step, 300);
  };

  // Shared chart builder — RVN peaks at 88% chart height, standard at 28%
  // This makes the visual gap obvious: supplements end ~3x higher
  const chartW = 280; const chartH = 110;
  const RVN_PEAK = 0.88;  // fraction of chartH the RVN line reaches at week 12
  const STD_PEAK = 0.26;  // fraction of chartH the standard line reaches at week 12
  const buildPoints = (isRVN) => Array.from({length:13}, (_,i) => {
    const p = i/12;
    const v = isRVN ? easeRVN(p) * RVN_PEAK : p * STD_PEAK;
    return `${(i/12)*chartW},${chartH - v*chartH}`;
  }).join(" ");
  const rvnPoints = buildPoints(true);
  const stdPoints = buildPoints(false);
  const rvnX = (week/12)*chartW; const rvnY = chartH - easeRVN(t)*RVN_PEAK*chartH;
  const stdX = (week/12)*chartW; const stdY = chartH - t*STD_PEAK*chartH;
  const MS_WEEKS = [3,6,9,12];
  // Final gain labels from milestone data
  const finalMs = milestones[milestones.length-1];
  const rvnFinalLabel  = finalMs?.rvn  || "+100%";
  const stdFinalLabel  = finalMs?.std  || "+30%";

  // ── Section renderer ────────────────────────────────────────────
  const renderSection = (isRVN) => {
    const sColor  = isRVN ? ac : T.muted;
    const pts     = isRVN ? rvnPoints : stdPoints;
    const dotX    = isRVN ? rvnX : stdX;
    const dotY    = isRVN ? rvnY : stdY;
    const pct     = isRVN ? rvnPct : stdPct;
    const curMs   = (() => {
      for (let i = milestones.length-1; i>=0; i--)
        if (week >= milestones[i].week) return milestones[i];
      return null;
    })();

    return (
      <div style={{ marginBottom:18 }}>
        {/* Section header */}
        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
          <div style={{ flex:1, height:1, background:`${sColor}33` }}/>
          <div style={{ fontSize:8.5, fontWeight:900, color:sColor, letterSpacing:".16em",
            padding:"3px 10px", border:`1px solid ${sColor}44`,
            borderRadius:20, whiteSpace:"nowrap" }}>
            {isRVN ? "✦ WITH RVN VISION PROTOCOL" : "◌ WITHOUT SUPPLEMENTS · STANDARD"}
          </div>
          <div style={{ flex:1, height:1, background:`${sColor}33` }}/>
        </div>

        {/* Trajectory chart */}
        <div style={{ background:T.glass, border:`1.5px solid ${isRVN ? ac+"44" : T.border}`,
          borderRadius:14, padding:"12px 14px 10px", marginBottom:10, overflow:"hidden",
          boxShadow: isRVN ? `0 0 24px ${ac}18` : "none" }}>
          <div style={{ fontSize:8, fontWeight:800, color:isRVN ? ac : T.faint,
            letterSpacing:".14em", marginBottom:8 }}>
            {isRVN ? "◉ RVN VISION TRAJECTORY · EXPONENTIAL CURVE" : "◉ STANDARD TRAJECTORY · LINEAR"}
          </div>
          <svg width="100%" viewBox={`0 0 ${chartW} ${chartH+4}`}
            style={{ overflow:"visible", display:"block" }}>
            <defs>
              <linearGradient id={isRVN?"rvnGradB":"stdGradB"} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={sColor} stopOpacity={isRVN?"0.35":"0.12"}/>
                <stop offset="100%" stopColor={sColor} stopOpacity="0"/>
              </linearGradient>
              {isRVN && (
                <filter id="rvnGlow2">
                  <feGaussianBlur stdDeviation="1.5" result="blur"/>
                  <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
                </filter>
              )}
            </defs>
            {/* Grid */}
            {[0,25,50,75,100].map(pct => (
              <line key={pct} x1={0} y1={chartH*(1-pct/100)} x2={chartW} y2={chartH*(1-pct/100)}
                stroke={T.border} strokeWidth={0.5} strokeDasharray="3 4"/>
            ))}
            {/* Milestone verticals */}
            {MS_WEEKS.map(w => {
              const ms = milestones.find(m=>m.week===w);
              return (
                <g key={w}>
                  <line x1={(w/12)*chartW} y1={0} x2={(w/12)*chartW} y2={chartH}
                    stroke={isRVN ? (ms?.color||T.border) : T.border}
                    strokeWidth={0.8} strokeDasharray="2 3" opacity={isRVN?0.7:0.3}/>
                  <text x={(w/12)*chartW+2} y={8} fontSize={6}
                    fill={isRVN ? (ms?.color||T.faint) : T.faint}
                    fontWeight="800" fontFamily="system-ui,sans-serif">WK{w}</text>
                </g>
              );
            })}
            {/* Area fill */}
            <polygon points={`0,${chartH} ${pts} ${chartW},${chartH}`}
              fill={`url(#${isRVN?"rvnGradB":"stdGradB"})`}/>
            {/* Curve */}
            <polyline points={pts} fill="none" stroke={sColor}
              strokeWidth={isRVN?2.4:1.6}
              strokeDasharray={isRVN?"none":"5 4"}
              strokeLinejoin="round"
              filter={isRVN?"url(#rvnGlow2)":undefined}
              opacity={isRVN?1:0.6}/>
            {/* Live dot */}
            {week > 0 && (
              <circle cx={dotX} cy={dotY} r={isRVN?5:4} fill={sColor}
                style={{ filter: isRVN ? `drop-shadow(0 0 6px ${ac})` : "none" }}/>
            )}
            {/* Y-axis labels — show actual gain endpoints */}
            <text x={1} y={chartH-1} fontSize={6} fill={T.faint} fontFamily="system-ui,sans-serif">0</text>
            {isRVN && (
              <text x={1} y={chartH - RVN_PEAK*chartH + 10} fontSize={7} fontWeight="800"
                fill={sColor} fontFamily="system-ui,sans-serif">{rvnFinalLabel}</text>
            )}
            {!isRVN && (
              <text x={1} y={chartH - STD_PEAK*chartH + 10} fontSize={7} fontWeight="700"
                fill={sColor} fontFamily="system-ui,sans-serif">{stdFinalLabel}</text>
            )}
            {/* End-point marker line */}
            <line x1={0} y1={isRVN ? chartH-RVN_PEAK*chartH : chartH-STD_PEAK*chartH}
              x2={chartW} y2={isRVN ? chartH-RVN_PEAK*chartH : chartH-STD_PEAK*chartH}
              stroke={sColor} strokeWidth={0.5} strokeDasharray="4 6" opacity={0.35}/>
          </svg>
          {/* Progress bar */}
          <div style={{ margin:"8px 0 2px" }}>
            <div style={{ display:"flex", justifyContent:"space-between",
              fontSize:8, color:isRVN?ac:T.muted, fontWeight:700, marginBottom:3 }}>
              <span>Week 0</span>
              <span style={{ fontSize:11, fontWeight:900 }}>{pct}% Progress</span>
              <span>Week 12</span>
            </div>
            <div style={{ height:4, background:T.border, borderRadius:2, overflow:"hidden" }}>
              <motion.div style={{ height:"100%", width:`${pct}%`,
                background: isRVN
                  ? `linear-gradient(90deg,${ac},#FFD700)`
                  : T.muted,
                boxShadow: isRVN ? `0 0 8px ${ac}` : "none",
                borderRadius:2 }}
                transition={{ duration:.15 }}/>
            </div>
          </div>
        </div>

        {/* Body silhouette centered */}
        <div style={{ display:"flex", flexDirection:"column", alignItems:"center",
          background:T.glass, border:`1px solid ${isRVN ? ac+"33" : T.border}`,
          borderRadius:14, padding:"16px 12px 10px", marginBottom:10,
          boxShadow: isRVN ? `0 0 20px ${ac}14` : "none" }}>
          <div style={{ fontSize:7.5, fontWeight:900, letterSpacing:".12em",
            color:isRVN ? ac : T.faint, marginBottom:8, textAlign:"center" }}>
            {isRVN ? "RVN VISION BODY · BIO-OPTIMIZED" : "STANDARD · NO PROTOCOL"}
          </div>
          <div style={{ display:"flex", justifyContent:"center", alignItems:"center",
            width:"100%" }}>
            <BodySilhouette t={t} color={sColor}
              cx={55} isRVN={isRVN} week={week} id={isRVN?"rvn3":"std3"}/>
          </div>
          <div style={{ fontSize:11, fontWeight:900, color:sColor, marginTop:6,
            textAlign:"center" }}>
            {week===0 ? "BASELINE" : week===12
              ? (isRVN ? "PEAK — PROTOCOL COMPLETE" : "STANDARD RESULT")
              : `WEEK ${week}`}
          </div>
        </div>

        {/* Milestone tiles for this section */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:6 }}>
          {milestones.map((ms, i) => {
            const isActive = week >= ms.week;
            const isCurrent = week >= ms.week && (i===milestones.length-1 || week < milestones[i+1].week);
            const tileColor = isRVN ? ms.color : T.muted;
            const val = isRVN ? ms.rvn : ms.std;
            return (
              <motion.div key={ms.week}
                animate={{ scale: isCurrent ? 1.02 : 1 }}
                transition={{ duration:.3 }}
                onClick={() => setActiveMilestone(activeMilestone===i?null:i)}
                style={{ cursor:"pointer", borderRadius:12, overflow:"hidden",
                  border:`1.5px solid ${isActive ? tileColor+"55" : T.border}`,
                  background: isActive && isRVN
                    ? `linear-gradient(135deg,${ms.color}16 0%,${T.glass} 100%)`
                    : T.glass,
                  opacity: isActive ? 1 : 0.38,
                  boxShadow: (isCurrent && isRVN) ? `0 0 18px ${ms.color}33` : "none" }}>
                <div style={{ padding:"10px 10px 8px" }}>
                  <div style={{ display:"flex", alignItems:"center",
                    justifyContent:"space-between", marginBottom:4 }}>
                    <div style={{ fontSize:8, fontWeight:900, color:tileColor,
                      letterSpacing:".1em" }}>WK {ms.week}</div>
                    {isCurrent && isRVN && (
                      <motion.div animate={{ opacity:[0.7,1,0.7] }}
                        transition={{ duration:1.2, repeat:Infinity }}
                        style={{ fontSize:7, fontWeight:900, color:ms.color,
                          background:`${ms.color}22`, padding:"1px 6px", borderRadius:8 }}>
                        ACTIVE
                      </motion.div>
                    )}
                  </div>
                  {isRVN && (
                    <div style={{ fontSize:10, fontWeight:900, color:T.text,
                      lineHeight:1.2, marginBottom:5 }}>{ms.supp}</div>
                  )}
                  <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
                    <div style={{ fontSize:8, color:T.faint }}>{ms.metric}:</div>
                    <div style={{ fontSize:13, fontWeight:900, color:tileColor }}>{val}</div>
                  </div>
                </div>
                <AnimatePresence>
                  {isRVN && (activeMilestone===i || isCurrent) && isActive && (
                    <motion.div
                      initial={{ height:0, opacity:0 }}
                      animate={{ height:"auto", opacity:1 }}
                      exit={{ height:0, opacity:0 }}
                      transition={{ duration:.25 }}
                      style={{ borderTop:`1px solid ${ms.color}33`,
                        padding:"8px 10px", fontSize:10,
                        color:T.muted, lineHeight:1.6 }}>
                      {ms.why}
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            );
          })}
        </div>
      </div>
    );
  };

  // ── Custom Stack Section ──────────────────────────────────────────────────
  const renderCustomSection = () => {
    const catalog = SUPPLEMENT_CATALOG[archetypeId] || SUPPLEMENT_CATALOG.mass_builder;
    const customColor = "#A855F7";

    const customProgress = (w) => {
      const p = w / 12;
      const std = p;
      const rvn = easeRVN(p);
      const totalW = catalog.reduce((s, x) => s + x.weight, 0);
      const selW   = catalog.reduce((s, x) => selectedSupps.has(x.id) && w >= x.week ? s + x.weight : s, 0);
      const frac   = totalW > 0 ? Math.min(selW / totalW, 1) : 0;
      return std + (rvn - std) * frac;
    };

    const customPts = Array.from({length:13}, (_,i) => {
      const v = customProgress(i);
      return `${(i/12)*chartW},${chartH - v*chartH}`;
    }).join(" ");

    const cPct   = Math.round(customProgress(week) * 100);
    const sDot   = { x:(week/12)*chartW, y: chartH - (week/12)*chartH };
    const rDot   = { x:(week/12)*chartW, y: chartH - easeRVN(week/12)*chartH };
    const cDot   = { x:(week/12)*chartW, y: chartH - customProgress(week)*chartH };
    const deltaVsStd = cPct - Math.round((week/12)*100);
    const deltaVsRvn = cPct - Math.round(easeRVN(week/12)*100);

    return (
      <div>
        {/* Section divider */}
        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:12 }}>
          <div style={{ flex:1, height:1, background:`${customColor}33` }}/>
          <div style={{ fontSize:8.5, fontWeight:900, color:customColor, letterSpacing:".16em",
            padding:"3px 12px", border:`1px solid ${customColor}55`,
            borderRadius:20, whiteSpace:"nowrap",
            boxShadow:`0 0 14px ${customColor}33` }}>
            ◈ BUILD YOUR CUSTOM STACK
          </div>
          <div style={{ flex:1, height:1, background:`${customColor}33` }}/>
        </div>

        {/* Supplement Picker */}
        <div style={{ background:T.glass, border:`1.5px solid ${customColor}44`,
          borderRadius:14, padding:"12px 14px", marginBottom:10,
          boxShadow:`0 0 20px ${customColor}1A` }}>
          <div style={{ display:"flex", alignItems:"center",
            justifyContent:"space-between", marginBottom:10 }}>
            <div>
              <div style={{ fontSize:8.5, fontWeight:900, color:customColor,
                letterSpacing:".14em", marginBottom:2 }}>SELECT YOUR SUPPLEMENTS</div>
              <div style={{ fontSize:9.5, color:T.muted }}>Stack any combination — chart updates live</div>
            </div>
            <div style={{ display:"flex", gap:6 }}>
              <motion.button whileTap={{ scale:.93 }}
                onClick={() => setSelectedSupps(new Set(catalog.map(s=>s.id)))}
                style={{ fontSize:8.5, padding:"4px 10px", borderRadius:10, cursor:"pointer",
                  border:`1px solid ${ac}55`, background:`${ac}18`, color:ac, fontWeight:700 }}>
                Full Stack
              </motion.button>
              <motion.button whileTap={{ scale:.93 }}
                onClick={() => setSelectedSupps(new Set())}
                style={{ fontSize:8.5, padding:"4px 10px", borderRadius:10, cursor:"pointer",
                  border:`1px solid ${T.border}`, background:T.glass, color:T.faint, fontWeight:700 }}>
                Clear
              </motion.button>
            </div>
          </div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:7 }}>
            {catalog.map(s => {
              const on = selectedSupps.has(s.id);
              return (
                <motion.button key={s.id} whileTap={{ scale:.91 }}
                  onClick={() => setSelectedSupps(prev => {
                    const n = new Set(prev); on ? n.delete(s.id) : n.add(s.id); return n;
                  })}
                  style={{ padding:"6px 12px", borderRadius:22, cursor:"pointer",
                    border:`1.5px solid ${on ? s.color : T.border}`,
                    background: on ? `${s.color}22` : T.glass,
                    color: on ? s.color : T.muted,
                    fontSize:10, fontWeight:700,
                    boxShadow: on ? `0 0 14px ${s.color}44` : "none",
                    transition:"all .18s" }}>
                  {on && <span style={{ marginRight:4 }}>✓</span>}
                  {s.name}
                  <span style={{ fontSize:8, opacity:.7, marginLeft:5 }}>WK{s.week}</span>
                </motion.button>
              );
            })}
          </div>
          <div style={{ marginTop:10 }}>
            <div style={{ display:"flex", justifyContent:"space-between",
              fontSize:8, color:T.faint, marginBottom:3 }}>
              <span>{selectedSupps.size} of {catalog.length} supplements selected</span>
              <span style={{ color:customColor, fontWeight:700 }}>
                {Math.round(catalog.reduce((s,x) => selectedSupps.has(x.id) ? s+x.weight : s, 0) * 100)}% of max stack
              </span>
            </div>
            <div style={{ height:4, background:T.border, borderRadius:2, overflow:"hidden" }}>
              <motion.div style={{ height:"100%", borderRadius:2,
                background:`linear-gradient(90deg,${customColor},#EC4899)`,
                boxShadow:`0 0 8px ${customColor}`,
                width:`${Math.round(catalog.reduce((s,x) => selectedSupps.has(x.id) ? s+x.weight : s, 0) * 100)}%` }}
                transition={{ duration:.2 }}/>
            </div>
          </div>
        </div>

        {/* 3-Line Chart */}
        <div style={{ background:T.glass, border:`1.5px solid ${customColor}44`,
          borderRadius:14, padding:"12px 14px 10px", marginBottom:10,
          boxShadow:`0 0 20px ${customColor}18` }}>
          <div style={{ fontSize:8, fontWeight:800, color:customColor,
            letterSpacing:".14em", marginBottom:8 }}>◉ YOUR CUSTOM STACK TRAJECTORY</div>
          <svg width="100%" viewBox={`0 0 ${chartW} ${chartH+4}`}
            style={{ overflow:"visible", display:"block" }}>
            <defs>
              <linearGradient id="custFill" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={customColor} stopOpacity="0.3"/>
                <stop offset="100%" stopColor={customColor} stopOpacity="0"/>
              </linearGradient>
              <filter id="custGlow">
                <feGaussianBlur stdDeviation="1.8" result="b"/>
                <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
              </filter>
            </defs>
            {[0,25,50,75,100].map(p => (
              <line key={p} x1={0} y1={chartH*(1-p/100)} x2={chartW} y2={chartH*(1-p/100)}
                stroke={T.border} strokeWidth={0.5} strokeDasharray="3 4"/>
            ))}
            {catalog.filter(s => selectedSupps.has(s.id)).map(s => (
              <g key={s.id}>
                <line x1={(s.week/12)*chartW} y1={0} x2={(s.week/12)*chartW} y2={chartH}
                  stroke={s.color} strokeWidth={0.8} strokeDasharray="2 3" opacity={0.5}/>
                <text x={(s.week/12)*chartW+2} y={chartH-3} fontSize={5.5}
                  fill={s.color} fontWeight="800" fontFamily="system-ui,sans-serif" opacity={0.8}>▲</text>
              </g>
            ))}
            <polyline points={stdPoints} fill="none" stroke={T.muted}
              strokeWidth={1.2} strokeDasharray="5 4" opacity={0.35}/>
            <polyline points={rvnPoints} fill="none" stroke={ac}
              strokeWidth={1.4} strokeDasharray="3 3" opacity={0.45}/>
            <polygon points={`0,${chartH} ${customPts} ${chartW},${chartH}`}
              fill="url(#custFill)"/>
            <polyline points={customPts} fill="none" stroke={customColor}
              strokeWidth={2.6} strokeLinejoin="round" filter="url(#custGlow)"/>
            {week > 0 && <>
              <circle cx={sDot.x} cy={sDot.y} r={3.5} fill={T.muted} opacity={0.5}/>
              <circle cx={rDot.x} cy={rDot.y} r={3.5} fill={ac} opacity={0.5}/>
              <circle cx={cDot.x} cy={cDot.y} r={5.5} fill={customColor}
                style={{ filter:`drop-shadow(0 0 7px ${customColor})` }}/>
            </>}
            <text x={1} y={chartH-1} fontSize={6} fill={T.faint} fontFamily="system-ui,sans-serif">0%</text>
            <text x={1} y={7} fontSize={6} fill={T.faint} fontFamily="system-ui,sans-serif">100%</text>
          </svg>
          <div style={{ display:"flex", gap:12, marginTop:7, flexWrap:"wrap" }}>
            {[
              { color:T.muted,    label:"Standard (no supps)", dash:true },
              { color:ac,         label:"Full RVN Protocol",   dash:true },
              { color:customColor,label:"Your Stack",          dash:false },
            ].map(({color,label,dash}) => (
              <div key={label} style={{ display:"flex", alignItems:"center",
                gap:5, fontSize:8.5, color, fontWeight: dash?400:700 }}>
                <div style={{ width:16, height: dash?1.5:2.5, background:color,
                  borderRadius:1, opacity: dash?0.5:1,
                  boxShadow: !dash ? `0 0 6px ${color}` : "none" }}/>
                {label}
              </div>
            ))}
          </div>
          <div style={{ marginTop:10 }}>
            <div style={{ display:"flex", justifyContent:"space-between",
              fontSize:8, color:customColor, fontWeight:700, marginBottom:3 }}>
              <span>Your Stack · Week {week}</span>
              <span style={{ fontSize:13, fontWeight:900 }}>{cPct}%</span>
            </div>
            <div style={{ height:5, background:T.border, borderRadius:3, overflow:"hidden" }}>
              <motion.div style={{ height:"100%", borderRadius:3,
                background:`linear-gradient(90deg,${customColor},#EC4899)`,
                boxShadow:`0 0 10px ${customColor}`, width:`${cPct}%` }}
                transition={{ duration:.15 }}/>
            </div>
            {week > 0 && (
              <div style={{ display:"flex", justifyContent:"space-between", marginTop:5, gap:6 }}>
                <div style={{ flex:1, background:`${T.muted}18`, borderRadius:8, padding:"5px 8px", textAlign:"center" }}>
                  <div style={{ fontSize:7.5, color:T.faint, marginBottom:1 }}>vs Standard</div>
                  <div style={{ fontSize:13, fontWeight:900, color:T.muted }}>+{deltaVsStd}%</div>
                </div>
                <div style={{ flex:1, background:`${customColor}14`, borderRadius:8, padding:"5px 8px", textAlign:"center" }}>
                  <div style={{ fontSize:7.5, color:T.faint, marginBottom:1 }}>vs Full RVN</div>
                  <div style={{ fontSize:13, fontWeight:900, color:customColor }}>
                    {deltaVsRvn >= 0 ? "+" : ""}{deltaVsRvn}%
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Per-supplement science cards */}
        <div style={{ marginBottom:6 }}>
          <div style={{ fontSize:8.5, fontWeight:800, color:T.faint,
            letterSpacing:".14em", marginBottom:10 }}>
            ◉ SUPPLEMENT SCIENCE · WHY EACH ONE WORKS
          </div>
          {catalog.map((s) => {
            const on      = selectedSupps.has(s.id);
            const fired   = on && week >= s.week;
            const pending = on && week < s.week;
            const wLeft   = Math.max(0, s.week - week);
            return (
              <motion.div key={s.id}
                animate={{ opacity: on ? 1 : 0.28, y: on ? 0 : 2 }}
                transition={{ duration:.22 }}
                style={{ marginBottom:9, borderRadius:13, overflow:"hidden",
                  border:`1.5px solid ${fired ? s.color+"77" : pending ? s.color+"33" : T.border}`,
                  background: fired
                    ? `linear-gradient(135deg,${s.color}18 0%,${T.glass} 100%)`
                    : T.glass,
                  boxShadow: fired ? `0 0 20px ${s.color}28` : "none" }}>
                <div style={{ padding:"11px 13px" }}>
                  <div style={{ display:"flex", alignItems:"flex-start",
                    justifyContent:"space-between", gap:8 }}>
                    <div style={{ flex:1 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:4 }}>
                        <div style={{ width:7, height:7, borderRadius:"50%", background:s.color,
                          flexShrink:0, boxShadow: fired ? `0 0 7px ${s.color}` : "none" }}/>
                        <div style={{ fontSize:8.5, fontWeight:900, letterSpacing:".1em",
                          color: fired ? s.color : pending ? s.color+"88" : T.faint }}>
                          {fired ? `✓ WK ${s.week} — ACTIVE`
                           : pending ? `⏳ ACTIVATES WK ${s.week} · ${wLeft}wk away`
                           : `WK ${s.week}`}
                        </div>
                        {!on && (
                          <div style={{ fontSize:7, color:T.faint, opacity:.5,
                            padding:"1px 6px", background:T.glass, borderRadius:6 }}>
                            NOT IN STACK
                          </div>
                        )}
                      </div>
                      <div style={{ fontSize:12.5, fontWeight:900, color:T.text,
                        lineHeight:1.2, marginBottom: on ? 8 : 0 }}>{s.name}</div>
                    </div>
                    <div style={{ textAlign:"right", flexShrink:0 }}>
                      <div style={{ fontSize:8, color:T.faint, marginBottom:2 }}>{s.metric}</div>
                      <div style={{ fontSize:18, fontWeight:900, color: on ? s.color : T.muted,
                        textShadow: fired ? `0 0 14px ${s.color}88` : "none" }}>{s.value}</div>
                      <div style={{ fontSize:7.5, color:T.faint }}>{Math.round(s.weight*100)}% stack weight</div>
                    </div>
                  </div>
                  {on && (
                    <motion.div initial={{ opacity:0, height:0 }} animate={{ opacity:1, height:"auto" }}
                      style={{ fontSize:11, color: fired ? T.text : T.muted,
                        lineHeight:1.7, borderLeft:`2px solid ${s.color}55`, paddingLeft:10 }}>
                      {s.why}
                    </motion.div>
                  )}
                </div>
                {on && (
                  <div style={{ padding:"0 13px 10px" }}>
                    <div style={{ fontSize:7.5, color:T.faint, marginBottom:3 }}>
                      {fired
                        ? `Active since week ${s.week} · contributing to your curve`
                        : `Activates at week ${s.week} · loading phase in progress`}
                    </div>
                    <div style={{ height:3, background:T.border, borderRadius:2 }}>
                      <motion.div
                        animate={{ width: fired
                          ? `${Math.min(100, Math.round(((week-s.week)/(12-s.week+0.01))*100))}%`
                          : "0%" }}
                        transition={{ duration:.5 }}
                        style={{ height:"100%", borderRadius:2,
                          background:`linear-gradient(90deg,${s.color}88,${s.color})`,
                          boxShadow:`0 0 4px ${s.color}88` }}/>
                    </div>
                  </div>
                )}
              </motion.div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div>
      {/* ─ Header ─ */}
      <div style={{ marginBottom:14 }}>
        <div style={{ fontSize:8.5, fontWeight:800, color:T.faint,
          letterSpacing:".16em", marginBottom:3 }}>◉ 12-WEEK TRANSFORMATION ANALYSIS</div>
        <div style={{ fontSize:17, fontWeight:900, color:T.text, lineHeight:1.1 }}>
          Without Supplements{" "}
          <span style={{ color:T.faint, fontWeight:400 }}>vs</span>{" "}
          <span style={{ color:ac }}>RVN VISION Protocol</span>
        </div>
        <div style={{ fontSize:10, color:T.muted, marginTop:3 }}>{label} · Both paths on the same timeline</div>
      </div>

      {/* ─ Combined divergence chart — both lines on same axes ─ */}
      <div style={{ background:T.glass, border:`1.5px solid ${ac}44`,
        borderRadius:14, padding:"14px 14px 10px", marginBottom:14,
        boxShadow:`0 0 28px ${ac}14` }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
          <div style={{ fontSize:8, fontWeight:900, color:ac, letterSpacing:".13em" }}>◉ DIVERGENCE CHART</div>
          <div style={{ display:"flex", gap:10 }}>
            <div style={{ display:"flex", alignItems:"center", gap:4 }}>
              <div style={{ width:16, height:2.5, background:ac, borderRadius:2 }}/>
              <span style={{ fontSize:7.5, color:ac, fontWeight:800 }}>WITH SUPPLEMENTS</span>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:4 }}>
              <div style={{ width:16, height:1.5, background:T.muted, borderRadius:2,
                backgroundImage:`repeating-linear-gradient(90deg,${T.muted} 0 4px,transparent 4px 8px)` }}/>
              <span style={{ fontSize:7.5, color:T.muted, fontWeight:700 }}>WITHOUT</span>
            </div>
          </div>
        </div>
        <svg width="100%" viewBox={`0 0 ${chartW} ${chartH+16}`} style={{ overflow:"visible", display:"block" }}>
          <defs>
            <linearGradient id="divRvnGrad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={ac} stopOpacity="0.3"/>
              <stop offset="100%" stopColor={ac} stopOpacity="0.02"/>
            </linearGradient>
            <filter id="divGlow">
              <feGaussianBlur stdDeviation="1.8" result="blur"/>
              <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
          </defs>
          {/* Grid lines */}
          {[0,25,50,75,100].map(p => (
            <line key={p} x1={0} y1={chartH*(1-p/100)} x2={chartW} y2={chartH*(1-p/100)}
              stroke={T.border} strokeWidth={0.4} strokeDasharray="3 5"/>
          ))}
          {/* Milestone verticals */}
          {MS_WEEKS.map(w => (
            <g key={w}>
              <line x1={(w/12)*chartW} y1={0} x2={(w/12)*chartW} y2={chartH}
                stroke={milestones.find(m=>m.week===w)?.color||T.border}
                strokeWidth={0.7} strokeDasharray="2 4" opacity={0.5}/>
              <text x={(w/12)*chartW+2} y={9} fontSize={6} fill={T.faint}
                fontWeight="800" fontFamily="system-ui,sans-serif">WK{w}</text>
            </g>
          ))}
          {/* Gap fill between the two lines */}
          <polygon
            points={`0,${chartH} ${rvnPoints} ${chartW},${chartH} ${[...Array(13)].map((_,i) => {
              const p=(12-i)/12; const v=p*STD_PEAK;
              return `${((12-i)/12)*chartW},${chartH-v*chartH}`;
            }).join(" ")}`}
            fill={ac} opacity={0.07}/>
          {/* Standard line (dashed, muted) */}
          <polyline points={stdPoints} fill="none" stroke={T.muted}
            strokeWidth={1.6} strokeDasharray="5 4" strokeLinejoin="round" opacity={0.7}/>
          {/* RVN area fill */}
          <polygon points={`0,${chartH} ${rvnPoints} ${chartW},${chartH}`}
            fill="url(#divRvnGrad)"/>
          {/* RVN line (solid, glowing) */}
          <polyline points={rvnPoints} fill="none" stroke={ac}
            strokeWidth={2.6} strokeLinejoin="round" filter="url(#divGlow)"/>
          {/* Live dots */}
          {week > 0 && <>
            <circle cx={rvnX} cy={rvnY} r={5.5} fill={ac}
              style={{ filter:`drop-shadow(0 0 7px ${ac})` }}/>
            <circle cx={stdX} cy={stdY} r={3.5} fill={T.muted} opacity={0.8}/>
          </>}
          {/* End labels at week 12 */}
          {week === 12 && <>
            <rect x={chartW-52} y={chartH-RVN_PEAK*chartH-16} width={50} height={14}
              rx={4} fill={ac} opacity={0.9}/>
            <text x={chartW-27} y={chartH-RVN_PEAK*chartH-6} fontSize={8} fontWeight="900"
              fill="#000" textAnchor="middle" fontFamily="system-ui,sans-serif">{rvnFinalLabel}</text>
            <rect x={chartW-40} y={chartH-STD_PEAK*chartH-16} width={38} height={13}
              rx={4} fill={T.muted} opacity={0.6}/>
            <text x={chartW-21} y={chartH-STD_PEAK*chartH-6} fontSize={7.5} fontWeight="800"
              fill={T.bg} textAnchor="middle" fontFamily="system-ui,sans-serif">{stdFinalLabel}</text>
          </>}
          {/* Gap annotation arrow at week 12 */}
          {week === 12 && (
            <g>
              <line x1={chartW-8} y1={chartH-STD_PEAK*chartH}
                x2={chartW-8} y2={chartH-RVN_PEAK*chartH}
                stroke={ac} strokeWidth={1} opacity={0.6}/>
              <polygon
                points={`${chartW-8},${chartH-RVN_PEAK*chartH} ${chartW-11},${chartH-RVN_PEAK*chartH+5} ${chartW-5},${chartH-RVN_PEAK*chartH+5}`}
                fill={ac} opacity={0.8}/>
            </g>
          )}
        </svg>
      </div>

      {/* ─ Shared controls ─ */}
      <div style={{ background:T.glass, border:`1px solid ${T.border}`,
        borderRadius:14, padding:"10px 14px", marginBottom:14 }}>
        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
          {[0,3,6,9,12].map(ms => (
            <div key={ms} style={{ textAlign:"center", cursor:"pointer", flex:1 }}
              onClick={() => setWeek(ms)}>
              <div style={{ width:8, height:8, borderRadius:"50%", margin:"0 auto 2px",
                background: week>=ms ? (milestones.find(m=>m.week===ms)?.color||ac) : T.border,
                boxShadow: week===ms ? `0 0 10px ${ac}` : "none", transition:"all .2s" }}/>
              <div style={{ fontSize:7, color:week>=ms?ac:T.faint, fontWeight:700 }}>WK{ms}</div>
            </div>
          ))}
        </div>
        <input type="range" min={0} max={12} step={1} value={week}
          onChange={e => { lockScroll(e); setWeek(Number(e.target.value)); }}
          style={{ width:"100%", accentColor:ac, cursor:"pointer", marginBottom:8 }}/>
        <motion.button whileTap={{ scale:.95 }} onClick={runAnimation} disabled={animating}
          style={{ width:"100%", padding:"11px",
            background: animating ? T.glass : `linear-gradient(90deg,${ac}cc,${ac})`,
            border:`1px solid ${ac}55`, borderRadius:12,
            fontSize:11, fontWeight:900,
            color: animating ? T.faint : "#000",
            cursor: animating ? "not-allowed" : "pointer",
            letterSpacing:".08em",
            boxShadow: animating ? "none" : `0 4px 20px ${ac}44` }}>
          {animating ? "▶ RUNNING 12-WEEK SIMULATION..." : "▶ RUN 12-WEEK SIMULATION · BOTH PATHS"}
        </motion.button>
      </div>

      {/* ─ Delta badge ─ */}
      {week > 0 && (
        <motion.div initial={{ opacity:0, y:4 }} animate={{ opacity:1, y:0 }}
          style={{ marginBottom:14,
            background:`${ac}14`, border:`1px solid ${ac}44`,
            borderRadius:10, padding:"8px 14px",
            display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div>
            <div style={{ fontSize:8, color:T.faint, letterSpacing:".1em", marginBottom:2 }}>
              RVN VISION ADVANTAGE AT WEEK {week}
            </div>
            <div style={{ fontSize:10.5, color:T.muted }}>
              Supplements accelerating your result by
            </div>
          </div>
          <div style={{ fontSize:28, fontWeight:900, color:ac,
            textShadow:`0 0 20px ${ac}88` }}>+{advDelta}%</div>
        </motion.div>
      )}

      {/* ─ Milestone popup flash ─ */}
      <AnimatePresence>
        {popupMs !== null && (() => {
          const ms = milestones.find(m => m.week === popupMs);
          if (!ms) return null;
          return (
            <motion.div key={`popup_${popupMs}`}
              initial={{ opacity:0, scale:.85, y:10 }}
              animate={{ opacity:1, scale:1, y:0 }}
              exit={{ opacity:0, scale:.92, y:-8 }}
              transition={{ duration:.35, ease:[.22,1,.36,1] }}
              style={{ position:"relative", zIndex:10, marginBottom:14,
                borderRadius:14, overflow:"hidden",
                border:`2px solid ${ms.color}`,
                background:`linear-gradient(135deg,${ms.color}22 0%,${T.glass} 100%)`,
                boxShadow:`0 0 32px ${ms.color}44, 0 0 8px ${ms.color}22` }}>
              <div style={{ height:3, background:`linear-gradient(90deg,transparent,${ms.color},transparent)` }}/>
              <div style={{ padding:"14px 16px" }}>
                <div style={{ display:"flex", alignItems:"center",
                  justifyContent:"space-between", marginBottom:8 }}>
                  <div>
                    <div style={{ fontSize:9, fontWeight:900, color:ms.color,
                      letterSpacing:".16em", marginBottom:2 }}>◉ WEEK {ms.week} — SUPPLEMENT ACTIVATING</div>
                    <div style={{ fontSize:16, fontWeight:900, color:T.text, lineHeight:1.1 }}>{ms.supp}</div>
                  </div>
                  <div style={{ textAlign:"right" }}>
                    <div style={{ fontSize:8, color:T.faint, marginBottom:3 }}>{ms.metric}</div>
                    <div style={{ fontSize:22, fontWeight:900, color:ms.color }}>{ms.rvn}</div>
                    <div style={{ fontSize:9, color:T.muted }}>vs {ms.std} standard</div>
                  </div>
                </div>
                <div style={{ fontSize:11.5, color:T.text, lineHeight:1.7, opacity:.9 }}>{ms.why}</div>
              </div>
              <div style={{ height:3, background:`linear-gradient(90deg,transparent,${ms.color},transparent)` }}/>
            </motion.div>
          );
        })()}
      </AnimatePresence>

      {/* ─ WITHOUT supplements section ─ */}
      {renderSection(false)}

      {/* ─ WITH RVN VISION section ─ */}
      {renderSection(true)}

      {/* ─ CUSTOM STACK section ─ */}
      {renderCustomSection()}
    </div>
  );
}

// ─── SMOKE PARTICLES (ported from v2 LogoReveal) ─────────────────────────────
function SmokeParticles({ visible }) {
  const particles = useMemo(() =>
    Array.from({ length: 55 }, (_, i) => ({
      id: i,
      startX:  (Math.random() - 0.5) * 900,
      startY:  (Math.random() - 0.5) * 600,
      size:    Math.random() * 3.5 + 1,
      dur:     1.2 + Math.random() * 0.6,
      delay:   Math.random() * 0.5,
      opacity: 0.25 + Math.random() * 0.55,
    })), []);
  return (
    <>
      {particles.map(p => (
        <motion.div key={p.id}
          initial={{ x: p.startX, y: p.startY, opacity: 0, scale: 2 }}
          animate={visible
            ? { x:0, y:0, opacity:0, scale:0.3,
                transition: { duration: p.dur, delay: p.delay, ease: [0.22,1,0.36,1] } }
            : { x: p.startX, y: p.startY, opacity: p.opacity, scale: 1,
                transition: { duration: 0.01 } }
          }
          style={{
            position: "absolute", width: p.size, height: p.size, borderRadius: "50%",
            background: "#fff", top: "50%", left: "50%",
            marginTop: -(p.size/2), marginLeft: -(p.size/2),
            pointerEvents: "none", boxShadow: `0 0 ${p.size*3}px #fff`,
          }}
        />
      ))}
    </>
  );
}

// ─── HISTORY FEED ────────────────────────────────────────────────────────────
// Renders past workout sessions inside the Narrative feed.
function HistoryFeed({ email, theme, accentColor }) {
  const T = D[theme] || D.dark;
  const ac = accentColor || T.blue;
  const { sessions, loading, error } = useHistory(email);

  if (loading) return (
    <div style={{ display:"flex", justifyContent:"center", padding:20 }}>
      <CobaltSpinner size={24} color={ac}/>
    </div>
  );
  if (error) return (
    <div style={{ fontSize:10, color:T.red, padding:"8px 14px", textAlign:"center" }}>
      ⚠ Could not load history — {error}
    </div>
  );
  if (!sessions.length) return (
    <div style={{ fontSize:10, color:T.muted, textAlign:"center", padding:"12px 0" }}>
      No past sessions yet. Complete your first workout to see history here.
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
      {sessions.map((s, i) => {
        const date     = new Date(s.logged_at || Date.now());
        const dateStr  = date.toLocaleDateString("en-US", { month:"short", day:"numeric" });
        const timeStr  = date.toLocaleTimeString("en-US", { hour:"2-digit", minute:"2-digit" });
        const doneCnt  = Object.values(s.sets_done || {}).filter(Boolean).length;
        const totalCnt = (s.exercises || []).reduce((acc, ex) => acc + parseInt(ex.sets || 0), 0);
        return (
          <motion.div key={s.id || i}
            initial={{ opacity:0, y:12 }} animate={{ opacity:1, y:0 }}
            transition={{ delay: i * 0.06, duration: 0.35 }}
            style={{
              background:   T.glass,
              border:       `1px solid ${T.border}`,
              borderRadius: 10,
              padding:      "11px 14px",
            }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:4 }}>
              <div style={{ fontSize:11, fontWeight:800, color:T.text, letterSpacing:".04em" }}>
                {(s.archetype_id || "session").toUpperCase().replace("_"," ")}
              </div>
              <div style={{ fontSize:9, color:T.muted }}>
                {dateStr}  ·  {timeStr}
              </div>
            </div>
            <div style={{ display:"flex", gap:14 }}>
              <div style={{ fontSize:10, color:ac, fontWeight:700 }}>
                ◈ {s.bio_score ?? "—"} BIO
              </div>
              <div style={{ fontSize:10, color:T.dim }}>
                {doneCnt}/{totalCnt} sets
              </div>
              {s.notes && (
                <div style={{ fontSize:10, color:T.muted, fontStyle:"italic" }}>
                  "{s.notes}"
                </div>
              )}
            </div>
          </motion.div>
        );
      })}
    </div>
  );
}

// ─── MORNING BRIEF SCREEN ─────────────────────────────────────────────────────
// Daily "here's your plan" screen — shown in the morning or on demand.
function MorningBriefScreen({ theme, user, archetypeId, bioData, biology, onBack }) {
  const T = D[theme] || D.dark;
  const circadian = getCircadianState();
  const hour      = new Date().getHours();
  const _allArch  = [...GYM_ARCHETYPES, ...FEMALE_GYM_ARCHETYPES];
  const arch      = _allArch.find(a => a.id === archetypeId) || GYM_ARCHETYPES[0];
  const bioScore  = calcBioScore(archetypeId, bioData) || 72;
  const firstName = user?.name?.split(" ")[0] || "Athlete";
  const dayLabel  = new Date().toLocaleDateString("en-US", { weekday:"long" });
  const dateLabel = new Date().toLocaleDateString("en-US", { month:"short", day:"numeric" });

  const readiness = bioScore >= 80
    ? { label:"HIGH",   color:"#30D158", note:"You're primed. Don't hold back today." }
    : bioScore >= 65
    ? { label:"GOOD",   color:"#0A84FF", note:"Solid day. Push to about 90% effort." }
    : { label:"RECOVER",color:"#FF6B35", note:"Your body needs more time. Focus on form over weight today." };

  const supplementNote = hour < 10
    ? "Best time to take your morning supplements is right now."
    : hour < 14
    ? "Take your supplements with your next meal."
    : "Stick to evening-safe supplements only. Save pre-workout stacks for tomorrow morning.";

  const actions = [
    { time:"RIGHT NOW",     icon:circadian.icon, color:circadian.color, text:circadian.advice },
    { time:"YOUR WORKOUT",  icon:"◈",            color:arch?.glow || T.blue,
      text:`Run your ${arch?.name || "workout"} protocol. Focus on: ${(arch?.muscles || []).slice(0,3).join(", ")}.` },
    { time:"NUTRITION",     icon:"⬡",            color:T.green,         text:supplementNote },
    { time:"TONIGHT",       icon:"◑",            color:"#BF5AF2",
      text:"7–9 hours sleep is where your muscles actually grow. Protect that window." },
  ];

  const forecast = getBioScoreForecast(bioScore, 3);
  const circWarn = getCircadianWorkoutWarning();

  return (
    <Screen theme={theme} style={{ overflowY:"auto" }}>
      <motion.div {...FX.page}>
        {/* Header */}
        <div style={{
          padding:"20px 20px 16px",
          borderBottom:`1px solid ${T.border}`,
          background:`linear-gradient(180deg, ${arch?.glow || T.blue}10 0%, transparent 100%)`,
        }}>
          <BackBtn onBack={onBack} theme={theme}/>
          <div style={{ marginTop:14 }}>
            <div style={{ fontSize:10, fontWeight:800, color:T.faint, letterSpacing:".16em" }}>
              {dayLabel.toUpperCase()} · {dateLabel.toUpperCase()}
            </div>
            <div style={{ fontSize:26, fontWeight:900, color:T.text, marginTop:4, lineHeight:1.25, letterSpacing:"-.01em" }}>
              Hey {firstName},<br/>
              <span style={{ color:arch?.glow || T.blue }}>here{"'"}s your plan.</span>
            </div>
          </div>
        </div>

        <div style={{ padding:"16px 18px 52px", display:"flex", flexDirection:"column", gap:12 }}>

          {/* Readiness card */}
          <motion.div {...FX.stagger(0, .05)}>
            <GlassCard theme={theme} glow={readiness.color} style={{ padding:"16px" }}>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
                <div style={{ fontSize:9, fontWeight:800, color:T.faint, letterSpacing:".14em" }}>
                  TODAY{"'"}S READINESS
                </div>
                <div style={{
                  fontSize:9, fontWeight:900, color:readiness.color, letterSpacing:".1em",
                  background:`${readiness.color}18`, padding:"2px 10px", borderRadius:4,
                }}>
                  {readiness.label}
                </div>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:14 }}>
                <BioRing score={bioScore} color={readiness.color} size={56} theme={theme}/>
                <div>
                  <div style={{ fontSize:22, fontWeight:900, color:readiness.color, lineHeight:1 }}>{bioScore}</div>
                  <div style={{ fontSize:10.5, color:T.muted, marginTop:4, lineHeight:1.55 }}>{readiness.note}</div>
                </div>
              </div>
            </GlassCard>
          </motion.div>

          {/* Circadian warning (if applicable) */}
          {circWarn && (
            <motion.div {...FX.stagger(1, .05)}>
              <div style={{
                padding:"12px 14px",
                background:`${circWarn.color}12`,
                border:`1px solid ${circWarn.color}44`,
                borderRadius:12,
                display:"flex", alignItems:"flex-start", gap:10,
              }}>
                <span style={{ fontSize:18, color:circWarn.color, lineHeight:1, marginTop:1 }}>
                  {circWarn.icon}
                </span>
                <div>
                  <div style={{ fontSize:9, fontWeight:900, color:circWarn.color, letterSpacing:".12em", marginBottom:3 }}>
                    {circWarn.title.toUpperCase()}
                  </div>
                  <div style={{ fontSize:11, color:T.muted, lineHeight:1.6 }}>{circWarn.msg}</div>
                </div>
              </div>
            </motion.div>
          )}

          {/* Week forecast */}
          <motion.div {...FX.stagger(2, .05)}>
            <GlassCard theme={theme} glow={forecast.trend === "up" ? "#30D158" : forecast.trend === "down" ? "#FF6B35" : T.blue}
              style={{ padding:"14px" }}>
              <div style={{ fontSize:9, fontWeight:800, color:T.faint, letterSpacing:".14em", marginBottom:6 }}>
                YOUR WEEK AHEAD
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:8 }}>
                <div style={{ fontSize:28, fontWeight:900,
                  color: forecast.trend === "up" ? "#30D158" : forecast.trend === "down" ? "#FF6B35" : T.blue }}>
                  {forecast.projected}
                </div>
                <div>
                  <div style={{ fontSize:8.5, fontWeight:700, color:T.faint, letterSpacing:".08em" }}>PROJECTED BIO-SCORE</div>
                  <div style={{ fontSize:8, color:T.faint, marginTop:2 }}>END OF WEEK</div>
                </div>
              </div>
              <div style={{ fontSize:11, color:T.muted, lineHeight:1.6 }}>{forecast.message}</div>
            </GlassCard>
          </motion.div>

          {/* Action plan */}
          <motion.div {...FX.stagger(3, .05)}>
            <div style={{ fontSize:9, fontWeight:800, color:T.faint, letterSpacing:".14em", marginBottom:8 }}>
              TODAY{"'"}S ACTION PLAN
            </div>
            {actions.map((a, i) => (
              <motion.div key={i} {...FX.stagger(i, .12)}
                style={{
                  display:"flex", alignItems:"flex-start", gap:12, marginBottom:10,
                  padding:"12px 14px", background:T.glass, borderRadius:12,
                  border:`1px solid ${T.border}`,
                }}>
                <div style={{
                  width:36, height:36, borderRadius:10, flexShrink:0,
                  background:`${a.color}18`, border:`1.5px solid ${a.color}44`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                }}>
                  <span style={{ fontSize:16, color:a.color }}>{a.icon}</span>
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:8, fontWeight:900, color:a.color, letterSpacing:".12em", marginBottom:3 }}>
                    {a.time}
                  </div>
                  <div style={{ fontSize:11.5, color:T.text, lineHeight:1.55, fontWeight:500 }}>{a.text}</div>
                </div>
              </motion.div>
            ))}
          </motion.div>

        </div>
      </motion.div>
    </Screen>
  );
}

