// ─── AUTH SCREEN — magic link email sign-in ───────────────────────────────────
function AuthScreen({ theme, onAuth }) {
  const T = D[theme] || D["dark"];
  const [email,   setEmail]   = useState("");
  const [status,  setStatus]  = useState("idle"); // idle | sending | sent | error
  const [errMsg,  setErrMsg]  = useState("");

  async function sendMagicLink() {
    if (!email.includes("@")) { setErrMsg("Enter a valid email."); setStatus("error"); return; }
    setStatus("sending");
    setErrMsg("");
    try {
      const { error } = await supabase.auth.signInWithOtp({
        email,
        options: { emailRedirectTo: window.location.origin },
      });
      if (error) { setErrMsg(error.message); setStatus("error"); return; }
      setStatus("sent");
    } catch (e) {
      setErrMsg("Something went wrong. Try again.");
      setStatus("error");
    }
  }

  return (
    <motion.div {...{
      initial: { opacity:0 }, animate: { opacity:1 }, exit: { opacity:0 },
      style: {
        minHeight: "100dvh", display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        background: T.bg, padding: "32px 24px",
      }
    }}>
      {/* Logo */}
      <div style={{ marginBottom: 48, textAlign: "center" }}>
        <div style={{ fontSize: 36, fontWeight: 900, letterSpacing: "-0.03em", color: T.text }}>
          RVN<span style={{ color: T.blue }}>OS</span>
        </div>
        <div style={{ fontSize: 12, color: T.muted, letterSpacing: ".15em", marginTop: 4 }}>
          PERFORMANCE INTELLIGENCE
        </div>
      </div>

      <div style={{ width: "100%", maxWidth: 380 }}>
        {status === "sent" ? (
          <motion.div initial={{ opacity:0, y:16 }} animate={{ opacity:1, y:0 }}
            style={{ textAlign:"center" }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>📬</div>
            <div style={{ fontSize: 20, fontWeight: 800, color: T.text, marginBottom: 8 }}>
              Check your inbox
            </div>
            <div style={{ fontSize: 13, color: T.muted, lineHeight: 1.6 }}>
              We sent a sign-in link to<br/>
              <span style={{ color: T.text, fontWeight: 700 }}>{email}</span>
            </div>
            <div style={{ fontSize: 11, color: T.faint, marginTop: 24 }}>
              Tap the link in your email — it'll sign you in instantly.<br/>
              No password ever needed.
            </div>
            <button onClick={() => setStatus("idle")}
              style={{ marginTop: 32, background: "transparent", border: `1px solid ${T.border}`,
                borderRadius: 10, padding: "10px 24px", color: T.muted, fontSize: 12, cursor: "pointer" }}>
              Use a different email
            </button>
          </motion.div>
        ) : (
          <motion.div initial={{ opacity:0, y:16 }} animate={{ opacity:1, y:0 }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: T.text, marginBottom: 8 }}>
              Sign in to RVN OS
            </div>
            <div style={{ fontSize: 13, color: T.muted, marginBottom: 28, lineHeight: 1.5 }}>
              Enter your email and we'll send you a magic link. No password needed.
            </div>

            <input
              type="email"
              placeholder="your@email.com"
              value={email}
              onChange={e => { setEmail(e.target.value); setErrMsg(""); }}
              onKeyDown={e => e.key === "Enter" && sendMagicLink()}
              style={{
                width: "100%", padding: "14px 16px", borderRadius: 12,
                border: `1px solid ${status === "error" ? T.red : T.border}`,
                background: T.glass, color: T.text, fontSize: 16,
                outline: "none", boxSizing: "border-box", marginBottom: 12,
              }}
            />

            {errMsg && (
              <div style={{ fontSize: 12, color: T.red, marginBottom: 12 }}>{errMsg}</div>
            )}

            <button
              onClick={sendMagicLink}
              disabled={status === "sending"}
              style={{
                width: "100%", padding: "14px", borderRadius: 12,
                background: status === "sending" ? T.muted : T.blue,
                color: "#fff", border: "none", fontSize: 15, fontWeight: 800,
                cursor: status === "sending" ? "not-allowed" : "pointer",
                transition: "background .2s",
              }}>
              {status === "sending" ? "Sending…" : "Send Magic Link →"}
            </button>

            <div style={{ fontSize: 11, color: T.faint, textAlign: "center", marginTop: 20, lineHeight: 1.5 }}>
              By continuing you agree to our Terms of Service.<br/>
              Your data is encrypted and never sold.
            </div>
          </motion.div>
        )}
      </div>
    </motion.div>
  );
}

// ─── SPLASH SCREEN ────────────────────────────────────────────────────────────
function SplashScreen({ onDone, theme }) {
  const T = D[theme] || D["dark"];
  const [phase, setPhase] = useState(0);
  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 800);
    const t2 = setTimeout(() => setPhase(2), 2200);
    const t3 = setTimeout(() => onDone && onDone(), 5500);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, [onDone]);

  return (
    <motion.div
      key="reveal"
      initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
      transition={{ duration:.4 }}
      onClick={phase === 2 ? onDone : undefined}
      style={{
        position:"fixed", inset:0,
        background: "#000",
        display:"flex", alignItems:"center", justifyContent:"center",
        flexDirection:"column",
        cursor: phase === 2 ? "pointer" : "default",
        overflow:"hidden",
      }}>
      {/* Radial halo */}
      <motion.div
        initial={{ opacity:0, scale:0.6 }}
        animate={{ opacity: phase >= 1 ? 0.15 : 0, scale: phase >= 1 ? 1 : 0.6 }}
        transition={{ duration:1.8, ease:"easeOut" }}
        style={{
          position:"absolute", width:500, height:300, borderRadius:"50%",
          background: "radial-gradient(ellipse, rgba(255,255,255,0.3) 0%, transparent 70%)",
          filter:"blur(40px)", pointerEvents:"none",
        }}
      />
      <SmokeParticles visible={phase >= 1}/>

      {/* LOGO */}
      <motion.div
        initial={{ opacity:0 }} animate={{ opacity: phase >= 1 ? 1 : 0 }}
        transition={{ duration:0.3, delay:0.2 }}
        style={{ position:"relative", zIndex:2, display:"flex", justifyContent:"center" }}>
        <RVNLogo size={260} glow={T.blue}/>
      </motion.div>

      {/* Touch to Begin */}
      <motion.div
        initial={{ opacity:0 }} animate={{ opacity: phase === 2 ? 0.55 : 0 }}
        transition={{ duration:1, delay:0.5 }}
        style={{
          position:"absolute", bottom:60, fontSize:12, letterSpacing:"0.35em",
          color: "rgba(255,255,255,.55)",
          textTransform:"uppercase",
          fontFamily: FONT_SERIF, fontWeight: 400,
        }}>
        Touch to Begin
      </motion.div>

      {/* ECG pulse */}
      {phase === 2 && (
        <motion.div
          initial={{ opacity:0 }} animate={{ opacity:1 }}
          style={{ position:"absolute", bottom:100, left:0, right:0, height:40 }}>
          <svg viewBox="0 0 400 40" style={{ width:"100%", height:40, opacity:0.25 }}>
            <motion.polyline
              points="0,20 60,20 80,20 90,4 100,36 110,20 130,20 200,20 210,20 220,6 228,34 236,20 250,20 400,20"
              fill="none" stroke="#fff" strokeWidth="1"
              initial={{ pathLength:0 }} animate={{ pathLength:1 }}
              transition={{ duration:1.2, ease:"easeInOut" }}
            />
          </svg>
        </motion.div>
      )}
    </motion.div>
  );
}

// ─── LANDING / HERO ───────────────────────────────────────────────────────────
function LandingScreen({ storeName, mode, theme, onBegin, onManager, onModeChange, onThemeToggle, modeLockedBy, location, onNfcTap, onGhostBar, onSignIn, onSurgical, onWearables }) {
  const T = D[theme];
  const M = OS_MODES[mode];
  const circ = useBioClock();
  const ac = T[M.accentKey];
  const words = M.heroWords;

  // ─── NFC listener (Web NFC — Chrome Android) ─────────────────────────────
  // Mode tags:    rvn://mode/<gym|store|smoothie>?venue=<name>
  // Station tags: rvn://station/<bench|squat|rows|deadlift|press>?venue=<name>
  // Gracefully no-ops on unsupported browsers / HTTPS contexts.
  useEffect(() => {
    if (typeof window === "undefined") return;
    if (!("NDEFReader" in window)) return;
    let reader; let stopped = false;
    (async () => {
      try {
        reader = new window.NDEFReader();
        await reader.scan();
        reader.onreading = (evt) => {
          if (stopped) return;
          for (const rec of evt.message.records) {
            try {
              const url = new TextDecoder().decode(rec.data);
              // Station tag takes priority
              const s = url.match(/rvn:\/\/station\/(bench|squat|rows|deadlift|press)(?:\?venue=([^&]+))?/i);
              if (s && onNfcTap) {
                const venue = s[2] ? decodeURIComponent(s[2]) : null;
                onNfcTap(null, venue ? { venueName: venue } : null, s[1].toLowerCase());
                return;
              }
              // Mode tag
              const m = url.match(/rvn:\/\/mode\/(gym|store|smoothie)(?:\?venue=([^&]+))?/i);
              if (m && onNfcTap) {
                const venue = m[2] ? decodeURIComponent(m[2]) : null;
                onNfcTap(m[1].toLowerCase(), venue ? { venueName: venue } : null, null);
              }
            } catch (_) {}
          }
        };
      } catch (_) { /* permission denied / unsupported */ }
    })();
    return () => { stopped = true; };
  }, [onNfcTap]);

  return (
    <Screen theme={theme}>
      {/* Ambient background */}
      <div style={{
        position:"absolute", inset:0, pointerEvents:"none",
        background: M.bgGradient(T),
      }}/>
      <NeuralMesh theme={theme} accentColor={ac} density={14}/>

      {/* Ticker */}
      <AITicker theme={theme} mode={mode}/>

      {/* Top bar */}
      <div style={{
        display:"flex", alignItems:"center", justifyContent:"space-between",
        padding:"16px 22px", position:"relative", zIndex:10,
      }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <RVNLogo size={38} glow={ac}/>
          <div>
            <div style={{ fontSize:15, fontWeight:800, color:T.text, letterSpacing:"-.01em" }}>
              {storeName || "RVN VISION"}
            </div>
            <div style={{ fontSize:9, fontWeight:700, color:T.faint, letterSpacing:".1em" }}>{M.label}</div>
          </div>
        </div>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <ThemeToggle theme={theme} onToggle={onThemeToggle || (() => {})}/>
          <motion.button whileTap={{ scale:.92 }} onClick={onManager}
            style={{
              background:T.glass, border:`1px solid ${T.border}`,
              backdropFilter:"blur(8px)", borderRadius:22,
              padding:"6px 14px", cursor:"pointer",
              fontSize:11, fontWeight:700, color:T.muted, letterSpacing:".06em",
            }}>···</motion.button>
        </div>
      </div>

      {/* Hero */}
      <div style={{
        flex:1, display:"flex", flexDirection:"column",
        alignItems:"center", justifyContent:"center",
        padding:"0 28px 32px", position:"relative", zIndex:10,
      }}>
        {/* Mode badge */}
        <motion.div {...FX.stagger(0,.1)} style={{ marginBottom:20 }}>
          <Pill label={`${M.icon}  ${M.tagline}`} color={ac} theme={theme}/>
        </motion.div>

        {/* Hero words */}
        <div style={{ textAlign:"center", marginBottom:14 }}>
          {words.map((word, i) => (
            <motion.div key={word}
              initial={{ opacity:0, y:36, filter:"blur(10px)" }}
              animate={{ opacity:1, y:0,  filter:"blur(0px)"  }}
              transition={{ delay:.18+i*.13, duration:.65, ease:[.22,1,.36,1] }}
              style={{
                fontSize:62, fontWeight:900, lineHeight:.98, letterSpacing:"-.03em",
                color: i===1 ? ac : T.text,
                textShadow: i===1 && theme==="dark" ? `0 0 48px ${ac}55` : "none",
              }}>
              {word}
            </motion.div>
          ))}
        </div>

        {/* AI sub-line */}
        <motion.div
          initial={{ opacity:0 }} animate={{ opacity:1 }}
          transition={{ delay:.68, duration:.5 }}
          style={{ marginBottom:36, textAlign:"center", maxWidth:300 }}>
          <div style={{ fontSize:13, color:T.muted, lineHeight:1.6 }}>{M.heroBio}</div>
        </motion.div>

        {/* CTA */}
        <motion.div
          initial={{ opacity:0, y:20 }} animate={{ opacity:1, y:0 }}
          transition={{ delay:.82 }}
          style={{ width:"100%", maxWidth:340 }}>
          <ShimmerCTA label={`${M.ctaLabel}  →`} onClick={onBegin} theme={theme} color={ac} icon={M.icon}/>
        </motion.div>

        {/* Returning user — Sign In */}
        <motion.div
          initial={{ opacity:0 }} animate={{ opacity:1 }}
          transition={{ delay:.88 }}
          style={{ marginTop:10, display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
          <span style={{ fontSize:11, color:T.faint, letterSpacing:".04em" }}>Returning athlete?</span>
          <button onClick={onSignIn}
            style={{
              background:"transparent", border:"none", cursor:"pointer",
              fontSize:11, fontWeight:800, color:ac, letterSpacing:".08em", padding:"4px 6px",
            }}>
            SIGN IN →
          </button>
        </motion.div>

        {/* Ghost Bar — Live VBT Telemetry HUD */}
        <motion.button
          initial={{ opacity:0, y:14 }} animate={{ opacity:1, y:0 }}
          transition={{ delay:.95 }}
          whileTap={{ scale:.97 }}
          onClick={onGhostBar}
          style={{
            marginTop:14, width:"100%", maxWidth:340,
            background:"transparent",
            border:`1px solid ${T.border}`,
            borderRadius:16, padding:"12px 16px",
            cursor:"pointer", color:T.text,
            display:"flex", alignItems:"center", justifyContent:"space-between",
            fontSize:12, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase",
          }}>
          <span style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{
              width:8, height:8, borderRadius:4, background:"#4D8CFF",
              boxShadow:"0 0 12px #4D8CFF",
            }}/>
            Ghost Bar · Live VBT
          </span>
          <span style={{ color:T.muted, fontSize:10 }}>F1 TELEMETRY →</span>
        </motion.button>

        {/* Surgical Vision — Agentic macro scanner + calorie monitor */}
        <motion.button
          initial={{ opacity:0, y:14 }} animate={{ opacity:1, y:0 }}
          transition={{ delay:1.02 }}
          whileTap={{ scale:.97 }}
          onClick={onSurgical}
          style={{
            marginTop:10, width:"100%", maxWidth:340,
            background:"transparent",
            border:`1px solid ${T.border}`,
            borderRadius:16, padding:"12px 16px",
            cursor:"pointer", color:T.text,
            display:"flex", alignItems:"center", justifyContent:"space-between",
            fontSize:12, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase",
          }}>
          <span style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{
              width:8, height:8, borderRadius:4, background:"#8AFF9E",
              boxShadow:"0 0 12px #8AFF9E",
            }}/>
            Surgical Vision · Macro Scan
          </span>
          <span style={{ color:T.muted, fontSize:10 }}>AGENTIC →</span>
        </motion.button>

        {/* Wearable Sync — Whoop + Apple Health + Calorie Entropy */}
        <motion.button
          initial={{ opacity:0, y:14 }} animate={{ opacity:1, y:0 }}
          transition={{ delay:1.08 }}
          whileTap={{ scale:.97 }}
          onClick={onWearables}
          style={{
            marginTop:10, width:"100%", maxWidth:340,
            background:"transparent",
            border:`1px solid ${T.border}`,
            borderRadius:16, padding:"12px 16px",
            cursor:"pointer", color:T.text,
            display:"flex", alignItems:"center", justifyContent:"space-between",
            fontSize:12, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase",
          }}>
          <span style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{
              width:8, height:8, borderRadius:4, background:"#00FFAB",
              boxShadow:"0 0 12px #00FFAB",
            }}/>
            Wearable Sync · Entropy
          </span>
          <span style={{ color:T.muted, fontSize:10 }}>WHOOP / APPLE →</span>
        </motion.button>

        {/* Bio-clock widget */}
        <motion.div
          initial={{ opacity:0 }} animate={{ opacity:1 }}
          transition={{ delay:1.0 }}
          style={{ marginTop:20, width:"100%", maxWidth:340 }}>
          <BioClockWidget theme={theme} compact/>
        </motion.div>

        {/* NFC / Environment indicator — no selector, mode is set by venue NFC
            (or Manager). Customers never pick mode manually. */}
        <motion.div
          initial={{ opacity:0 }} animate={{ opacity:1 }}
          transition={{ delay:1.15 }}
          style={{ marginTop:20, width:"100%", maxWidth:340 }}>
          <div style={{
            display:"flex", alignItems:"center", gap:10,
            padding:"10px 14px",
            background:T.glass, border:`1px solid ${T.border}`,
            backdropFilter:"blur(16px)", borderRadius:14,
          }}>
            <div style={{
              width:30, height:30, borderRadius:"50%",
              background: modeLockedBy === "nfc" ? `${ac}22` : T.glass,
              border: `1px solid ${modeLockedBy === "nfc" ? ac+"66" : T.border}`,
              display:"flex", alignItems:"center", justifyContent:"center",
              fontSize:14, color: modeLockedBy === "nfc" ? ac : T.faint,
            }}>📡</div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:9, fontWeight:700, letterSpacing:".12em", color:T.faint }}>
                {modeLockedBy === "nfc" ? "NFC LINKED" : "ENVIRONMENT"}
              </div>
              <div style={{ fontSize:12, fontWeight:800, color:T.text, letterSpacing:"-.01em",
                            whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
                {modeLockedBy === "nfc" && location?.venueName
                  ? `${location.venueName} · ${M.label}`
                  : M.label}
              </div>
            </div>
            {modeLockedBy === "nfc" && (
              <div style={{
                fontSize:8, fontWeight:800, letterSpacing:".1em",
                color:ac, padding:"4px 8px",
                border:`1px solid ${ac}55`, borderRadius:8,
              }}>LIVE</div>
            )}
          </div>
          <div style={{ fontSize:9, color:T.faint, marginTop:8, textAlign:"center", letterSpacing:".08em" }}>
            TAP AN RVN NFC POINT TO UNLOCK THE LOCAL EXPERIENCE
          </div>
        </motion.div>
      </div>
    </Screen>
  );
}

