// ─── PERFORMANCE STEP ─────────────────────────────────────────────────────────
function PerformanceStep({ archetypeId, mode, onSubmit, onBack, theme }) {
  const T = D[theme];
  const M = OS_MODES[mode];
  const ac = T[M.accentKey];
  const isGym = mode==="gym";

  const metrics = isGym
    ? [{ id:"bw",    label:"Body Weight",             unit:"lbs", min:80,  max:400, step:1, default:175, note:null },
       { id:"bench", label:"Bench Press (1 Rep Max)", unit:"lbs", min:45,  max:505, step:5, default:135, note:"Enter the maximum weight you can lift for one rep" },
       { id:"squat", label:"Squat (1 Rep Max)",        unit:"lbs", min:45,  max:605, step:5, default:185, note:"Enter the maximum weight you can squat for one rep" }]
    : [{ id:"age",   label:"Age",                unit:"yrs", min:18, max:75,  step:1, default:32  },
       { id:"sleep", label:"Avg. Sleep Quality", unit:"hrs", min:3,  max:10,  step:.5,default:6.5 },
       { id:"stress",label:"Stress Level",        unit:"/10", min:1,  max:10,  step:1, default:6   }];

  const [sel, setSel]    = useState(metrics[0].id);
  const [vals, setVals]  = useState(() => Object.fromEntries(metrics.map(m => [m.id, m.default])));
  const metric = metrics.find(m=>m.id===sel);
  const val = vals[sel];
  const pct = ((val-metric.min)/(metric.max-metric.min))*100;

  const insight = useMemo(() => {
    if (!isGym) {
      if (sel==="sleep" && val < 6) return { text:"Sleep debt critical. Recovery protocol is your highest-ROI intervention.", color:"#FF4B2B" };
      if (sel==="stress" && val > 7) return { text:"High cortisol detected. Adaptogen protocol will be prioritized.", color:"#FF4B2B" };
      return { text:"Baseline captured. Protocol precision: calibrated.", color:"#00FFAB" };
    }
    if (sel==="bw") {
      const bwKg = Math.round(val * 0.4536);
      return { text:`At ${val}lbs (${bwKg}kg) your precision protein target will be calculated after strength baseline. Awaiting lifts.`, color:ac };
    }
    if (sel==="bench") {
      if (val > 275) return { text:"Elite-tier. Neural drive optimized. Protocol targets advanced hypertrophy.", color:"#00FFAB" };
      if (val > 185) return { text:"Advanced baseline. Protocol targets strength-hypertrophy hybrid.", color:"#D4AF37" };
      return { text:"Building phase. Neural adaptations will drive 40%+ strength gains in 12 weeks.", color:"#2E5BFF" };
    }
    return { text:"Baseline logged. Protocol calibrated to your current output capacity.", color:"#00FFAB" };
  }, [sel, val, isGym]);

  return (
    <Screen theme={theme}>
      <div style={{ padding:"20px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <RVNLogo size={30}/>
      </div>
      <div style={{ flex:1, display:"flex", flexDirection:"column", padding:"16px 24px 36px" }}>
        <StepProgress step={3} total={5} label="PERFORMANCE BASELINE" accent={ac} theme={theme}/>
        <motion.div {...FX.up} style={{ marginTop:22, marginBottom:16 }}>
          <div style={{ fontSize:30, fontWeight:900, letterSpacing:"-.02em", color:T.text }}>
            {isGym ? "Strength Baseline" : "Lifestyle Baseline"}
          </div>
          <div style={{ fontSize:13, color:T.muted, marginTop:4 }}>Precision calibration for your protocol</div>
        </motion.div>

        {/* Metric tabs */}
        <div style={{ display:"flex", gap:8, marginBottom:20 }}>
          {metrics.map(m => (
            <motion.button key={m.id} whileTap={{ scale:.94 }}
              onClick={() => setSel(m.id)}
              style={{
                flex:1, padding:"9px 6px",
                background: sel===m.id ? ac : T.glass,
                backdropFilter:"blur(8px)",
                border:`1px solid ${sel===m.id ? ac : T.border}`,
                borderRadius:10, cursor:"pointer",
                fontSize:10, fontWeight:800,
                color: sel===m.id ? (theme==="dark"?"#000":"#fff") : T.muted,
                letterSpacing:".06em",
                boxShadow: sel===m.id ? `0 0 16px ${ac}55` : "none",
              }}>
              {m.label.split(" ")[0].toUpperCase()}
            </motion.button>
          ))}
        </div>

        {/* Giant value display */}
        <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center" }}>
          <motion.div key={sel} initial={{ opacity:0, scale:.6 }} animate={{ opacity:1, scale:1 }}
            transition={{ duration:.35, ease:[.22,1,.36,1] }}
            style={{ textAlign:"center", marginBottom:4 }}>
            <div style={{
              fontSize:92, fontWeight:900, letterSpacing:"-.04em",
              color:T.text, lineHeight:1,
              textShadow: theme==="dark" ? `0 0 50px ${ac}44` : "none",
            }}>{val}</div>
            <div style={{ fontSize:16, fontWeight:600, color:T.faint, letterSpacing:".14em", marginTop:-6 }}>
              {metric.unit.toUpperCase()}
            </div>
            {metric.note && (
              <div style={{ fontSize:10, color:T.faint, marginTop:8, fontStyle:"italic", maxWidth:260, textAlign:"center", lineHeight:1.4 }}>
                {metric.note}
              </div>
            )}
          </motion.div>

          {/* Slider */}
          <div style={{ width:"100%", maxWidth:310, padding:"0 4px" }}>
            <div style={{ position:"relative", height:5, background:T.glass, borderRadius:3, marginBottom:6, overflow:"visible" }}>
              <div style={{
                position:"absolute", left:0, top:0, bottom:0,
                width:`${pct}%`, background:`linear-gradient(90deg,${ac},${ac}dd)`,
                borderRadius:3, boxShadow:`0 0 14px ${ac}77`,
                transition:"width .04s",
              }}/>
              <div style={{
                position:"absolute", top:"50%", left:`${pct}%`,
                transform:"translate(-50%,-50%)",
                width:18, height:18, borderRadius:"50%",
                background:"#fff", boxShadow:`0 0 10px ${ac}88, 0 2px 8px rgba(0,0,0,.3)`,
              }}/>
            </div>
            <input type="range" min={metric.min} max={metric.max} step={metric.step} value={val}
              onChange={e => setVals(p => ({ ...p, [sel]:Number(e.target.value) }))}
              style={{ width:"100%", marginTop:-22, position:"relative", zIndex:2, height:28, background:"transparent" }}/>
            <div style={{ display:"flex", justifyContent:"space-between", marginTop:-4 }}>
              <span style={{ fontSize:10, color:T.faint }}>{metric.min}{metric.unit}</span>
              <span style={{ fontSize:10, color:T.faint }}>{metric.max}{metric.unit}</span>
            </div>
          </div>
        </div>

        {/* Bio insight */}
        <motion.div
          initial={{ opacity:0, y:14 }} animate={{ opacity:1, y:0 }} transition={{ delay:.3 }}>
          <GlassCard theme={theme} glow={insight.color}
            style={{ padding:"12px 16px", marginBottom:18 }}>
            <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:4 }}>
              KAILU BIO-INSIGHT
            </div>
            <div style={{ fontSize:12.5, color:T.muted, lineHeight:1.55 }}>
              <span style={{ color:insight.color, fontWeight:700 }}>◈ </span>
              {insight.text}
            </div>
          </GlassCard>
        </motion.div>

        {/* Surgical Defaults — skip unnecessary input, hit < 120s onboarding target */}
        <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} transition={{ delay:.5 }}
          style={{ marginBottom:12, textAlign:"center" }}>
          <button
            onClick={() => {
              // Auto-fill all metrics with surgical population defaults
              const defaults = Object.fromEntries(metrics.map(m => [m.id, m.default]));
              setVals(defaults);
              track("Surgical Defaults Applied", { mode, archetypeId, step: "performance" });
              // Auto-advance after brief confirmation delay
              setTimeout(() => onSubmit({ metric:sel, value:defaults[sel], all:defaults }), 320);
            }}
            style={{
              background: "transparent",
              border: `1px solid ${T.borderHi}`,
              borderRadius: 8, padding: "7px 18px",
              fontSize: 9.5, fontWeight: 700, letterSpacing: ".1em",
              color: T.muted, cursor: "pointer",
            }}>
            ⚡ USE SURGICAL DEFAULTS  (fastest)
          </button>
          <div style={{ fontSize: 8.5, color: T.faint, marginTop: 4 }}>
            Pre-fills population averages. You can update any time in settings.
          </div>
        </motion.div>

        <ShimmerCTA label="Confirm Baseline  →" onClick={() => onSubmit({ metric:sel, value:val, all:vals })} theme={theme} color={ac}/>
      </div>
    </Screen>
  );
}


// ─── AI GOALS ENGINE ─────────────────────────────────────────────────────────
// Research sources: Mifflin-St Jeor (TDEE), ISSN protein guidelines,
// NSCA training volume recommendations, Hirshkowitz et al. sleep science.
function generateAIGoals({ age, heightIn, bw, activityLevel, trainingDays, goalFocus, dietType, biology }) {
  const bwKg     = (bw || 175) * 0.453592;
  const heightCm = (heightIn || 69) * 2.54;
  const a        = age || 25;
  const isMale   = biology !== "female";

  // Mifflin-St Jeor BMR
  const bmr = isMale
    ? (10 * bwKg) + (6.25 * heightCm) - (5 * a) + 5
    : (10 * bwKg) + (6.25 * heightCm) - (5 * a) - 161;

  // TDEE = BMR × activity multiplier
  const actMult = { sedentary:1.2, light:1.375, moderate:1.55, active:1.725 }[activityLevel] || 1.375;
  const tdee    = Math.round(bmr * actMult * (trainingDays >= 5 ? 1.08 : trainingDays >= 4 ? 1.04 : 1));

  // Calorie target by goal
  const cAdj     = { muscle:+300, fat:-400, recomp:0 }[goalFocus] ?? 0;
  const calories = Math.round(tdee + cAdj);

  // Protein — ISSN: 1.6-2.2g/kg for muscle, 1.8-2.4g/kg for fat loss
  const protG    = { muscle:2.0, fat:2.2, recomp:1.8 }[goalFocus] ?? 2.0;
  const protein  = Math.round(bwKg * protG);

  // Fats — ~25-30% of calories (keto: ~70%)
  const fatCals  = dietType === "keto" ? calories * 0.70 : calories * 0.27;
  const fats     = Math.round(fatCals / 9);

  // Carbs — remaining after protein + fats
  const remainCals = calories - (protein * 4) - (fats * 9);
  const carbs      = Math.max(dietType === "keto" ? 20 : 80, Math.round(remainCals / 4));

  // Sleep — Hirshkowitz et al. + training load factor
  let sleepH = 7.5;
  if (a < 25) sleepH += 0.5;
  if (trainingDays >= 5) sleepH += 0.5;
  if (activityLevel === "active") sleepH += 0.25;
  const sleepTarget = Math.min(9.5, Math.round(sleepH * 2) / 2);

  // Readable reasoning
  const goalLabel = { muscle:"muscle building", fat:"fat loss", recomp:"body recomp" }[goalFocus] || "your goal";
  const actLabel  = { sedentary:"desk job", light:"lightly active", moderate:"moderately active", active:"very active" }[activityLevel] || "your activity";

  return {
    calories, tdee,
    macroGoals: { protein, carbs, fats },
    macroToday: { protein: 0, carbs: 0, fats: 0 },
    sleepTarget,
    sleepDays: Array(7).fill(sleepTarget),
    prs: { bench: bw ? Math.round(bw * 0.75) : 185, squat: bw ? Math.round(bw * 1.1) : 245, ohp: bw ? Math.round(bw * 0.45) : 115, deadlift: bw ? Math.round(bw * 1.3) : 295 },
    reasoning: {
      calories: `Your TDEE is ~${tdee} kcal/day (${actLabel}, Mifflin-St Jeor). ${cAdj > 0 ? `+${cAdj}` : cAdj} kcal surplus for ${goalLabel}.`,
      protein:  `${protG}g per kg body weight (${Math.round(bwKg)}kg) — ISSN-recommended for ${goalLabel}.`,
      carbs:    `Remaining calories after protein and fats. ${dietType === "keto" ? "Keto ceiling: 20g net carbs." : "Fuels training performance."}`,
      fats:     `${dietType === "keto" ? "70%" : "~27%"} of calories. Supports hormone production and recovery.`,
      sleep:    `${sleepTarget}h nightly — adjusted for age ${a}${trainingDays >= 5 ? `, high training frequency (${trainingDays}×/week)` : ""}. Based on Hirshkowitz et al. NSF guidelines.`,
    },
    generatedAt: Date.now(),
  };
}

// ─── PERSONALIZE STEP ─────────────────────────────────────────────────────────
function PersonalizeStep({ perfData, biology, archetypeId, onSubmit, onBack, theme }) {
  const T  = D[theme] || D.dark;
  const ac = T.blue;
  const bw = perfData?.all?.bw || 175;

  const [age,           setAge]           = useState(24);
  const [heightFt,      setHeightFt]      = useState(5);
  const [heightIn,      setHeightIn]      = useState(9);
  const [activityLevel, setActivityLevel] = useState("moderate");
  const [trainingDays,  setTrainingDays]  = useState(4);
  const [goalFocus,     setGoalFocus]     = useState("muscle");
  const [dietType,      setDietType]      = useState("standard");
  const [sleepGoal,     setSleepGoal]     = useState(8);
  const [aiPreview,     setAiPreview]     = useState(null);
  const [generating,    setGenerating]    = useState(false);

  const totalHeightIn = (heightFt * 12) + heightIn;

  // Auto-generate preview whenever inputs change
  useEffect(() => {
    const t = setTimeout(() => {
      const goals = generateAIGoals({ age, heightIn: totalHeightIn, bw, activityLevel, trainingDays, goalFocus, dietType, biology });
      setAiPreview(goals);
    }, 300);
    return () => clearTimeout(t);
  }, [age, heightFt, heightIn, activityLevel, trainingDays, goalFocus, dietType, biology, bw]);

  const handleSubmit = () => {
    setGenerating(true);
    setTimeout(() => {
      const goals = generateAIGoals({ age, heightIn: totalHeightIn, bw, activityLevel, trainingDays, goalFocus, dietType, biology });
      const profile = { ...goals, age, heightIn: totalHeightIn, bw, activityLevel, trainingDays, goalFocus, dietType };
      try { localStorage.setItem("rvn_profile", JSON.stringify(profile)); } catch {}
      onSubmit(profile);
    }, 600);
  };

  const TileRow = ({ options, value, onChange, cols = 2 }) => (
    <div style={{ display:"grid", gridTemplateColumns:`repeat(${cols}, 1fr)`, gap:8 }}>
      {options.map(opt => (
        <motion.button key={opt.value} whileTap={{ scale:.94 }}
          onClick={() => onChange(opt.value)}
          style={{
            padding:"10px 8px", borderRadius:12, cursor:"pointer",
            border:`1px solid ${value === opt.value ? ac : T.border}`,
            background: value === opt.value ? `${ac}18` : T.glass,
            color: value === opt.value ? ac : T.muted,
            fontSize:11, fontWeight:800, letterSpacing:".04em", textAlign:"center",
            boxShadow: value === opt.value ? `0 0 12px ${ac}33` : "none",
          }}>
          <div style={{ fontSize:16, marginBottom:3 }}>{opt.icon}</div>
          {opt.label}
        </motion.button>
      ))}
    </div>
  );

  const SectionLabel = ({ text }) => (
    <div style={{ fontSize:10, fontWeight:800, letterSpacing:".14em", color:T.faint, marginBottom:10, marginTop:20 }}>{text}</div>
  );

  return (
    <Screen theme={theme}>
      <div style={{ padding:"16px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <RVNLogo size={30}/>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:"16px 24px 36px" }}>
        <StepProgress step={4} total={6} label="KAILU PERSONALIZATION" accent={ac} theme={theme}/>

        <motion.div {...FX.up} style={{ marginTop:16, marginBottom:20 }}>
          <div style={{ fontSize:28, fontWeight:900, letterSpacing:"-.02em", color:T.text }}>
            Personalize Your Goals
          </div>
          <div style={{ fontSize:13, color:T.muted, marginTop:4, lineHeight:1.5 }}>
            Answer a few questions and our AI will calculate your exact macro targets, sleep goals, and training load — backed by peer-reviewed research.
          </div>
        </motion.div>

        {/* Age */}
        <SectionLabel text="YOUR AGE"/>
        <div style={{ display:"flex", alignItems:"center", gap:16, marginBottom:4 }}>
          <input type="range" min={16} max={65} step={1} value={age}
            onChange={e => setAge(Number(e.target.value))}
            style={{ flex:1, accentColor: ac }}/>
          <div style={{ fontSize:28, fontWeight:900, color:T.text, minWidth:52, textAlign:"right" }}>
            {age}<span style={{ fontSize:13, color:T.faint, marginLeft:3 }}>yrs</span>
          </div>
        </div>

        {/* Height */}
        <SectionLabel text="HEIGHT"/>
        <div style={{ display:"flex", gap:12 }}>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:9, color:T.faint, marginBottom:4 }}>FEET</div>
            <input type="range" min={4} max={7} step={1} value={heightFt}
              onChange={e => setHeightFt(Number(e.target.value))}
              style={{ width:"100%", accentColor: ac }}/>
            <div style={{ fontSize:22, fontWeight:900, color:T.text, textAlign:"center", marginTop:4 }}>
              {heightFt}<span style={{ fontSize:12, color:T.faint }}>ft</span>
            </div>
          </div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:9, color:T.faint, marginBottom:4 }}>INCHES</div>
            <input type="range" min={0} max={11} step={1} value={heightIn}
              onChange={e => setHeightIn(Number(e.target.value))}
              style={{ width:"100%", accentColor: ac }}/>
            <div style={{ fontSize:22, fontWeight:900, color:T.text, textAlign:"center", marginTop:4 }}>
              {heightIn}<span style={{ fontSize:12, color:T.faint }}>in</span>
            </div>
          </div>
        </div>

        {/* Activity Level */}
        <SectionLabel text="ACTIVITY LEVEL OUTSIDE THE GYM"/>
        <TileRow cols={2} value={activityLevel} onChange={setActivityLevel} options={[
          { value:"sedentary", icon:"🪑", label:"Desk Job" },
          { value:"light",     icon:"🚶", label:"Lightly Active" },
          { value:"moderate",  icon:"🚴", label:"Moderately Active" },
          { value:"active",    icon:"⚡", label:"Very Active" },
        ]}/>

        {/* Goal Focus */}
        <SectionLabel text="PRIMARY GOAL"/>
        <TileRow cols={3} value={goalFocus} onChange={setGoalFocus} options={[
          { value:"muscle", icon:"💪", label:"Build Muscle" },
          { value:"fat",    icon:"🔥", label:"Lose Fat"    },
          { value:"recomp", icon:"⚖️", label:"Recomp"      },
        ]}/>

        {/* Training Days */}
        <SectionLabel text="GYM SESSIONS PER WEEK"/>
        <div style={{ display:"flex", gap:8 }}>
          {[2,3,4,5,6].map(d => (
            <motion.button key={d} whileTap={{ scale:.92 }}
              onClick={() => setTrainingDays(d)}
              style={{
                flex:1, padding:"12px 0", borderRadius:10, cursor:"pointer",
                border:`1px solid ${trainingDays===d ? ac : T.border}`,
                background: trainingDays===d ? `${ac}18` : T.glass,
                color: trainingDays===d ? ac : T.muted,
                fontSize:16, fontWeight:900,
              }}>{d}x</motion.button>
          ))}
        </div>

        {/* Diet Type */}
        <SectionLabel text="DIET STYLE"/>
        <TileRow cols={2} value={dietType} onChange={setDietType} options={[
          { value:"standard",    icon:"🥩", label:"Standard"    },
          { value:"plant",       icon:"🥦", label:"Plant-Based" },
          { value:"keto",        icon:"🥑", label:"Keto"        },
          { value:"highcarb",    icon:"🍚", label:"High Carb"   },
        ]}/>

        {/* Sleep Goal */}
        <SectionLabel text="SLEEP TARGET (HOURS/NIGHT)"/>
        <div style={{ display:"flex", alignItems:"center", gap:16, marginBottom:4 }}>
          <input type="range" min={5} max={10} step={0.5} value={sleepGoal}
            onChange={e => setSleepGoal(Number(e.target.value))}
            style={{ flex:1, accentColor: ac }}/>
          <div style={{ fontSize:28, fontWeight:900, color:T.text, minWidth:52, textAlign:"right" }}>
            {sleepGoal}<span style={{ fontSize:13, color:T.faint, marginLeft:3 }}>h</span>
          </div>
        </div>

        {/* AI Preview Card */}
        {aiPreview && (
          <motion.div key={JSON.stringify(aiPreview.macroGoals)} {...FX.up}
            style={{ marginTop:20, marginBottom:8 }}>
            <GlassCard theme={theme} glow={ac} style={{ padding:"14px" }}>
              <div style={{ fontSize:9, fontWeight:800, letterSpacing:".16em", color:ac, marginBottom:8 }}>
                ◈ KAILU-GENERATED TARGETS · UPDATES IN REAL TIME
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:8, marginBottom:10 }}>
                {[
                  { label:"CALORIES", value:`${aiPreview.calories}`, unit:"kcal", color:T.text },
                  { label:"PROTEIN",  value:`${aiPreview.macroGoals.protein}`, unit:"g", color:ac },
                  { label:"CARBS",    value:`${aiPreview.macroGoals.carbs}`,   unit:"g", color:T.teal },
                  { label:"FATS",     value:`${aiPreview.macroGoals.fats}`,    unit:"g", color:"#FF9F0A" },
                ].map(({ label, value, unit, color }) => (
                  <div key={label} style={{ background:T.glass, borderRadius:10, padding:"8px 6px", textAlign:"center", border:`1px solid ${T.border}` }}>
                    <div style={{ fontSize:8, color:T.faint, letterSpacing:".1em", fontWeight:700, marginBottom:3 }}>{label}</div>
                    <div style={{ fontSize:18, fontWeight:900, color, fontVariantNumeric:"tabular-nums" }}>{value}</div>
                    <div style={{ fontSize:9, color:T.faint }}>{unit}</div>
                  </div>
                ))}
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:8, padding:"8px 10px", background:T.glass, borderRadius:8 }}>
                <div style={{ fontSize:16 }}>😴</div>
                <div>
                  <div style={{ fontSize:10, fontWeight:800, color:T.text }}>Sleep Target: {aiPreview.sleepTarget}h</div>
                  <div style={{ fontSize:10, color:T.muted, lineHeight:1.4 }}>{aiPreview.reasoning.sleep}</div>
                </div>
              </div>
              <div style={{ marginTop:8, fontSize:9.5, color:T.muted, lineHeight:1.5 }}>
                {aiPreview.reasoning.calories}
              </div>
            </GlassCard>
          </motion.div>
        )}

        {/* Actions */}
        <motion.div style={{ marginTop:16, display:"flex", flexDirection:"column", gap:10 }}>
          <ShimmerCTA
            label={generating ? "Kailu is calculating…" : "Generate with Kailu  →"}
            onClick={handleSubmit} theme={theme} color={ac}
          />
          <button onClick={() => onSubmit(null)}
            style={{ padding:"10px", borderRadius:12, background:"transparent", border:`1px solid ${T.border}`, color:T.faint, fontSize:10, fontWeight:700, letterSpacing:".1em", cursor:"pointer" }}>
            ⚡ SKIP · USE DEFAULTS
          </button>
        </motion.div>
      </div>
    </Screen>
  );
}

// ─── DIGITAL KEY ANIMATION ───────────────────────────────────────────────────
function DigitalKey({ color="#D4AF37", theme }) {
  const T = D[theme]||D.dark;
  const [unlocked, setUnlocked] = useState(false);
  const [beams,    setBeams]    = useState(false);

  useEffect(() => {
    const t1 = setTimeout(() => setUnlocked(true), 400);
    const t2 = setTimeout(() => setBeams(true),    900);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, []);

  return (
    <div style={{ position:"relative", width:120, height:130, display:"flex",
      alignItems:"center", justifyContent:"center" }}>
      {/* Radial glow pulse */}
      <motion.div
        animate={{ scale:[1,1.6,1], opacity:[0.3,0,0.3] }}
        transition={{ duration:2.4, repeat:Infinity }}
        style={{ position:"absolute", width:100, height:100, borderRadius:"50%",
          background:`radial-gradient(circle, ${color}44 0%, transparent 70%)`,
          pointerEvents:"none" }}/>

      {/* Beam rays */}
      {beams && [0,45,90,135,180,225,270,315].map((deg,i) => (
        <motion.div key={deg}
          initial={{ opacity:0, scaleX:0 }}
          animate={{ opacity:[0,0.7,0], scaleX:[0,1,0] }}
          transition={{ duration:0.8, delay:i*0.06, repeat:Infinity, repeatDelay:1.8 }}
          style={{
            position:"absolute", top:"50%", left:"50%",
            width:44, height:1.5,
            background:`linear-gradient(90deg, ${color}, transparent)`,
            transformOrigin:"left center",
            transform:`rotate(${deg}deg)`,
          }}/>
      ))}

      {/* Key SVG */}
      <motion.svg width="72" height="110" viewBox="0 0 72 110"
        animate={{ rotateY: unlocked ? [0,360] : 0 }}
        transition={{ duration:0.9, ease:[.22,1,.36,1] }}
        style={{ transformStyle:"preserve-3d", filter:`drop-shadow(0 0 8px ${color}88)` }}>
        <defs>
          <linearGradient id="dkey_grad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor={color}/>
            <stop offset="100%" stopColor={color} stopOpacity="0.5"/>
          </linearGradient>
          <filter id="dkey_glow">
            <feGaussianBlur stdDeviation="3" result="b"/>
            <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
          </filter>
        </defs>

        {/* Key bow (circle) */}
        <circle cx="36" cy="26" r="20" fill="none"
          stroke="url(#dkey_grad)" strokeWidth="5"
          filter="url(#dkey_glow)" opacity="0.95"/>
        {/* Key hole */}
        <circle cx="36" cy="26" r="7" fill="none"
          stroke={color} strokeWidth="2.5" opacity="0.6"/>

        {/* Key shaft */}
        <rect x="33" y="44" width="6" height="46" rx="3"
          fill="url(#dkey_grad)" filter="url(#dkey_glow)"/>

        {/* Key teeth */}
        <rect x="39" y="56" width="10" height="5" rx="2" fill={color} opacity="0.85"/>
        <rect x="39" y="68" width="7"  height="5" rx="2" fill={color} opacity="0.85"/>
        <rect x="39" y="80" width="10" height="5" rx="2" fill={color} opacity="0.85"/>

        {/* Circuit traces on bow */}
        {[0,60,120,180,240,300].map((a,i) => {
          const rad=a*Math.PI/180;
          const x1=36+20*Math.cos(rad), y1=26+20*Math.sin(rad);
          const x2=36+28*Math.cos(rad), y2=26+28*Math.sin(rad);
          return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2}
            stroke={color} strokeWidth="1.2" strokeOpacity="0.4"/>;
        })}

        {/* Lock icon (fades out on unlock) */}
        <motion.g animate={{ opacity:unlocked?0:1 }} transition={{ duration:.4 }}>
          <rect x="28" y="18" width="16" height="14" rx="4"
            fill="none" stroke={color} strokeWidth="2" opacity="0.5"/>
          <circle cx="36" cy="26" r="3" fill={color} opacity="0.6"/>
        </motion.g>

        {/* Checkmark (fades in on unlock) */}
        <motion.g animate={{ opacity:unlocked?1:0, scale:unlocked?1:0.5 }}
          transition={{ duration:.5, delay:.1 }}
          style={{ transformOrigin:"36px 26px" }}>
          <path d="M29,26 L34,31 L43,20"
            fill="none" stroke={color} strokeWidth="3"
            strokeLinecap="round" strokeLinejoin="round"
            filter="url(#dkey_glow)"/>
        </motion.g>
      </motion.svg>

      {/* Unlock label */}
      <motion.div
        initial={{ opacity:0, y:6 }}
        animate={{ opacity:unlocked?1:0, y:unlocked?0:6 }}
        transition={{ delay:.7, duration:.5 }}
        style={{ position:"absolute", bottom:0, fontSize:9, fontWeight:800,
          letterSpacing:".18em", color }}>
        BIO-VAULT OPEN
      </motion.div>
    </div>
  );
}

// ─── ACCOUNT / BIO-IDENTITY ───────────────────────────────────────────────────
function AccountScreen({ onComplete, onBack, theme, mode }) {
  const T = D[theme];
  const M = OS_MODES[mode];
  const ac = T[M.accentKey];
  const [phase, setPhase]       = useState(0);
  const [name, setName]         = useState("");
  const [email, setEmail]       = useState("");
  const [vaultEmail, setVaultEmail]   = useState("");
  const [vaultPass,  setVaultPass]    = useState("");
  const [vaultName,  setVaultName]    = useState("");
  const [vaultDone,  setVaultDone]    = useState(false);

  const [password,   setPassword]   = useState("");
  const [confirmPw,  setConfirmPw]  = useState("");
  const [showPw,     setShowPw]     = useState(false);
  const [pwErr,      setPwErr]      = useState("");
  const [signingUp,  setSigningUp]  = useState(false);
  const [gymCode,    setGymCode]    = useState("");
  const [gymInfo,    setGymInfo]    = useState(null);  // { id, name, tier } if valid
  const [gymChecking,setGymChecking] = useState(false);
  const [gymErr,     setGymErr]     = useState("");

  const checkGymCode = async (code) => {
    if (!code.trim()) { setGymInfo(null); setGymErr(""); return; }
    setGymChecking(true); setGymErr("");
    try {
      const client = await getSupaClient();
      const { data, error } = await client
        .from("rvn_gyms")
        .select("id,name,tier,subscription_status,member_cap")
        .eq("gym_code", code.trim().toUpperCase())
        .single();
      if (error || !data) { setGymInfo(null); setGymErr("Gym code not found."); }
      else if (data.subscription_status !== "active") { setGymInfo(null); setGymErr("This gym's subscription is inactive."); }
      else { setGymInfo(data); setGymErr(""); }
    } catch (_) { setGymErr("Could not verify code. Try again."); }
    setGymChecking(false);
  };

  const handleCreateAccount = async () => {
    setPwErr("");
    if (!name.trim())        { setPwErr("Enter your name."); return; }
    if (!email.trim())       { setPwErr("Enter your email."); return; }
    if (password.length < 8) { setPwErr("Password must be at least 8 characters."); return; }
    if (gymCode.trim() && !gymInfo) { setPwErr("Enter a valid gym code or leave it blank."); return; }
    setSigningUp(true);
    try {
      const client = await getSupaClient();
      const { error } = await client.auth.signUp({ email: email.trim(), password: password.trim() });
      if (error && !error.message.includes("already registered")) throw error;
    } catch (e) {
      setSigningUp(false);
      setPwErr(e.message || "Sign-up failed. Try again.");
      return;
    }
    setSigningUp(false);
    onComplete({
      name: email.trim(),
      email: email.trim(),
      gymId: gymInfo?.id || null,
      gymName: gymInfo?.name || null,
      gymTier: gymInfo?.tier || null,
      subscriptionStatus: gymInfo ? "gym_member" : "individual",
    });
  };


  const startScan = () => { setPhase(1); setTimeout(() => setPhase(2), 2600); };

  return (
    <Screen theme={theme}>
      <div style={{ padding:"20px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <RVNLogo size={30}/>
      </div>
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", padding:"16px 24px 36px" }}>
        <StepProgress step={4} total={5} label="BIO-IDENTITY VAULT" accent={ac} theme={theme}/>
        <motion.div {...FX.up} style={{ marginTop:24, textAlign:"center", marginBottom:28 }}>
          <div style={{ fontSize:30, fontWeight:900, letterSpacing:"-.02em", color:T.text }}>
            Secure Your<br/>Bio-Identity
          </div>
          <div style={{ fontSize:13, color:T.muted, marginTop:6 }}>
            {phase<2 ? "Biometric registration in progress" : "Identity confirmed — welcome to the OS"}
          </div>
        </motion.div>

        <IrisScan phase={phase} theme={theme}/>

        {phase===0 && (
          <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} transition={{ delay:.3 }}
            style={{ marginTop:28, width:"100%", maxWidth:310 }}>
            <ShimmerCTA label="Initialize Iris Scan  ◉" onClick={startScan} theme={theme} color={ac}/>
          </motion.div>
        )}

        {phase===1 && (
          <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }}
            style={{ marginTop:24, textAlign:"center", display:"flex", flexDirection:"column", alignItems:"center", gap:8 }}>
            <AITyping theme={theme}/>
            <div style={{ fontSize:11, fontWeight:700, color:ac, letterSpacing:".16em", animation:"os_pulse 1s ease-in-out infinite" }}>
              READING BIOMETRIC SIGNATURE
            </div>
          </motion.div>
        )}

        {phase===2 && (
          <motion.div {...FX.up} style={{ marginTop:16, width:"100%", maxWidth:340 }}>
            {/* Digital Key unlock animation */}
            <div style={{ display:"flex", justifyContent:"center", marginBottom:18 }}>
              <DigitalKey color={ac} theme={theme}/>
            </div>

            <div style={{ textAlign:"center", marginBottom:20 }}>
              <Pill label="◉  BIO-VAULT UNLOCKED" color={T.green} theme={theme}/>
              <div style={{ fontSize:11, color:T.muted, marginTop:8, lineHeight:1.6 }}>
                Your encrypted biometric profile is active.<br/>
                Enter your details to personalize your vault.
              </div>
            </div>

            {/* Name input */}
            <GlassCard theme={theme}
              style={{ padding:"14px 16px", marginBottom:10,
                border:`1px solid ${ac}44`, boxShadow:`0 0 16px ${ac}18` }}>
              <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                VAULT ALIAS
              </div>
              <input value={name} onChange={e => setName(e.target.value)}
                placeholder="Enter your name"
                style={{ width:"100%", fontSize:17, fontWeight:600 }}/>
            </GlassCard>

            {/* Email — required for Supabase auth */}
            <GlassCard theme={theme}
              style={{ padding:"14px 16px", marginBottom:10,
                border:`1px solid ${ac}22` }}>
              <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                EMAIL <span style={{ color:T.red }}>*</span>
              </div>
              <input value={email} onChange={e => { setEmail(e.target.value); setPwErr(""); }}
                placeholder="you@domain.com"
                type="email"
                style={{ width:"100%", fontSize:17, fontWeight:600 }}/>
            </GlassCard>

            {/* Password */}
            <GlassCard theme={theme}
              style={{ padding:"14px 16px", marginBottom:10,
                border:`1px solid ${ac}22`, marginBottom:14 }}>
              <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                PASSWORD <span style={{ color:T.red }}>*</span>
                <span style={{ color:T.faint, fontWeight:500, marginLeft:6 }}>min 8 chars</span>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                <input type={showPw ? "text" : "password"} value={password}
                  onChange={e => { setPassword(e.target.value); setPwErr(""); }}
                  placeholder="••••••••"
                  style={{ flex:1, fontSize:17, fontWeight:600, letterSpacing: showPw ? ".02em" : ".22em" }}/>
                <button onClick={() => setShowPw(s => !s)}
                  style={{
                    background:"transparent", border:`1px solid ${T.border}`,
                    borderRadius:8, padding:"3px 8px", cursor:"pointer",
                    fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".08em", flexShrink:0,
                  }}>
                  {showPw ? "HIDE" : "SHOW"}
                </button>
              </div>
            </GlassCard>


            {pwErr && (
              <div style={{ fontSize:11, color:T.red, marginBottom:10,
                textAlign:"center", letterSpacing:".04em" }}>
                {pwErr}
              </div>
            )}

            {/* Gym Code — optional, for corporate gym members */}
            <div style={{ marginBottom:14 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:6 }}>
                <div style={{ flex:1, height:1, background:T.border }}/>
                <span style={{ fontSize:9, color:T.faint, letterSpacing:".12em" }}>OPTIONAL · GYM MEMBER?</span>
                <div style={{ flex:1, height:1, background:T.border }}/>
              </div>
              <GlassCard theme={theme} style={{ padding:"14px 16px",
                border:`1px solid ${gymInfo ? T.green+"66" : ac+"11"}` }}>
                <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                  GYM CODE
                  <span style={{ fontWeight:500, color:T.faint, marginLeft:6 }}>— enter if your gym is on RVN</span>
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <input value={gymCode}
                    onChange={e => { setGymCode(e.target.value.toUpperCase()); setGymInfo(null); setGymErr(""); }}
                    onBlur={() => checkGymCode(gymCode)}
                    placeholder="e.g. IRONHAUS"
                    style={{ flex:1, fontSize:17, fontWeight:700, letterSpacing:".08em" }}/>
                  {gymChecking && <span style={{ fontSize:10, color:T.faint, letterSpacing:".1em" }}>CHECKING…</span>}
                  {gymInfo && <span style={{ fontSize:10, fontWeight:800, color:T.green, letterSpacing:".1em" }}>✓ VERIFIED</span>}
                </div>
                {gymErr && <div style={{ fontSize:10, color:T.red, marginTop:4 }}>{gymErr}</div>}
                {gymInfo && (
                  <div style={{ fontSize:10, color:T.green, marginTop:4, letterSpacing:".06em" }}>
                    {gymInfo.name} · {(gymInfo.tier||"").toUpperCase()} · FREE ACCESS UNLOCKED
                  </div>
                )}
              </GlassCard>
            </div>

            {/* Primary CTA */}
            <ShimmerCTA
              label={signingUp ? "Creating Vault…" : name.trim() ? `Secure My Vault, ${name.split(" ")[0]}  →` : "Secure My Vault  →"}
              onClick={() => !signingUp && handleCreateAccount()}
              theme={theme} color={ac}
              disabled={signingUp || !name.trim() || !email.trim() || password.length < 8}/>


            {/* Signup / Account link — minimalist, high-end */}
            <div style={{ textAlign:"center", marginTop:18 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, justifyContent:"center",
                marginBottom:10 }}>
                <div style={{ flex:1, height:"1px", background:T.border }}/>
                <span style={{ fontSize:9, color:T.faint, letterSpacing:".12em" }}>OR</span>
                <div style={{ flex:1, height:"1px", background:T.border }}/>
              </div>
              <motion.button whileHover={{ scale:1.02 }} whileTap={{ scale:.97 }}
                onClick={() => setPhase(3)}
                style={{
                  background:"none", border:`1px solid ${T.border}`, borderRadius:14,
                  padding:"11px 24px", cursor:"pointer", width:"100%",
                  fontSize:12, fontWeight:700, color:T.muted, letterSpacing:".06em",
                }}>
                Create a Bio-Vault Account
              </motion.button>
              <div style={{ fontSize:9.5, color:T.faint, marginTop:8, lineHeight:1.6 }}>
                Save your protocol. Track progress. Sync across devices.
              </div>
            </div>
          </motion.div>
        )}

        {/* Phase 3 — Bio-Vault account creation */}
        {phase===3 && (
          <motion.div
            initial={{ opacity:0, x:40 }} animate={{ opacity:1, x:0 }}
            exit={{ opacity:0, x:-40 }} transition={{ duration:.38, ease:[.22,1,.36,1] }}
            style={{ width:"100%", maxWidth:340, marginTop:16 }}>

            {/* Back to vault */}
            <motion.button whileTap={{ scale:.92 }} onClick={() => setPhase(2)}
              style={{ background:"none", border:"none", cursor:"pointer",
                display:"flex", alignItems:"center", gap:6,
                fontSize:11, color:T.faint, marginBottom:18, padding:0 }}>
              ← Back
            </motion.button>

            {!vaultDone ? (
              <>
                <div style={{ textAlign:"center", marginBottom:22 }}>
                  <div style={{ fontSize:26, fontWeight:900, color:T.text,
                    letterSpacing:"-.02em" }}>Create Your<br/>
                    <span style={{ color:ac }}>Bio-Vault</span>
                  </div>
                  <div style={{ fontSize:11, color:T.muted, marginTop:6 }}>
                    Encrypted. Biometric-locked. Yours forever.
                  </div>
                </div>

                {/* Vault account fields */}
                {[
                  { label:"FULL NAME",      val:vaultName,  set:setVaultName,  ph:"Your name",           type:"text"     },
                  { label:"EMAIL ADDRESS",  val:vaultEmail, set:setVaultEmail, ph:"name@email.com",       type:"email"    },
                  { label:"VAULT PASSWORD", val:vaultPass,  set:setVaultPass,  ph:"Min. 8 characters",    type:"password" },
                ].map(f => (
                  <GlassCard key={f.label} theme={theme}
                    style={{ padding:"12px 16px", marginBottom:10,
                      border:`1px solid ${vaultEmail&&f.label==="EMAIL ADDRESS"?ac+"44":T.border}` }}>
                    <div style={{ fontSize:8.5, fontWeight:800, color:T.faint,
                      letterSpacing:".14em", marginBottom:5 }}>{f.label}</div>
                    <input value={f.val} onChange={e => f.set(e.target.value)}
                      placeholder={f.ph} type={f.type}
                      style={{ width:"100%", fontSize:16, fontWeight:600,
                        background:"none", border:"none", outline:"none", color:T.text }}/>
                  </GlassCard>
                ))}

                {/* Perks list */}
                <div style={{ margin:"14px 0 18px", padding:"12px 14px",
                  background:T.glass, borderRadius:12, border:`1px solid ${T.border}` }}>
                  {[
                    "\u25c9  Protocol saved & synced across devices",
                    "\u25c9  Biometric profile encrypted in vault",
                    "\u25c9  Progress tracked over 6-month timeline",
                    "\u25c9  Early access to new RVN OS features",
                  ].map(line => (
                    <div key={line} style={{ fontSize:10, color:T.muted,
                      marginBottom:5, lineHeight:1.5 }}>{line}</div>
                  ))}
                </div>

                <ShimmerCTA
                  label={vaultName&&vaultEmail&&vaultPass.length>=8
                    ? "Activate Bio-Vault  →" : "Complete all fields"}
                  onClick={() => {
                    if (vaultName&&vaultEmail&&vaultPass.length>=8) setVaultDone(true);
                  }}
                  theme={theme} color={ac}
                  disabled={!(vaultName&&vaultEmail&&vaultPass.length>=8)}/>

                <div style={{ textAlign:"center", marginTop:10,
                  fontSize:8.5, color:T.faint, lineHeight:1.6 }}>
                  Your data never leaves this device without your consent.
                </div>
              </>
            ) : (
              /* Success state */
              <motion.div initial={{ opacity:0, scale:.9 }} animate={{ opacity:1, scale:1 }}
                transition={{ duration:.5, ease:[.22,1,.36,1] }}
                style={{ textAlign:"center", padding:"32px 20px" }}>
                <motion.div
                  animate={{ scale:[1,1.15,1], opacity:[0.7,1,0.7] }}
                  transition={{ duration:2, repeat:Infinity }}
                  style={{ fontSize:52, marginBottom:16 }}>
                  {"\u25c9"}
                </motion.div>
                <div style={{ fontSize:22, fontWeight:900, color:ac,
                  letterSpacing:"-.01em", marginBottom:8 }}>
                  Vault Active
                </div>
                <div style={{ fontSize:12, color:T.muted, lineHeight:1.7, marginBottom:24 }}>
                  Welcome, {vaultName.split(" ")[0]}.<br/>
                  Your Bio-Vault is encrypted and live.
                </div>
                <ShimmerCTA
                  label="Continue to Protocol  →"
                  onClick={() => onComplete({ name:vaultName.trim(), email:vaultEmail.trim() })}
                  theme={theme} color={ac}/>
              </motion.div>
            )}
          </motion.div>
        )}
      </div>
    </Screen>
  );
}

