const MANIFEST_LIST = Object.values(BIO_LOGIC_MANIFEST);

// Look up a manifest entry by any alias mentioned in a user phrase
function matchManifest(text) {
  const lower = (text || "").toLowerCase();
  for (const entry of MANIFEST_LIST) {
    for (const a of entry.aliases) {
      // word-boundary-ish match
      const re = new RegExp(`(^|[^a-z])${a.replace(/[-/\\^$*+?.()|[\]{}]/g, "\\$&")}($|[^a-z])`, "i");
      if (re.test(lower)) return entry;
    }
  }
  return null;
}

// ─── INTENT CLASSIFIER ──────────────────────────────────────────────────────
// Keyword-weighted. Good-enough for a kiosk; replaceable with a model call.
const INTENT_KEYWORDS = {
  schedule:   ["schedule", "plan my day", "daily plan", "24 hour", "24-hour", "routine", "day plan", "plan the day", "build a day", "what should my day", "my day", "morning routine", "evening routine", "time blocking", "time block", "lock in my day", "give me a plan"],
  food:       ["ate", "eating", "just had", "had a", "drinking", "drank", "breakfast", "lunch", "dinner", "meal", "snack", "protein shake", "chicken", "rice", "eggs", "oats", "bowl", "carbs", "calories", "g protein", "grams", "macros"],
  injury:     ["hurt", "pain", "injured", "injury", "sore", "soreness", "tweak", "tweaked", "pulled", "strain", "strained", "ache", "aching", "stiff", "can't lift", "cant lift", "knee pain", "shoulder pain", "back pain", "cramping"],
  goal:       ["goal", "trying to", "want to", "i want", "i'd like", "build", "cut", "lean out", "gain", "bulk", "target", "competition", "meet", "show", "wedding", "reset my goal", "change my goal"],
  supplement: ["supplement", "stack", "should i take", "what do you recommend", "thorne", "creatine", "magnesium", "ashwagandha", "omega", "fish oil", "nmn", "whey", "protein powder", "electrolyte", "dosage", "dose", "when to take"],
  sleep:      ["sleep", "slept", "hours of sleep", "tired", "exhausted", "wired", "insomnia", "couldn't sleep", "cant sleep"],
  stress:     ["stressed", "anxious", "anxiety", "overwhelmed", "burnt out", "burned out", "cortisol"],
  training:   ["workout", "training", "lift", "lifted", "session", "set", "rep", "1rm", "pr", "cardio", "run", "running", "bench", "squat", "deadlift"],
  workout_generate: ["create a workout", "generate a workout", "build me a workout", "make me a program", "give me a program", "write me a workout", "build a program", "what should i do today", "give me a workout", "build my workout", "design a workout", "plan my workout", "training program", "training plan"],
};

function classifyIntent(text) {
  const lower = (text || "").toLowerCase();
  let best = null, bestScore = 0;
  for (const [intent, kws] of Object.entries(INTENT_KEYWORDS)) {
    let score = 0;
    for (const k of kws) if (lower.includes(k)) score += 1 + (k.length > 6 ? 0.3 : 0);
    if (score > bestScore) { best = intent; bestScore = score; }
  }
  return bestScore > 0 ? best : "chat";
}

// Pull macro-ish numbers out of free text: "had 40g of chicken" → { amount:40, unit:"g", kind:"protein" }
function extractMacroLog(text) {
  const lower = (text || "").toLowerCase();
  const grams = lower.match(/(\d+(?:\.\d+)?)\s*g(?:rams)?/);
  const oz    = lower.match(/(\d+(?:\.\d+)?)\s*oz/);
  let amount = grams ? parseFloat(grams[1]) : oz ? parseFloat(oz[1]) * 28.35 : null;

  let kind = null;
  if (/chicken|beef|steak|egg|salmon|tuna|whey|protein|yogurt|cottage/i.test(lower)) kind = "protein";
  else if (/rice|pasta|oat|bread|bagel|potato|banana|carb/i.test(lower))              kind = "carbs";
  else if (/avocado|nut|butter|oil|cheese|fat/i.test(lower))                          kind = "fat";
  else if (/fiber|salad|broccoli|veggies|vegetable|greens/i.test(lower))              kind = "fiber";
  else if (/water|\boz\b|hydrat/i.test(lower))                                        kind = "water";

  if (kind && !amount) {
    // estimate defaults for common items
    if (/chicken\s*breast/.test(lower))  amount = 30;
    else if (/eggs?/.test(lower))        amount = 6;
    else if (/shake|protein/.test(lower)) amount = 25;
    else if (/banana/.test(lower))        amount = 27;
    else if (/rice.*bowl|bowl.*rice/.test(lower)) amount = 45;
  }

  if (!kind || !amount) return null;
  return { kind, amount, unit: kind === "water" ? "oz" : "g", note: text.slice(0, 80) };
}

