// ─── CONTEXT EXTRACTORS ─────────────────────────────────────────────────────
// Pick up lifestyle signals out of the user's free text. These let us tune
// the schedule & advice without asking follow-up questions.
function readLifeContext(text) {
  const lower = (text || "").toLowerCase();
  return {
    nineToFive:  /\b(9[\s-]?(?:to|-)[\s-]?5|desk job|office job|cubicle|at work|at the office)\b/.test(lower),
    student:     /\b(student|study|studying|exam|class|classes|college|uni|school|biochem|chem major|pre[\s-]?med)\b/.test(lower),
    biochem:     /\b(biochem|biochemistry|chem major|chemistry major|organic chem)\b/.test(lower),
    sales:       /\b(sales|client call|pitching|quota|prospecting)\b/.test(lower),
    parent:      /\b(kid|kids|daughter|son|baby|toddler|parent|parenting)\b/.test(lower),
    earlyRiser:  /\b(up at [3-6]|5am|4am|early bird|morning person)\b/.test(lower),
    nightOwl:    /\b(night owl|up late|late night|2am|1am|midnight)\b/.test(lower),
    cutting:     /\b(cut|cutting|deficit|lean out|drop weight|lose fat)\b/.test(lower),
    bulking:     /\b(bulk|bulking|surplus|gain weight|mass)\b/.test(lower),
    squat405:    /\b405\b/.test(lower),
    powerlifter: /\b(powerlift|powerlifter|meet|usapl|usapa|spf)\b/.test(lower),
  };
}

// ─── GENERATIVE 24-HOUR SCHEDULE ENGINE ────────────────────────────────────
// Builds a plan tuned to context: 9-5 workers get cortisol-management blocks,
// students get focus windows, lifters get training + recovery anchors.
function generateDaySchedule(text, state) {
  const ctx = readLifeContext(text);
  const readiness = state.bioLogic?.readiness ?? 75;
  const lowReadiness = readiness < 65;
  const items = [];
  const push = (time, title, category, note) =>
    items.push({ time, title, category, note });

  // — Pre-dawn: hydration + cortisol priming —
  push("05:45", "Wake + 16oz water with electrolytes",
    "hydration",
    "Rehydrate before caffeine. Sodium restores plasma volume after the overnight fast.");
  push("06:00", "10-min mobility + sunlight exposure",
    "recovery",
    "Morning light locks circadian rhythm — cortisol wave peaks cleanly instead of dragging all day.");

  // — Training window — early if 9-5, otherwise mid-morning —
  if (ctx.nineToFive || ctx.student) {
    push("06:20", lowReadiness ? "Mobility + Zone-2 cardio (30 min)" : "Strength session — main lift day",
      "training",
      lowReadiness
        ? "Readiness low — down-regulate. Preserve adaptation, skip the heavy triples."
        : (ctx.squat405 ? "Keep the 405 squat on a 3-week wave. Top sets AM when neural drive peaks." : "Compound first, accessories second. Rest 3:00 between heavy sets."));
    push("07:30", "Hot shower → cold finish",
      "recovery",
      "30s cold at the end shuts down residual inflammation and sharpens the next 4 hours.");
    push("07:45", "Protein-led breakfast (40g+)",
      "nutrition",
      ctx.biochem
        ? "Biochem grind: 4 eggs + 1 scoop whey + oats. Leucine + slow carbs = steady dopamine through orgo."
        : "40g protein locks muscle protein synthesis. Slow carbs for the morning cognitive window.");
  } else {
    push("07:00", "Protein-led breakfast (40g+)", "nutrition",
      "Set the MPS clock early. Whey or eggs within 60 min of waking.");
    push("09:30", "Strength session — main lift",
      "training",
      ctx.squat405 ? "405 squat on a 3-week wave — keep the bar speed." : "Compound focus, 3:00 rest on heavy sets.");
  }

  // — 9-5 / study block —
  if (ctx.nineToFive || ctx.student) {
    push("09:00", ctx.student ? "Deep focus block — hardest course first" : "Deep-work block #1 (90 min)",
      "focus",
      "Phone in another room. No meetings. This is where 80% of your output is made.");
    push("10:30", "Stand + 8oz water + 5-min walk",
      "recovery",
      "Every 90 min. Lymph flow, cortisol dip, eye-distance reset.");
    push("11:00", ctx.sales ? "Calls / prospecting block" : "Deep-work block #2",
      "focus",
      ctx.sales ? "Stack the high-energy outreach here — voice is sharpest pre-lunch." : "Lighter cognitive tasks if the morning block was heavy.");
    push("12:30", "Lunch — 40g protein + fiber + complex carbs",
      "nutrition",
      ctx.cutting
        ? "Big volume, low density. Chicken, greens, sweet potato. Stay full without the insulin crash."
        : "Balanced plate: 40g protein minimum, a cup of greens, one fist of slow carbs.");
  }

  // — Afternoon cortisol dip + recovery —
  push("14:00", "5-min box breathing (4-4-4-4)",
    "stress",
    "Vagal activation. Drops afternoon cortisol; re-centers the HPA axis. More leverage than any afternoon coffee.");
  if (ctx.nineToFive || ctx.student) {
    push("14:15", ctx.student ? "Focus block — problem sets / memorization" : "Deep-work block #3",
      "focus",
      "Last sustained block of the day. After this, energy pivots.");
  }
  push("15:30", "Snack — 25g protein + handful of berries",
    "nutrition",
    "Bridges the insulin dip. Protein pulse protects lean mass if you're in a deficit.");

  // — Second session if no morning training —
  if (!ctx.nineToFive && !ctx.student) {
    push("16:30", "Conditioning — Zone 2 or sprints",
      "training",
      "Separate from the strength session. Builds the mitochondrial floor without cannibalizing recovery.");
  }

  // — Evening wind-down —
  push("18:30", "Dinner — largest protein dose (50g+)",
    "nutrition",
    "Whole-food protein + cruciferous veg + complex carb. Carbs here help sleep depth.");
  push("20:00", "Screen dim + blue-light off",
    "sleep",
    "Melatonin release is gated by retinal blue light. Shift the OS now, not at bedtime.");
  push("21:15", "300mg magnesium bisglycinate + 10-min read",
    "sleep",
    "Glycinate crosses the blood-brain barrier and stacks with the evening GABA pulse. N3 sleep deepens inside a week.");
  push("22:00", "Lights out — hard anchor",
    "sleep",
    "7.5-8h is the non-negotiable. Your 405 squat lives or dies here.");

  return items;
}

// ─── GENERATIVE ADVICE ENGINE — no templates, context-weighted prose ────────
// Pulls the strongest 2-3 signals from state + text and composes a coach
// response that reads like a conversation, not a dropdown.
function generateOpenAdvice(text, state) {
  const ctx = readLifeContext(text);
  const R = state.bioLogic?.readiness ?? 75;
  const mode = state.mode;
  const lines = [];

  // Opener — readiness-informed
  if (R < 55) lines.push("Let me be straight with you — readiness is in the red. Whatever we plan today has to protect the nervous system first.");
  else if (R < 70) lines.push("Readiness is middling. You'll get through the day, but we don't spend the tank on anything that isn't essential.");
  else lines.push("Your system looks primed.");

  // Biochem/student bias
  if (ctx.biochem || ctx.student) {
    lines.push("You're sitting in biochem half the day, so cortisol management is the lever — not another stim. Anchor two deep blocks, kill notifications, and get sunlight in the morning.");
    if (ctx.squat405) lines.push("The 405 squat survives finals only if the protein stays above 1 g/lb and sleep stays at 8 hours. Non-negotiable.");
  } else if (ctx.nineToFive) {
    lines.push("Desk work eats posture and testosterone — every 90 minutes stand, 2-minute walk, one set of 10 band pull-aparts. Compounds over a week.");
  } else if (ctx.sales) {
    lines.push("High-output voice work all day — hydrate hard, electrolytes twice, and keep caffeine under 300 mg or the afternoon tanks.");
  }

  // Goal-bias
  if (ctx.cutting) lines.push("Cutting: protein goes UP, not down. 1.1-1.2 g per pound of bodyweight. That's what preserves the strength base.");
  if (ctx.bulking) lines.push("Bulking: the ceiling is recovery, not calories. If soreness is dragging, you're adding mass you can't use.");

  // Closer — real coach energy
  const closers = [
    "Ask me for a schedule and I'll lock it to your Dashboard.",
    "Want me to build the day around this?",
    "Say the word and I'll draft a 24-hour plan you can lock in.",
    "I can generate a full-day blueprint if that's useful.",
  ];
  lines.push(closers[Math.floor(Math.random() * closers.length)]);

  return lines.join(" ");
}

// ─── RESPONSE COMPOSER — generative-first, grounded-when-needed ─────────────

// ─── GYM SUPPLEMENT CONFIG ────────────────────────────────────────────────────
const GYM_SUPPLEMENT_CONFIG = (typeof window !== "undefined" && window.RVN_GYM_SUPPLEMENTS) || {
  protein:    { brand: null, url: null },
  creatine:   { brand: null, url: null },
  preworkout: { brand: null, url: null },
  omega3:     { brand: null, url: null },
  vitamins:   { brand: null, url: null },
};

function getGymSupplementLine(category, state) {
  const tier = state?.sub?.subscription_tier || state?.sub?.gym_tier || "free";
  if (tier !== "gym_standard") return null;
  const cfg = GYM_SUPPLEMENT_CONFIG[category];
  if (!cfg?.brand) return null;
  return `Our gym recommends ${cfg.brand}${cfg.url ? " — available at " + cfg.url : ""}.`;
}

// ─── WORKOUT GENERATOR ────────────────────────────────────────────────────────
function generateWorkoutPlan(text, state) {
  const lower = (text || "").toLowerCase();
  const archetypeId = state?.archetypeId || "strength";
  const bioLogic    = state?.bioLogic    || {};
  const readiness   = bioLogic.readiness || 75;

  const isUpper  = /upper|chest|back|shoulder|arm|pull|push/.test(lower);
  const isLower  = /lower|leg|quad|hamstring|glute|squat|deadlift/.test(lower);
  const isCardio = /cardio|run|conditioning|hiit|circuit/.test(lower);
  const focus    = isUpper ? "upper" : isLower ? "lower" : isCardio ? "cardio" : "fullbody";

  const TEMPLATES = {
    upper: [
      { exercise:"Bench Press",           sets:4, reps:"6-8",     rest:"3 min",  notes:"Focus on chest stretch at bottom" },
      { exercise:"Pendlay Row",           sets:4, reps:"6-8",     rest:"3 min",  notes:"Explosively pull to lower chest" },
      { exercise:"Overhead Press",        sets:3, reps:"8-10",    rest:"2 min",  notes:"Brace core, no arch" },
      { exercise:"Lat Pulldown",          sets:3, reps:"10-12",   rest:"90 sec", notes:"Depress scapula before pulling" },
      { exercise:"Tricep Dips",           sets:3, reps:"10-12",   rest:"90 sec", notes:"Upright torso for tricep focus" },
      { exercise:"Face Pulls",            sets:3, reps:"15",      rest:"60 sec", notes:"External rotation finish" },
    ],
    lower: [
      { exercise:"Back Squat",            sets:4, reps:"5-6",     rest:"3 min",  notes:"Break parallel, drive knees out" },
      { exercise:"Romanian Deadlift",     sets:3, reps:"8-10",    rest:"2 min",  notes:"Hinge at hip, soft knee" },
      { exercise:"Leg Press",             sets:3, reps:"10-12",   rest:"90 sec", notes:"Full range, no lockout" },
      { exercise:"Bulgarian Split Squat", sets:3, reps:"10 each", rest:"90 sec", notes:"Front foot far enough forward" },
      { exercise:"Leg Curl",             sets:3, reps:"12-15",   rest:"60 sec", notes:"Pause at contraction" },
      { exercise:"Standing Calf Raise",   sets:4, reps:"15-20",   rest:"45 sec", notes:"Full range, slow eccentric" },
    ],
    cardio: [
      { exercise:"Warm-up (Rowing)",      sets:1, reps:"5 min",         rest:"—",        notes:"Moderate pace, HR to 130" },
      { exercise:"HIIT Sprints (Bike)",   sets:8, reps:"30s on/30s off", rest:"Embedded", notes:"All-out on intervals" },
      { exercise:"Incline Treadmill Walk",sets:1, reps:"10 min",        rest:"—",        notes:"12% incline, 3.5 mph" },
      { exercise:"Jump Rope",             sets:3, reps:"2 min",         rest:"60 sec",   notes:"Double-unders if capable" },
      { exercise:"Cool Down (Walk)",      sets:1, reps:"5 min",         rest:"—",        notes:"HR back under 120" },
    ],
    fullbody: [
      { exercise:"Deadlift",                  sets:4, reps:"4-6",   rest:"3 min",  notes:"Brace full before lift" },
      { exercise:"Incline Dumbbell Press",    sets:3, reps:"8-10",  rest:"2 min",  notes:"30° angle, neutral grip" },
      { exercise:"Chest-Supported Row",       sets:3, reps:"8-10",  rest:"2 min",  notes:"Retract scapula first" },
      { exercise:"Goblet Squat",              sets:3, reps:"12-15", rest:"90 sec", notes:"High elbows, upright torso" },
      { exercise:"Dumbbell Shoulder Press",   sets:3, reps:"10-12", rest:"90 sec", notes:"No arch in lower back" },
      { exercise:"Plank",                     sets:3, reps:"45 sec",rest:"30 sec", notes:"Hollow body, squeeze glutes" },
    ],
  };

  const exercises = TEMPLATES[focus].map(ex => ({
    ...ex,
    sets:  readiness < 50 ? Math.max(2, ex.sets - 1) : ex.sets,
    notes: readiness < 50 ? ex.notes + " (deload — reduce weight 20%)" : ex.notes,
  }));

  return {
    name:     `RVN ${focus.charAt(0).toUpperCase() + focus.slice(1)} Day`,
    focus, readiness, exercises,
    duration: focus === "cardio" ? "~30 min" : `~${exercises.length * 10} min`,
    basedOn:  archetypeId,
  };
}

async function composeBioPalResponse(text, state) {
  const intent = classifyIntent(text);
  const persona = RVN_VISION_PERSONAS[state.mode] || RVN_VISION_PERSONAS.personal;
  const manifest = matchManifest(text);
  const sv = state?.bioLogic || {};

  // ── STEP 1: Detect side-effects (pre-processing only — not used for response text) ──
  let appliedDelta = null;
  let workoutPlan  = null;
  let scheduleItems = null;

  if (intent === "workout_generate") {
    workoutPlan  = generateWorkoutPlan(text, state);
    appliedDelta = { kind: "workoutGenerated", plan: workoutPlan };
  } else if (intent === "food") {
    const log = extractMacroLog(text);
    if (log) appliedDelta = { kind: "bioLogicLog", entry: log };
  } else if (intent === "injury") {
    const patch = { soreness: Math.min(100, (sv.soreness || 0) + 25), mood: "cautious" };
    appliedDelta = { kind: "bioLogicUpdate", patch };
  } else if (intent === "goal") {
    appliedDelta = { kind: "navigate", screen: "target" };
  } else if (intent === "schedule") {
    scheduleItems = generateDaySchedule(text, state);
    appliedDelta  = { kind: "schedulePending", items: scheduleItems };
  }

  // ── STEP 2: Build rich system prompt from real user data ──────────────────────
  let profileCtx = "";
  try {
    const p = JSON.parse(localStorage.getItem("rvn_profile") || "{}");
    const mg = p.macroGoals || {};
    const mt = p.macroToday || {};
    const pr = p.prs || {};
    const avgSleep = Array.isArray(p.sleepDays) && p.sleepDays.length
      ? (p.sleepDays.reduce((a, b) => a + b, 0) / p.sleepDays.length).toFixed(1)
      : null;
    const parts = [];
    if (mg.protein)         parts.push(`Macro goals: ${mg.protein}g protein / ${mg.carbs}g carbs / ${mg.fats}g fat`);
    if (mt.protein != null) parts.push(`Today logged: ${mt.protein}g protein / ${mt.carbs}g carbs / ${mt.fats}g fat`);
    if (pr.bench)           parts.push(`PRs — bench: ${pr.bench}lb, squat: ${pr.squat}lb, deadlift: ${pr.deadlift}lb, OHP: ${pr.ohp}lb`);
    if (avgSleep)           parts.push(`Avg sleep: ${avgSleep}h`);
    if (p.sleepTarget)      parts.push(`Sleep target: ${p.sleepTarget}h`);
    if (p.calories)         parts.push(`TDEE: ~${p.calories} kcal`);
    profileCtx = parts.join(". ");
  } catch (_) {}

  const svContext = sv.readiness
    ? `Readiness: ${sv.readiness}%. Soreness: ${sv.soreness || 0}%.${sv.lastWorkout ? ` Last workout: ${sv.lastWorkout}.` : ""}`
    : "";

  // Time-of-day context so Kailu knows it's morning vs evening and what day it is
  const now = new Date();
  const hour = now.getHours();
  const dayName = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"][now.getDay()];
  const timeOfDay = hour < 5 ? "late night" : hour < 12 ? "morning" : hour < 17 ? "afternoon" : hour < 21 ? "evening" : "night";
  const timeCtx = `Current time: ${timeOfDay} (${String(hour).padStart(2,"0")}:${String(now.getMinutes()).padStart(2,"0")}), ${dayName}. Macros reset at midnight each day — if the user says they ate something, log it to today's macros.`;

  // Supplement grounding context — from the manifest DB, never hallucinate beyond this
  const suppCtx = manifest
    ? `Supplement info on file: ${manifest.brand} — ${manifest.mechanism}. Dose: ${manifest.typicalDose}. vs generic: ${manifest.vsGeneric}.${manifest.longTerm ? ` Long-term note: ${manifest.longTerm}` : ""} Only use these facts — do not add any that aren't listed here.`
    : "";

  // Side-effect context hints so Claude knows what action just ran
  const actionCtx = [
    workoutPlan   ? `You just generated a ${workoutPlan.focus} workout plan called "${workoutPlan.name}" (${workoutPlan.duration}). Write a short motivating intro — do NOT list the exercises.` : "",
    scheduleItems ? `You just generated a 24-hour schedule with ${scheduleItems.length} blocks. Briefly introduce it and let the user know they can lock it in.` : "",
    appliedDelta?.kind === "bioLogicLog"    ? "You just logged this food entry. Confirm it naturally and give one practical insight about timing or macros." : "",
    appliedDelta?.kind === "bioLogicUpdate" ? "You've flagged this injury and automatically reduced their load. Give brief, targeted recovery advice." : "",
    appliedDelta?.kind === "navigate"       ? "You are sending them to the Target Protocol screen to recalibrate their goal." : "",
  ].filter(Boolean).join(" ");

  const systemPrompt = [
    `You are Kailu — an elite performance AI built into RVN OS. Mode: ${state.mode}. ${persona.framing}`,
    "Keep every response under 3 sentences. Be direct, precise, data-driven. No bullet lists. No filler phrases like 'great question', 'absolutely', or 'your system looks primed'. Sound like a coach who actually knows this person.",
    "Always reference the user's real numbers when available. Never invent stats.",
    timeCtx,
    svContext,
    profileCtx,
    suppCtx,
    actionCtx,
  ].filter(Boolean).join(" ");

  // ── STEP 3: Build conversation history (last 6 turns) ─────────────────────────
  const history = (state.biopal?.messages || [])
    .filter(m => m.role === "user" || m.role === "pal")
    .slice(-6)
    .map(m => ({ role: m.role === "pal" ? "assistant" : "user", content: m.text }));

  // ── STEP 4: Always call Claude — no more scripted response branches ────────────
  try {
    const reply = await callClaudeAPI({ system: systemPrompt, history, user: text, maxTokens: 280 });
    if (reply) return { text: reply, intent, appliedDelta, workoutPlan, scheduleItems };
  } catch (_) { /* offline — fall through to local fallback */ }

  // ── STEP 5: Offline / API unavailable fallback ────────────────────────────────
  if (intent === "workout_generate" && workoutPlan) {
    const intro = sv.readiness < 50
      ? `Readiness at ${sv.readiness}% — volume scaled back. Here's your ${workoutPlan.focus} day:`
      : `Readiness at ${sv.readiness || 75}% — go time. Here's your ${workoutPlan.focus} day:`;
    return { text: intro, intent, appliedDelta, workoutPlan, scheduleItems };
  }
  if (manifest) {
    const gymLine = getGymSupplementLine(manifest.category, state);
    const line = [`${manifest.brand} — ${manifest.mechanism}`, `Dose: ${manifest.typicalDose}.`, manifest.longTerm ? `Long-term: ${manifest.longTerm}` : "", gymLine || ""].filter(Boolean).join(" ");
    return { text: line, intent, appliedDelta, workoutPlan, scheduleItems };
  }
  if (intent === "food" && appliedDelta?.entry) {
    const { amount, unit, kind } = appliedDelta.entry;
    return { text: `Logged ${amount}${unit} ${kind}. Keep the next meal 4 hours out so MPS resets cleanly.`, intent, appliedDelta, workoutPlan, scheduleItems };
  }
  if (intent === "injury") {
    const area = (text.match(/\b(knee|shoulder|back|hamstring|calf|wrist|elbow|hip|neck|chest|glute|quad|forearm)\b/i) || [])[1] || "soft tissue";
    return { text: `${area} flagged — load reduced for 48 hours. Magnesium bisglycinate tonight, skip any sharp-pain movements entirely.`, intent, appliedDelta, workoutPlan, scheduleItems };
  }
  if (intent === "goal") {
    return { text: "Goal registered. Opening Target Protocol — recalibrating your 12-week trajectory now.", intent, appliedDelta, workoutPlan, scheduleItems };
  }
  if (intent === "schedule" && scheduleItems) {
    return { text: "Here's your 24-hour plan. Lock it in and I'll nudge you at each block.", intent, appliedDelta, workoutPlan, scheduleItems };
  }
  return { text: generateOpenAdvice(text, state), intent, appliedDelta, workoutPlan, scheduleItems };
}

// ─── Claude API stub — pluggable. In a real deployment, wire this to a
// kiosk-side proxy that holds the API key (do NOT ship a key in the bundle).
async function callClaudeAPI({ system, user, history, maxTokens }) {
  if (typeof window === "undefined") return null;
  // Auto-detect endpoint: explicit override → Vercel /api/kailu → null (offline)
  const base = window.__RVN_BIOPAL_ENDPOINT__ || (window.location.hostname !== "localhost" ? "/api/kailu" : null);
  if (!base) return null;
  try {
    const res = await fetch(base, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        system,
        user,
        history: history || [],
        max_tokens: maxTokens || 280,
      }),
    });
    if (!res.ok) return null;
    const json = await res.json();
    return json?.text || json?.content?.[0]?.text || null;
  } catch { return null; }
}

// ─── RVN VISION OVERLAY UI ──────────────────────────────────────────────────────
function RVNVisionOverlay() {
  const env = useEnv();
  const { state, biopalToggle, biopalSend, biopalProcessing, bioLogicLog, bioLogicUpdate, goto, scheduleSetPending, scheduleLock } = env;
  const { theme, mode, biopal, bioLogic, screen } = state;
  // Only render on post-onboarding screens — not during splash/onboarding flow
  // Hide only on splash (loading) and manager PIN — show everywhere else
  if (screen === "splash" || screen === "manager") return null;
  const T = D[theme];
  const M = (typeof OS_MODES !== "undefined" && OS_MODES[mode]) ? OS_MODES[mode] : null;
  const ac = M ? T[M.accentKey] : T.blue;
  const persona = RVN_VISION_PERSONAS[mode] || RVN_VISION_PERSONAS.personal;

  const [draft, setDraft] = useState("");
  const scrollerRef = useRef(null);

  // Seed the greeting the first time RVN Vision opens in this session
  useEffect(() => {
    if (biopal.open && biopal.messages.length === 0) {
      biopalSend({ role: "pal", text: persona.greeting(state), intent: "greet" });
    }
  }, [biopal.open]); // eslint-disable-line

  // Auto-scroll on new message
  useEffect(() => {
    if (scrollerRef.current) {
      scrollerRef.current.scrollTop = scrollerRef.current.scrollHeight;
    }
  }, [biopal.messages.length, biopal.processing]);

  function handleLockSchedule(items) {
    if (!items || !items.length) return;
    scheduleLock && scheduleLock();
    biopalSend({
      role: "pal",
      text: "Locked in. The full 24-hour plan is now on your Dashboard — I'll nudge you at each block.",
      intent: "schedule",
      appliedDelta: { kind: "scheduleLocked", count: items.length },
    });
  }

  async function handleSend() {
    const text = draft.trim();
    if (!text || biopal.processing) return;
    setDraft("");
    biopalSend({ role: "user", text });

    // Shortcut: "lock it in" / "confirm" / "save the plan" commits any pending schedule
    if (/\block\s?(it\s)?in\b|\bconfirm\b|\bsave\s(it|that|the)\s(plan|schedule|day)\b/i.test(text)) {
      const pending = state.schedule?.pending;
      if (pending && pending.length) {
        handleLockSchedule(pending);
        return;
      }
    }

    biopalProcessing(true);
    try {
      const minDelay = 1100 + Math.random() * 700;
      const [reply] = await Promise.all([
        composeBioPalResponse(text, state),
        new Promise(r => setTimeout(r, minDelay)),
      ]);
      // Apply side-effects before delivering the line
      if (reply.appliedDelta) {
        const d = reply.appliedDelta;
        if (d.kind === "bioLogicLog"     && d.entry)  bioLogicLog(d.entry);
        if (d.kind === "bioLogicUpdate"  && d.patch)  bioLogicUpdate(d.patch);
        if (d.kind === "navigate"        && d.screen) setTimeout(() => goto(d.screen), 600);
        if (d.kind === "schedulePending" && d.items)  scheduleSetPending && scheduleSetPending(d.items);
      }
      biopalSend({
        role: "pal", text: reply.text, intent: reply.intent,
        appliedDelta: reply.appliedDelta || null,
        scheduleItems: reply.scheduleItems || null,
      });
    } catch (_) {
      biopalSend({ role: "pal", text: "Line dropped. Ask me again.", intent: "error" });
    } finally {
      biopalProcessing(false);
    }
  }

  const quickChips = (RVN_VISION_QUICK_CHIPS[mode] || RVN_VISION_QUICK_CHIPS.personal);

  return (
    <>
      {/* FAB — always on top, every screen */}
      <motion.button
        onClick={() => biopalToggle()}
        whileTap={{ scale: .92 }}
        style={{
          position: "fixed", right: 16, bottom: 20, zIndex: 1000,
          width: 54, height: 54, borderRadius: "50%",
          background: `radial-gradient(circle at 30% 30%, ${ac}, ${ac}aa 55%, ${ac}55 100%)`,
          border: `1.5px solid ${ac}88`, boxShadow: `0 8px 32px ${ac}66, inset 0 1px 0 #ffffff44`,
          color: "#fff", fontSize: 22, fontWeight: 900, cursor: "pointer",
          display: "flex", alignItems: "center", justifyContent: "center",
          backdropFilter: "blur(12px)",
        }}
        aria-label="Open RVN Vision">
        {biopal.open
          ? <span style={{ fontSize: 26, lineHeight: 1 }}>×</span>
          : <img src="data:image/png;base64," alt="RVN Vision"
                 style={{ width: 38, height: 38, objectFit: "contain",
                          filter: `drop-shadow(0 0 8px ${ac}88)` }}/>}
      </motion.button>

      <AnimatePresence>
        {biopal.open && (
          <motion.div
            initial={{ opacity: 0, y: 32, scale: .96 }}
            animate={{ opacity: 1, y: 0,  scale: 1  }}
            exit={{    opacity: 0, y: 32, scale: .96 }}
            transition={{ duration: .24, ease: [.22,1,.36,1] }}
            style={{
              position: "fixed", right: 12, left: 12, bottom: 84,
              maxWidth: 420, margin: "0 auto",
              zIndex: 999,
              background: theme === "dark"
                ? "linear-gradient(180deg, rgba(18,22,30,.94), rgba(10,12,18,.94))"
                : "linear-gradient(180deg, rgba(255,255,255,.94), rgba(245,247,252,.94))",
              border: `1px solid ${T.border}`,
              borderRadius: 20,
              boxShadow: `0 32px 80px rgba(0,0,0,.45), 0 0 0 1px ${ac}22`,
              backdropFilter: "blur(24px)",
              display: "flex", flexDirection: "column",
              maxHeight: "72vh",
              overflow: "hidden",
            }}>

            {/* Header */}
            <div style={{
              display: "flex", alignItems: "center", gap: 10,
              padding: "12px 14px",
              borderBottom: `1px solid ${T.border}`,
            }}>
              <div style={{
                width: 34, height: 34, borderRadius: "50%",
                background: `radial-gradient(circle at 30% 30%, ${ac}22, transparent 70%)`,
                border: `1px solid ${ac}66`,
                display: "flex", alignItems: "center", justifyContent: "center",
                overflow: "hidden",
              }}>
                <img src="data:image/png;base64," alt="RVN Vision"
                     style={{ width: 26, height: 26, objectFit: "contain" }}/>
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12, fontWeight: 800, color: T.text, letterSpacing: "-.01em" }}>
                  {persona.title}
                </div>
                <div style={{ fontSize: 9, fontWeight: 700, color: T.faint, letterSpacing: ".12em" }}>
                  READINESS {bioLogic.readiness} · {M ? M.label : "PERSONAL MODE"}
                </div>
              </div>
              <button onClick={() => biopalToggle(false)}
                style={{
                  background: "none", border: "none", color: T.faint,
                  cursor: "pointer", fontSize: 20, padding: "0 6px",
                }}>×</button>
            </div>

            {/* Transcript */}
            <div ref={scrollerRef} style={{
              flex: 1, overflowY: "auto", padding: "14px",
              display: "flex", flexDirection: "column", gap: 10,
              minHeight: 180,
            }}>
              {biopal.messages.map((m, i) => (
                <RVNVisionBubble key={i} m={m} ac={ac} T={T} theme={theme} onLock={handleLockSchedule}/>
              ))}
              {biopal.processing && (
                <div style={{ display: "flex", justifyContent: "flex-start" }}>
                  <div style={{
                    padding: "10px 14px",
                    background: theme === "dark" ? "rgba(255,255,255,.04)" : "rgba(0,0,0,.04)",
                    border: `1px solid ${T.border}`,
                    borderRadius: 14, borderBottomLeftRadius: 4,
                    display: "flex", alignItems: "center", gap: 5,
                  }}>
                    <img src="data:image/png;base64," alt=""
                         style={{ width: 11, height: 11, objectFit: "contain", marginRight: 3 }}/>
                    {[0,1,2].map(i => (
                      <motion.span key={i}
                        animate={{ y: [0, -5, 0] }}
                        transition={{ duration: .6, delay: i * .18, repeat: Infinity, ease: "easeInOut" }}
                        style={{
                          display: "inline-block",
                          width: 7, height: 7, borderRadius: "50%",
                          background: ac, opacity: .75,
                        }}/>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Quick chips */}
            {biopal.messages.length < 3 && (
              <div style={{
                display: "flex", gap: 6, padding: "0 14px 10px",
                flexWrap: "wrap",
              }}>
                {quickChips.map((q) => (
                  <button key={q} onClick={() => setDraft(q)}
                    style={{
                      background: T.glass, border: `1px solid ${T.border}`,
                      borderRadius: 14, padding: "5px 10px",
                      fontSize: 10.5, color: T.muted, cursor: "pointer",
                      letterSpacing: ".02em",
                    }}>{q}</button>
                ))}
              </div>
            )}

            {/* Composer */}
            <div style={{
              display: "flex", gap: 8, padding: "10px 12px",
              borderTop: `1px solid ${T.border}`,
              background: theme === "dark" ? "rgba(0,0,0,.25)" : "rgba(255,255,255,.5)",
            }}>
              <input
                value={draft}
                onChange={(e) => setDraft(e.target.value)}
                onKeyDown={(e) => { if (e.key === "Enter") handleSend(); }}
                placeholder="Ask anything — food, injury, stack, goal…"
                style={{
                  flex: 1, background: T.glass, border: `1px solid ${T.border}`,
                  borderRadius: 12, padding: "10px 12px",
                  fontSize: 13, color: T.text, outline: "none",
                }}/>
              <motion.button
                whileTap={{ scale: .94 }}
                onClick={handleSend}
                disabled={!draft.trim() || biopal.processing}
                style={{
                  background: draft.trim() ? ac : T.glass,
                  border: `1px solid ${draft.trim() ? ac : T.border}`,
                  borderRadius: 12, padding: "0 14px",
                  color: draft.trim() ? "#fff" : T.faint, fontWeight: 800,
                  fontSize: 12, letterSpacing: ".06em", cursor: "pointer",
                }}>SEND</motion.button>
            </div>

          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

const RVN_VISION_QUICK_CHIPS = {
  personal: ["Build me a full body workout", "Plan my day — 9-5 + lift + study", "I just had 40g chicken", "What should I take at night?"],
  gym:      ["Build me a lower body workout", "Generate an upper body program", "I felt my hamstring tweak", "Pre-workout stack"],
  store:    ["Why Thorne creatine?", "Best magnesium for sleep?", "Explain NMN", "Recovery stack under $100"],
  smoothie: ["Pre-workout blend", "Post-lift recovery shake", "Low-sugar energy blend", "Something for focus"],
};

function RVNVisionBubble({ m, ac, T, theme, onLock }) {
  const isUser = m.role === "user";
  return (
    <div style={{
      display: "flex", justifyContent: isUser ? "flex-end" : "flex-start",
    }}>
      <div style={{
        maxWidth: "92%",
        padding: "9px 12px",
        background: isUser ? `${ac}22` : (theme === "dark" ? "rgba(255,255,255,.04)" : "rgba(0,0,0,.04)"),
        border: `1px solid ${isUser ? ac + "55" : T.border}`,
        borderRadius: 14,
        borderBottomRightRadius: isUser ? 4 : 14,
        borderBottomLeftRadius:  isUser ? 14 : 4,
        color: T.text,
        fontSize: 13, lineHeight: 1.55,
        whiteSpace: "pre-wrap",
      }}>
        {!isUser && (
          <div style={{
            fontSize: 8.5, fontWeight: 800, color: ac,
            letterSpacing: ".14em", marginBottom: 3,
            display: "flex", alignItems: "center", gap: 5,
          }}>
            <img src="data:image/png;base64," alt="" style={{ width: 11, height: 11, objectFit: "contain" }}/>
            RVN VISION{m.intent && m.intent !== "chat" ? ` · ${m.intent.toUpperCase()}` : ""}
          </div>
        )}
        {m.text}
        {m.scheduleItems && m.scheduleItems.length > 0 && (
          <div style={{
            marginTop: 10, borderTop: `1px solid ${T.border}`, paddingTop: 8,
            display: "flex", flexDirection: "column", gap: 4,
          }}>
            {m.scheduleItems.map((it, i) => (
              <div key={i} style={{
                display: "flex", alignItems: "flex-start", gap: 8,
                fontSize: 11.5, lineHeight: 1.45,
              }}>
                <div style={{
                  minWidth: 44, fontFamily: "monospace", fontWeight: 700,
                  color: ac, letterSpacing: ".04em",
                }}>{it.time}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ color: T.text, fontWeight: 600 }}>{it.title}</div>
                  {it.note && <div style={{ color: T.faint, fontSize: 10.5, marginTop: 1 }}>{it.note}</div>}
                </div>
              </div>
            ))}
            {onLock && (
              <button
                onClick={() => onLock(m.scheduleItems)}
                style={{
                  marginTop: 8, padding: "7px 12px", borderRadius: 8,
                  background: ac, color: "#000", border: "none",
                  fontSize: 10.5, fontWeight: 900, letterSpacing: ".14em",
                  textTransform: "uppercase", cursor: "pointer",
                }}>
                LOCK IT IN → DASHBOARD
              </button>
            )}
          </div>
        )}
        {m.workoutPlan && (
          <WorkoutPlanCard plan={m.workoutPlan} ac={ac} T={T} theme={theme}/>
        )}
        {m.appliedDelta && m.appliedDelta.kind !== "schedulePending" && (
          <div style={{
            marginTop: 6, fontSize: 10, color: T.faint,
            letterSpacing: ".08em", textTransform: "uppercase",
          }}>
            → {deltaLabel(m.appliedDelta)}
          </div>
        )}
      </div>
    </div>
  );
}

function WorkoutPlanCard({ plan, ac, T, theme }) {
  const [added, setAdded] = useState(false);
  const handleAdd = () => {
    setAdded(true);
    if (typeof window !== "undefined")
      window.dispatchEvent(new CustomEvent("rvn:add-workout", { detail: plan }));
  };
  return (
    <div style={{ marginTop:10, background: theme==="dark"?"rgba(255,255,255,.03)":"rgba(0,0,0,.03)", border:`1px solid ${T.border}`, borderRadius:12, padding:12 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
        <div>
          <div style={{ fontSize:12, fontWeight:800, color:ac, letterSpacing:".1em" }}>{plan.name.toUpperCase()}</div>
          <div style={{ fontSize:10, color:T.faint }}>{plan.duration} · Readiness {plan.readiness}%</div>
        </div>
        <motion.button whileTap={{ scale:.94 }} onClick={handleAdd} disabled={added}
          style={{ padding:"6px 12px", background:added?T.glass:ac, color:added?T.faint:"#000", border:`1px solid ${added?T.border:ac}`, borderRadius:8, fontSize:10, fontWeight:800, cursor:added?"default":"pointer" }}>
          {added ? "✓ ADDED" : "+ PROTOCOL"}
        </motion.button>
      </div>
      {plan.exercises.map((ex,i) => (
        <div key={i} style={{ display:"flex", gap:10, alignItems:"flex-start", padding:"6px 0", borderTop:i>0?`1px solid ${T.border}`:"none" }}>
          <div style={{ minWidth:18, fontSize:10, color:T.faint, paddingTop:1 }}>{i+1}</div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:12, fontWeight:700, color:T.text }}>{ex.exercise}</div>
            <div style={{ fontSize:10.5, color:T.muted, marginTop:2 }}>{ex.sets} sets × {ex.reps} · Rest {ex.rest}</div>
            {ex.notes && <div style={{ fontSize:10, color:T.faint, marginTop:1, fontStyle:"italic" }}>{ex.notes}</div>}
          </div>
        </div>
      ))}
    </div>
  );
}


function deltaLabel(d) {
  if (!d) return "";
  if (d.kind === "bioLogicLog"    && d.entry)  return `LOGGED ${d.entry.amount}${d.entry.unit} ${d.entry.kind}`;
  if (d.kind === "bioLogicUpdate" && d.patch)  return `RECOVERY UI UPDATED`;
  if (d.kind === "navigate"       && d.screen) return `OPENING ${d.screen.toUpperCase()}`;
  if (d.kind === "scheduleLocked")               return `SCHEDULE LOCKED · ${d.count} BLOCKS`;
  if (d.kind === "workoutGenerated")             return `WORKOUT READY — TAP + PROTOCOL TO SAVE`;
  return "";
}


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║  RVN OS — GHOST BAR · VBT TELEMETRY HUD                                  ║
// ║  F1-inspired live physics readout for barbell lifts.                     ║
// ║                                                                          ║
// ║  No 3D body. True Black canvas, cobalt bar path, red-on-deviation.       ║
// ║  MediaPipe Pose via CDN; falls back to a demo driver if it can't load.   ║
// ║                                                                          ║
// ║  Tracks:                                                                 ║
// ║    • Right-wrist Y → bar path (proxy for barbell position)               ║
// ║    • Concentric mean + peak velocity (m/s)                               ║
// ║    • Real-time power output (W) = force × velocity, F = m × (g + a)      ║
// ║    • Bar path horizontal deviation from set start (forward drift)        ║
// ║    • Knee-cave angle: hip→knee→ankle (valgus flag under ~165°)           ║
// ║    • Rep counter — phase machine on smoothed Y-velocity                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// Landmark indices (BlazePose 33-keypoint schema)
const LM = {
  L_SHOULDER: 11, R_SHOULDER: 12,
  L_WRIST: 15,    R_WRIST: 16,
  L_HIP: 23,      R_HIP: 24,
  L_KNEE: 25,     R_KNEE: 26,
  L_ANKLE: 27,    R_ANKLE: 28,
};

const MEDIAPIPE_VERSION = "0.5.1675469404";
const MEDIAPIPE_BASE = `https://cdn.jsdelivr.net/npm/@mediapipe/pose@${MEDIAPIPE_VERSION}`;

// Gravity, for power calc (m/s^2)
const G = 9.80665;

// Rep-detection thresholds (world-space-ish fraction of shoulder→hip reference)
const VELOCITY_THRESHOLD = 0.08; // m/s — above this, considered "moving"
const DEVIATION_WARN     = 0.05; // m — bar drift forward from set start
const DEVIATION_ALARM    = 0.12; // m — hard foul; bar path turns red
const KNEE_ANGLE_WARN    = 172; // degrees — above this we're straight; below, bending
const KNEE_CAVE_FLAG     = 158; // degrees — valgus collapse angle

// ─── Math helpers ────────────────────────────────────────────────────────────
function angleBetween(a, b, c) {
  // Interior angle at b (a-b-c), in degrees. 2D projection.
  const v1x = a.x - b.x, v1y = a.y - b.y;
  const v2x = c.x - b.x, v2y = c.y - b.y;
  const dot = v1x * v2x + v1y * v2y;
  const m1 = Math.hypot(v1x, v1y);
  const m2 = Math.hypot(v2x, v2y);
  if (m1 === 0 || m2 === 0) return 180;
  const cosA = Math.max(-1, Math.min(1, dot / (m1 * m2)));
  return (Math.acos(cosA) * 180) / Math.PI;
}

function midpoint(a, b) {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
}

// ─── Ghost Bar component ─────────────────────────────────────────────────────
function GhostBarHUD({ onBack, theme = "dark" }) {
  const [localTheme, setLocalTheme] = useState(theme);
  const T = D[localTheme] || D["dark"];
  const ac = T.blue;

  const videoRef  = useRef(null);
  const canvasRef = useRef(null);
  const rafRef    = useRef(null);
  const poseRef   = useRef(null);
  const streamRef = useRef(null);

  // Rolling state for the physics engine — kept in a ref so we don't rerender per-frame.
  const engineRef = useRef({
    startedAt: null,
    lastSampleT: null,
    lastWristY: null,
    lastWristX: null,
    startX: null,       // set-start x (mid-foot reference proxy)
    bodyScalePxPerM: null, // px→meters from shoulder→hip baseline
    phase: "idle",       // "idle" | "descent" | "bottom" | "ascent" | "lockout"
    concentricSamples: [], // [{v, t}]  — accumulated over current concentric
    repPeakV: 0,
    trail: [],           // [{x, y, t, warn, alarm}] for the bar-path ribbon
    reps: [],            // completed reps { meanV, peakV, power, ts }
  });

  // UI state
  const [weightInput, setWeightInput] = useState("225");
  const [unit, setUnit] = useState("lb");
  const [status, setStatus] = useState("INITIALIZING");
  const [armed, setArmed]   = useState(false);   // ready to capture set
  const [cameraReady, setCameraReady] = useState(false);
  const [cameraBlocked, setCameraBlocked] = useState(false);
  const [metrics, setMetrics] = useState({
    meanV: 0, peakV: 0, power: 0,
    reps: 0,
    barPathDeviation: 0,
    barPathState: "clean",        // "clean" | "warn" | "alarm"
    kneeAngle: 180,
    kneeCave: false,
    fps: 0,
  });

  // Derived: weight in kg (for power calc)
  const massKg = useMemo(() => {
    const v = parseFloat(weightInput) || 0;
    return unit === "kg" ? v : v * 0.453592;
  }, [weightInput, unit]);

  // ── Camera + MediaPipe setup ──────────────────────────────────────────────
  useEffect(() => {
    let cancelled = false;

    async function injectScript(src) {
      if (document.querySelector(`script[data-rvn-pose="${src}"]`)) return;
      await new Promise((resolve, reject) => {
        const s = document.createElement("script");
        s.src = src;
        s.crossOrigin = "anonymous";
        s.dataset.rvnPose = src;
        s.onload = () => resolve();
        s.onerror = () => reject(new Error("script load failed: " + src));
        document.head.appendChild(s);
      });
    }

    async function waitFor(predicate, timeout = 8000, interval = 50) {
      const start = Date.now();
      while (!predicate()) {
        if (Date.now() - start > timeout) throw new Error("timeout");
        await new Promise((r) => setTimeout(r, interval));
      }
    }

    async function setup() {
      try {
        setStatus("LOADING MODEL");
        await injectScript(`${MEDIAPIPE_BASE}/pose.js`);
        await waitFor(() => typeof window.Pose !== "undefined");
        if (cancelled) return;

        const pose = new window.Pose({
          locateFile: (file) => `${MEDIAPIPE_BASE}/${file}`,
        });
        pose.setOptions({
          modelComplexity: 1,
          smoothLandmarks: true,
          enableSegmentation: false,
          minDetectionConfidence: 0.55,
          minTrackingConfidence: 0.55,
        });
        pose.onResults(handleResults);
        poseRef.current = pose;

        setStatus("TAP TO ENABLE CAMERA");
        // On mobile, camera must be triggered by a user gesture.
        // We set a flag so the UI shows a "Start Camera" button.
        setCameraBlocked(false);
        // Try auto-start — works on desktop + Android Chrome.
        // iOS Safari requires the button tap path below.
        try {
          await startCamera(cancelled, loop);
        } catch(camErr) {
          console.warn("[GhostBar] camera auto-start failed:", camErr);
          // Show tap-to-start UI rather than dropping to demo
          setCameraBlocked(true);
          setStatus("TAP · ENABLE CAMERA");
        }
      } catch (e) {
        console.warn("[GhostBar] setup failed, falling back to demo driver:", e);
        setStatus("DEMO MODE");
        startDemoDriver();
      }

      async function startCamera(cancelled, loop) {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: { ideal: "environment" },
            width:  { ideal: 1280 },
            height: { ideal: 720 },
            frameRate: { ideal: 30, max: 60 },
          },
          audio: false,
        });
        if (cancelled) { stream.getTracks().forEach(t => t.stop()); return; }
        streamRef.current = stream;
        const video = videoRef.current;
        if (!video) return;
        video.srcObject = stream;
        video.playsInline = true;
        video.muted = true;
        await video.play();
        setCameraReady(true);
        setCameraBlocked(false);
        setStatus("TELEMETRY LIVE");
        loop();
      }
    }

    let lastFrameT = performance.now();
    let fpsEma = 0;
    async function loop() {
      if (cancelled) return;
      const video = videoRef.current;
      if (video && poseRef.current && video.readyState >= 2) {
        try {
          await poseRef.current.send({ image: video });
          const now = performance.now();
          const dt = (now - lastFrameT) / 1000;
          lastFrameT = now;
          const fps = 1 / Math.max(dt, 0.001);
          fpsEma = fpsEma ? fpsEma * 0.9 + fps * 0.1 : fps;
          setMetrics((m) => (Math.abs(m.fps - fpsEma) > 1 ? { ...m, fps: Math.round(fpsEma) } : m));
        } catch (_) { /* swallow frame errors */ }
      }
      rafRef.current = requestAnimationFrame(loop);
    }

    setup();
    return () => {
      cancelled = true;
      cancelAnimationFrame(rafRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop());
      if (poseRef.current)   try { poseRef.current.close(); } catch (_) {}
    };
    // eslint-disable-next-line
  }, []);

  // ── Demo driver (when camera/model unavailable) ───────────────────────────
  function startDemoDriver() {
    let t0 = performance.now();
    const tick = () => {
      const t = (performance.now() - t0) / 1000;
      // Simulate a squat: 3s descent, 0.5s pause, 2s ascent, 1s reset. Loop.
      const phaseT = t % 6.5;
      let y;
      if (phaseT < 3)      y = 0.3 + 0.35 * (phaseT / 3);              // descend
      else if (phaseT < 3.5) y = 0.65;                                   // pause
      else if (phaseT < 5.5) y = 0.65 - 0.35 * ((phaseT - 3.5) / 2);     // ascend
      else                   y = 0.3;                                    // locked out
      // light lateral drift for flavor
      const x = 0.5 + Math.sin(t * 0.8) * 0.01 + (phaseT > 4 ? (phaseT - 4) * 0.008 : 0);
      const kneeAngle = phaseT < 3 ? 180 - (phaseT / 3) * 90 : phaseT < 3.5 ? 90 : phaseT < 5.5 ? 90 + ((phaseT - 3.5) / 2) * 90 : 180;
      simulateFrame({ x, y, kneeAngle });
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
  }

  function simulateFrame({ x, y, kneeAngle }) {
    const eng = engineRef.current;
    const now = performance.now();
    if (!eng.startedAt) eng.startedAt = now;
    if (!eng.bodyScalePxPerM) eng.bodyScalePxPerM = 1; // normalized units
    if (eng.startX === null) eng.startX = x;
    processSample({ x, y, kneeAngle, now, normalized: true });
    drawOverlay(null); // no video — pure HUD
  }

  // ── Pose results → physics engine ─────────────────────────────────────────
  function handleResults(results) {
    const canvas = canvasRef.current;
    const video = videoRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    // Resize canvas to match video
    if (video && video.videoWidth && (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight)) {
      canvas.width  = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    ctx.save();
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    // Dim the raw video so the HUD pops (True-Black pitch aesthetic).
    ctx.globalAlpha = 0.55;
    ctx.filter = "saturate(0.5) contrast(1.05)";
    if (video) ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.filter = "none";
    ctx.globalAlpha = 1;
    ctx.fillStyle = "rgba(0,0,0,0.45)";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.restore();

    const landmarks = results?.poseLandmarks;
    if (!landmarks) {
      drawOverlay(results);
      return;
    }

    const eng = engineRef.current;
    const now = performance.now();
    if (!eng.startedAt) eng.startedAt = now;

    // Body scale: normalized [0..1] coords * imageHeight for a meter reference.
    // Shoulder→hip distance ≈ 0.5 m typical adult.
    const lSh = landmarks[LM.L_SHOULDER], rSh = landmarks[LM.R_SHOULDER];
    const lHp = landmarks[LM.L_HIP],      rHp = landmarks[LM.R_HIP];
    if (lSh && rSh && lHp && rHp) {
      const sh = midpoint(lSh, rSh);
      const hp = midpoint(lHp, rHp);
      const dyNorm = Math.abs(sh.y - hp.y);
      if (dyNorm > 0.05) {
        // 0.5 m over dyNorm of the frame → 1/(2*dyNorm) meters per normalized unit
        eng.bodyScalePxPerM = 1 / (2 * dyNorm); // meters per normalized y unit
      }
    }

    // Bar proxy = right wrist (swap to left for southpaw demos)
    const rW = landmarks[LM.R_WRIST];
    if (!rW) {
      drawOverlay(results);
      return;
    }

    // Knee cave — right leg
    const rH = landmarks[LM.R_HIP], rK = landmarks[LM.R_KNEE], rA = landmarks[LM.R_ANKLE];
    let kneeAngle = 180;
    if (rH && rK && rA) kneeAngle = angleBetween(rH, rK, rA);

    if (eng.startX === null) eng.startX = rW.x;

    processSample({ x: rW.x, y: rW.y, kneeAngle, now, normalized: true });
    drawOverlay(results);
  }

  // ── Core engine step — called with normalized [0..1] coords ───────────────
  function processSample({ x, y, kneeAngle, now, normalized }) {
    const eng = engineRef.current;
    const pxPerM = eng.bodyScalePxPerM || 1;

    // Y-velocity in meters per second. Positive v = bar rising (screen Y decreasing).
    let v = 0;
    if (eng.lastSampleT !== null && eng.lastWristY !== null) {
      const dt = (now - eng.lastSampleT) / 1000;
      if (dt > 0.0001) {
        const dyNorm = eng.lastWristY - y; // screen y inverted → up is positive
        const dyMeters = normalized ? dyNorm * pxPerM : dyNorm;
        v = dyMeters / dt;
      }
    }
    eng.lastSampleT = now;
    eng.lastWristY  = y;
    eng.lastWristX  = x;

    // Bar path deviation (meters), from set start
    const devNorm = Math.abs(x - eng.startX);
    const devMeters = devNorm * pxPerM;

    // Phase machine on velocity (with deadband)
    const was = eng.phase;
    if (v < -VELOCITY_THRESHOLD) {
      eng.phase = "descent";
    } else if (v > VELOCITY_THRESHOLD) {
      if (was === "descent" || was === "bottom" || was === "idle") eng.phase = "ascent";
    } else {
      if (was === "descent") eng.phase = "bottom";
      else if (was === "ascent") eng.phase = "lockout";
    }

    // Accumulate concentric (ascent) samples for mean/peak
    if (eng.phase === "ascent") {
      eng.concentricSamples.push({ v, t: now });
      if (v > eng.repPeakV) eng.repPeakV = v;
    }

    // Complete rep on ascent→lockout transition
    if (was === "ascent" && eng.phase === "lockout" && eng.concentricSamples.length > 2) {
      const meanV = eng.concentricSamples.reduce((s, r) => s + r.v, 0) / eng.concentricSamples.length;
      const peakV = eng.repPeakV;
      // Power = F × v_mean. F = m × (g + a). Approximate a = peakV / ascent duration.
      const dur = (eng.concentricSamples[eng.concentricSamples.length - 1].t - eng.concentricSamples[0].t) / 1000;
      const a = dur > 0.05 ? peakV / dur : 0;
      const power = Math.max(0, massKg * (G + a) * meanV);
      eng.reps.push({ meanV, peakV, power, ts: now });
      eng.concentricSamples = [];
      eng.repPeakV = 0;
      // Re-anchor start X for the next rep so drift measures per-rep
      eng.startX = x;
    }

    // Push a trail point
    let state = "clean";
    if (devMeters >= DEVIATION_ALARM) state = "alarm";
    else if (devMeters >= DEVIATION_WARN) state = "warn";

    const kneeCave = kneeAngle < KNEE_CAVE_FLAG && kneeAngle > 20; // ignore garbage
    eng.trail.push({ x, y, t: now, state });
    // Cap trail length so we don't leak memory (last ~6s @ 30fps)
    if (eng.trail.length > 200) eng.trail.splice(0, eng.trail.length - 200);

    // Push metrics every ~120ms to avoid rerender storms
    if (!processSample._lastFlush || now - processSample._lastFlush > 120) {
      processSample._lastFlush = now;
      const last = eng.reps[eng.reps.length - 1];
      setMetrics((m) => ({
        ...m,
        meanV: last ? last.meanV : 0,
        peakV: last ? last.peakV : 0,
        power: last ? last.power : 0,
        reps: eng.reps.length,
        barPathDeviation: devMeters,
        barPathState: state,
        kneeAngle,
        kneeCave,
      }));
    }
  }

  // ── HUD overlay draw (canvas) ─────────────────────────────────────────────
  function drawOverlay(results) {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    // Match canvas resolution to its actual displayed size
    const rect = canvas.getBoundingClientRect();
    const W = rect.width  || canvas.parentElement?.clientWidth  || 960;
    const H = rect.height || canvas.parentElement?.clientHeight || 540;
    if (canvas.width !== W || canvas.height !== H) { canvas.width = W; canvas.height = H; }

    const eng = engineRef.current;

    // If no video was drawn (demo mode), paint theme background.
    if (!results || !videoRef.current?.videoWidth) {
      ctx.fillStyle = T.bg || "#000";
      ctx.fillRect(0, 0, W, H);
    }

    // ── Grid backdrop (F1 telemetry) ────────────────────────────────────────
    ctx.save();
    ctx.strokeStyle = "rgba(255,255,255,0.04)";
    ctx.lineWidth = 1;
    const step = 48;
    for (let x = 0; x < W; x += step) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y < H; y += step) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }
    ctx.restore();

    // ── Vertical set-start reference line (mid-foot proxy) ──────────────────
    if (eng.startX !== null) {
      const sx = eng.startX * W;
      ctx.save();
      ctx.setLineDash([6, 8]);
      ctx.strokeStyle = "rgba(255,255,255,0.22)";
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(sx, 0); ctx.lineTo(sx, H);
      ctx.stroke();
      ctx.restore();
    }

    // ── Bar path ribbon ─────────────────────────────────────────────────────
    if (eng.trail.length > 1) {
      ctx.save();
      ctx.lineCap = "round";
      ctx.lineJoin = "round";
      // Draw in segments so we can color-switch on deviation states
      for (let i = 1; i < eng.trail.length; i++) {
        const p0 = eng.trail[i - 1], p1 = eng.trail[i];
        const stroke =
          p1.state === "alarm" ? "rgba(255, 69, 58, 0.95)" :
          p1.state === "warn"  ? "rgba(255, 159, 10, 0.85)" :
                                  "rgba(10, 132, 255, 0.95)";
        ctx.strokeStyle = stroke;
        ctx.shadowColor = stroke;
        ctx.shadowBlur = 14;
        ctx.lineWidth = 3.5;
        ctx.beginPath();
        ctx.moveTo(p0.x * W, p0.y * H);
        ctx.lineTo(p1.x * W, p1.y * H);
        ctx.stroke();
      }
      // Head dot
      const head = eng.trail[eng.trail.length - 1];
      const hx = head.x * W, hy = head.y * H;
      const headColor =
        head.state === "alarm" ? "#FF453A" :
        head.state === "warn"  ? "#FF9F0A" : "#0A84FF";
      ctx.shadowColor = headColor;
      ctx.shadowBlur = 26;
      ctx.fillStyle = headColor;
      ctx.beginPath(); ctx.arc(hx, hy, 7, 0, Math.PI * 2); ctx.fill();
      ctx.restore();
    }

    // ── Pose skeleton (subtle) ──────────────────────────────────────────────
    const lms = results?.poseLandmarks;
    if (lms) {
      ctx.save();
      ctx.strokeStyle = "rgba(255,255,255,0.18)";
      ctx.lineWidth = 1.5;
      const chains = [
        [LM.L_SHOULDER, LM.L_HIP], [LM.R_SHOULDER, LM.R_HIP],
        [LM.L_SHOULDER, LM.R_SHOULDER], [LM.L_HIP, LM.R_HIP],
        [LM.L_HIP, LM.L_KNEE], [LM.L_KNEE, LM.L_ANKLE],
        [LM.R_HIP, LM.R_KNEE], [LM.R_KNEE, LM.R_ANKLE],
      ];
      for (const [a, b] of chains) {
        const pa = lms[a], pb = lms[b];
        if (!pa || !pb) continue;
        ctx.beginPath();
        ctx.moveTo(pa.x * W, pa.y * H);
        ctx.lineTo(pb.x * W, pb.y * H);
        ctx.stroke();
      }
      // Knee joints — tinted on cave
      const rK = lms[LM.R_KNEE];
      if (rK) {
        const cave = metrics.kneeCave;
        ctx.fillStyle = cave ? "#FF453A" : "rgba(255,255,255,0.6)";
        ctx.shadowBlur = cave ? 18 : 0;
        ctx.shadowColor = cave ? "#FF453A" : "transparent";
        ctx.beginPath(); ctx.arc(rK.x * W, rK.y * H, 5, 0, Math.PI * 2); ctx.fill();
      }
      ctx.restore();
    }
  }

  // Redraw whenever phase/trail changes even without video (demo mode path)
  useEffect(() => {
    if (!videoRef.current?.videoWidth) drawOverlay(null);
    // eslint-disable-next-line
  }, [metrics.barPathState, metrics.reps]);

  // Formatted readouts
  const v = metrics.meanV;
  const pv = metrics.peakV;
  const wClass =
    v >= 1.0 ? "STRENGTH-SPEED" :
    v >= 0.75 ? "SPEED-STRENGTH" :
    v >= 0.5 ? "ACCELERATIVE" :
    v >= 0.3 ? "ABSOLUTE STR." :
               v > 0 ? "MAX STRENGTH" : "—";

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div style={{
      position: "fixed", inset: 0, background: T.bg, color: T.text,
      display: "flex", flexDirection: "column", overflow: "hidden",
      fontFamily: "-apple-system, BlinkMacSystemFont, 'SF Pro Display', Inter, system-ui, sans-serif",
    }}>
      {/* Top bar — compact, two rows so status never squishes EXIT */}
      <div style={{
        position: "relative", zIndex: 10,
        background: T.card, borderBottom: `1px solid ${T.border}`,
      }}>
        {/* Row 1: EXIT + controls */}
        <div style={{
          display: "flex", justifyContent: "space-between", alignItems: "center",
          padding: "10px 16px 6px",
        }}>
          <button onClick={onBack} style={{
            padding: "7px 14px", borderRadius: 10,
            border: `1px solid ${T.border}`, background: "transparent",
            color: T.faint, fontSize: 10, letterSpacing: ".22em", fontWeight: 800,
            cursor: "pointer", flexShrink: 0,
          }}>← EXIT</button>

          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ fontSize: 9, letterSpacing: ".2em", color: T.faint, fontWeight: 700 }}>
              {metrics.fps} FPS
            </div>
            <button
              onClick={() => setLocalTheme(t => t === "dark" ? "light" : "dark")}
              style={{
                padding: "5px 10px", borderRadius: 8,
                border: `1px solid ${T.border}`, background: "transparent",
                color: T.text, fontSize: 14, cursor: "pointer",
              }}
            >{localTheme === "dark" ? "☀️" : "🌙"}</button>
          </div>
        </div>
        {/* Row 2: status line */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
          padding: "0 16px 8px",
        }}>
          <div style={{ width: 6, height: 6, borderRadius: "50%", flexShrink: 0,
            background: status.startsWith("TELEMETRY") ? "#30D158" : ac,
            boxShadow: `0 0 8px ${status.startsWith("TELEMETRY") ? "#30D158" : ac}`,
          }}/>
          <div style={{
            fontSize: 9, letterSpacing: ".24em", fontWeight: 800, color: ac,
            overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", maxWidth: "85vw",
          }}>
            GHOST BAR · {status.startsWith("DEMO") ? "DEMO MODE · POINT CAMERA TO START" : status}
          </div>
        </div>
      </div>

      {/* ── CAMERA — full width, main focus ── */}
      <div style={{ flex: 1, position: "relative", background: T.bg, overflow: "hidden", minHeight: 0 }}>
        <video ref={videoRef} playsInline muted autoPlay style={{ display: "none" }}/>
        <canvas ref={canvasRef} style={{
          position: "absolute", inset: 0, width: "100%", height: "100%",
        }}/>

        {/* Tap-to-start camera overlay — shown on iOS before permission granted */}
        {cameraBlocked && (
          <div style={{
            position:"absolute", inset:0, zIndex:8,
            display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center",
            background:"rgba(0,0,0,0.82)", backdropFilter:"blur(12px)",
          }}>
            <div style={{ fontSize:48, marginBottom:16 }}>📷</div>
            <div style={{ fontSize:16, fontWeight:900, color:"#fff", marginBottom:8, letterSpacing:".04em" }}>
              Camera Access Required
            </div>
            <div style={{ fontSize:12, color:"rgba(255,255,255,0.55)", marginBottom:28, textAlign:"center", maxWidth:260, lineHeight:1.5 }}>
              Ghost Bar needs your camera to track bar velocity and form in real time.
            </div>
            <button
              onClick={async () => {
                setCameraBlocked(false);
                setStatus("REQUESTING CAMERA");
                try {
                  const stream = await navigator.mediaDevices.getUserMedia({
                    video: { facingMode:{ ideal:"environment" }, width:{ ideal:1280 }, height:{ ideal:720 }, frameRate:{ ideal:30 } },
                    audio: false,
                  });
                  streamRef.current = stream;
                  const video = videoRef.current;
                  if (!video) return;
                  video.srcObject = stream;
                  video.playsInline = true;
                  video.muted = true;
                  await video.play();
                  setCameraReady(true);
                  setStatus("TELEMETRY LIVE");
                } catch(e) {
                  setStatus("CAMERA DENIED · DEMO MODE");
                  startDemoDriver();
                }
              }}
              style={{
                padding:"14px 32px", borderRadius:14, background:ac,
                border:"none", color:"#fff", fontSize:14, fontWeight:900,
                letterSpacing:".06em", cursor:"pointer",
                boxShadow:`0 0 24px ${ac}66`,
              }}>
              ENABLE CAMERA
            </button>
          </div>
        )}

        {/* Velocity class — top-left corner, always readable pill */}
        <div style={{
          position: "absolute", top: 14, left: 16, zIndex: 4, pointerEvents: "none",
          fontSize: 9, letterSpacing: ".22em", fontWeight: 800,
          background: "rgba(0,0,0,0.55)", backdropFilter: "blur(8px)",
          color: "rgba(255,255,255,0.75)", padding: "5px 10px", borderRadius: 8,
          border: "1px solid rgba(255,255,255,0.12)",
        }}>
          VEL CLASS · <span style={{ color: ac }}>{wClass}</span>
        </div>

        {/* Knee cave warning — top-right */}
        {metrics.kneeCave && (
          <motion.div
            initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }}
            style={{
              position: "absolute", top: 14, right: 16, zIndex: 4,
              padding: "8px 12px", borderRadius: 10,
              border: "1px solid #FF453A", background: "rgba(255,69,58,0.18)",
              color: "#FF453A", fontSize: 10, fontWeight: 900, letterSpacing: ".16em",
              boxShadow: "0 0 20px #FF453A44",
            }}>
            ⚠ KNEE CAVE · {Math.round(metrics.kneeAngle)}°
          </motion.div>
        )}

        {/* ── Floating metrics HUD — bottom of camera ── */}
        <div style={{
          position: "absolute", bottom: 0, left: 0, right: 0, zIndex: 4,
          background: "linear-gradient(to top, rgba(0,0,0,0.92) 0%, rgba(0,0,0,0.6) 70%, transparent 100%)",
          padding: "28px 16px 16px",
        }}>
          {/* 4 big stats in a row — dark pill always so readable on any bg */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 8, marginBottom: 12 }}>
            {[
              { label: "MEAN V", value: v.toFixed(2), unit: "m/s", color: ac },
              { label: "PEAK V", value: pv.toFixed(2), unit: "m/s", color: ac },
              { label: "POWER",  value: Math.round(metrics.power), unit: "W",   color: "#30D158" },
              { label: "REPS",   value: metrics.reps, unit: "",    color: "#fff" },
            ].map(({ label, value, unit: u, color }) => (
              <div key={label} style={{
                background: "rgba(0,0,0,0.65)", borderRadius: 12,
                padding: "10px 6px", textAlign: "center",
                border: "1px solid rgba(255,255,255,0.15)",
                backdropFilter: "blur(12px)",
              }}>
                <div style={{ fontSize: 8, letterSpacing: ".18em", color: "rgba(255,255,255,0.5)", fontWeight: 800, marginBottom: 4 }}>{label}</div>
                <div style={{ fontSize: 22, fontWeight: 800, color, fontVariantNumeric: "tabular-nums", lineHeight: 1 }}>
                  {value}
                </div>
                {u ? <div style={{ fontSize: 9, color: "rgba(255,255,255,0.35)", marginTop: 2 }}>{u}</div> : null}
              </div>
            ))}
          </div>

          {/* Bar path drift — thin line */}
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ fontSize: 8, letterSpacing: ".2em", color: "rgba(255,255,255,0.7)", fontWeight: 800, whiteSpace: "nowrap", textShadow: "0 1px 4px rgba(0,0,0,0.8)" }}>BAR DRIFT</div>
            <div style={{ flex: 1, height: 3, borderRadius: 2, background: "rgba(255,255,255,0.1)", overflow: "hidden" }}>
              <div style={{
                height: "100%", borderRadius: 2,
                width: `${Math.min(100, (metrics.barPathDeviation * 100) / 20 * 100)}%`,
                background: metrics.barPathState === "alarm" ? "#FF453A" : metrics.barPathState === "warn" ? "#FF9F0A" : ac,
                transition: "width .2s",
              }}/>
            </div>
            <div style={{
              fontSize: 12, fontWeight: 800, fontVariantNumeric: "tabular-nums",
              color: metrics.barPathState === "alarm" ? "#FF453A" : metrics.barPathState === "warn" ? "#FF9F0A" : "rgba(255,255,255,0.7)",
              minWidth: 48, textAlign: "right",
            }}>
              {(metrics.barPathDeviation * 100).toFixed(1)} cm
            </div>
          </div>
        </div>
      </div>

      {/* ── Bottom panel — load input + form gauges ── */}
      <div style={{
        background: T.card, borderTop: `1px solid ${T.border}`,
        padding: "14px 16px 20px", display: "flex", flexDirection: "column", gap: 12,
      }}>
        {/* Weight input row */}
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <div style={{ fontSize: 9, letterSpacing: ".24em", color: T.faint, fontWeight: 800, whiteSpace: "nowrap" }}>LOAD</div>
          <input
            value={weightInput}
            onChange={(e) => setWeightInput(e.target.value.replace(/[^\d.]/g, ""))}
            inputMode="decimal"
            style={{
              flex: 1, padding: "10px 14px", borderRadius: 10,
              border: `1px solid ${T.border}`, background: T.glass,
              color: T.text, fontSize: 20, fontWeight: 700,
              outline: "none", fontVariantNumeric: "tabular-nums", textAlign: "center",
            }}
          />
          <button
            onClick={() => setUnit(unit === "lb" ? "kg" : "lb")}
            style={{
              padding: "10px 16px", borderRadius: 10,
              border: `1px solid ${T.border}`, background: "transparent",
              color: T.text, fontSize: 11, fontWeight: 900, letterSpacing: ".18em", cursor: "pointer",
            }}>{unit.toUpperCase()}</button>
        </div>

        {/* Knee angle gauge */}
        <Gauge
          label="KNEE ANGLE (R)"
          value={Math.round(metrics.kneeAngle)}
          unit="°"
          min={60} max={180}
          warnBelow={KNEE_CAVE_FLAG}
          T={T}
        />

        <div style={{ fontSize: 9, color: T.ghost, letterSpacing: ".14em", textAlign: "center", marginTop: -4 }}>
          RVN · GHOST BAR v1.0 · {massKg.toFixed(1)} kg
        </div>
      </div>
    </div>
  );
}

// ─── Stat card (big number) ──────────────────────────────────────────────────
function Stat({ label, value, unit, accent, T }) {
  return (
    <div>
      <div style={{ fontSize: 9, letterSpacing: ".22em", color: T.faint, fontWeight: 800 }}>{label}</div>
      <div style={{
        fontSize: 34, fontWeight: 800, color: accent, letterSpacing: "-0.02em", lineHeight: 1.05,
        fontVariantNumeric: "tabular-nums", marginTop: 2,
      }}>
        {value}<span style={{ fontSize: 12, color: T.faint, marginLeft: 6, fontWeight: 700, letterSpacing: ".08em" }}>{unit}</span>
      </div>
    </div>
  );
}

// ─── Gauge (thin bar) ────────────────────────────────────────────────────────
function Gauge({ label, value, unit, min, max, warnAbove, alarmAbove, warnBelow, T }) {
  const t = Math.max(0, Math.min(1, (value - min) / (max - min)));
  let color = T.blue;
  if (alarmAbove !== undefined && value >= alarmAbove) color = "#FF453A";
  else if (warnAbove !== undefined && value >= warnAbove) color = "#FF9F0A";
  if (warnBelow !== undefined && value < warnBelow) color = "#FF453A";
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
        <span style={{ fontSize: 9, letterSpacing: ".22em", color: T.faint, fontWeight: 800 }}>{label}</span>
        <span style={{ fontSize: 13, fontWeight: 800, color, fontVariantNumeric: "tabular-nums" }}>
          {value}<span style={{ fontSize: 10, color: T.faint, marginLeft: 4 }}>{unit}</span>
        </span>
      </div>
      <div style={{ marginTop: 6, height: 4, background: T.border, borderRadius: 2, overflow: "hidden" }}>
        <div style={{
          width: `${t * 100}%`, height: "100%", background: color,
          boxShadow: `0 0 10px ${color}`, transition: "width .15s ease-out",
        }}/>
      </div>
    </div>
  );
}


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║  RVN OS — SIGN-IN / RETURNING USER VAULT                                 ║
// ║  Returning athletes skip the questionnaire; their biology, archetype,    ║
// ║  and perf data are restored from the local Bio-Vault.                    ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ─── Safe storage (localStorage with try/catch + in-memory fallback) ────────
const RVN_VAULT_KEY = "rvn_os_vault_v1";
const __rvn_mem_vault = { data: null };

function rvnReadVault() {
  if (__rvn_mem_vault.data) return __rvn_mem_vault.data;
  try {
    if (typeof window !== "undefined" && window.localStorage) {
      const raw = window.localStorage.getItem(RVN_VAULT_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        __rvn_mem_vault.data = parsed;
        return parsed;
      }
    }
  } catch (_) { /* sandboxed — in-memory only */ }
  __rvn_mem_vault.data = { profiles: [] };
  return __rvn_mem_vault.data;
}

function rvnWriteVault(v) {
  __rvn_mem_vault.data = v;
  try {
    if (typeof window !== "undefined" && window.localStorage) {
      window.localStorage.setItem(RVN_VAULT_KEY, JSON.stringify(v));
    }
  } catch (_) { /* ignore */ }
}





// ─── Sign-in screen ─────────────────────────────────────────────────────────
function SignInScreen({ onSignIn, onNewUser, onBack, theme = "dark", mode = "gym" }) {
  const T = D[theme];
  const M = OS_MODES[mode] || OS_MODES.gym;
  const ac = T[M.accentKey];

  const [query, setQuery] = useState("");
  const [err, setErr]     = useState("");
  const [scanning, setScanning] = useState(false);

  const vault = useMemo(() => rvnReadVault(), []);
  const profiles = (vault?.profiles || [])
    .slice()
    .sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));

  const doSignIn = (p) => {
    setErr("");
    setScanning(true);
    setTimeout(() => {
      setScanning(false);
      onSignIn && onSignIn(p);
    }, 900);
  };

  const tryLookup = () => {
    const p = rvnFindProfile(query);
    if (p) doSignIn(p);
    else setErr("No Bio-Vault found for that ID. Create one below.");
  };

  return (
    <Screen theme={theme}>
      <div style={{ padding:"20px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <RVNLogo size={30}/>
      </div>

      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", padding:"8px 24px 36px" }}>
        <motion.div {...FX.up} style={{ textAlign:"center", marginTop:14, marginBottom:22 }}>
          <Pill label="◉  BIO-VAULT · RETURNING"  color={ac} theme={theme}/>
          <div style={{ fontSize:30, fontWeight:900, letterSpacing:"-.02em", color:T.text, marginTop:14, lineHeight:1.02 }}>
            Welcome<br/>Back.
          </div>
          <div style={{ fontSize:13, color:T.muted, marginTop:8, maxWidth:280 }}>
            Your biology is already on file. Sign in to skip the questionnaire and jump straight to tonight's protocol.
          </div>
        </motion.div>

        {/* Saved profiles */}
        {profiles.length > 0 && (
          <motion.div {...FX.up} style={{ width:"100%", maxWidth:360, marginBottom:16 }}>
            <div style={{ fontSize:9.5, fontWeight:800, color:T.faint, letterSpacing:".14em", marginBottom:8, paddingLeft:4 }}>
              SAVED PROFILES · THIS DEVICE
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {profiles.slice(0, 4).map((p, i) => {
                const label = p.user?.name || p.user?.email || "Athlete";
                const sub   = p.user?.email || (p.archetypeId || "").replace(/_/g," ").toUpperCase();
                return (
                  <motion.button key={i} whileTap={{ scale:.98 }}
                    onClick={() => doSignIn(p)}
                    style={{
                      textAlign:"left",
                      background:T.glass, border:`1px solid ${T.border}`,
                      borderRadius:14, padding:"12px 14px", cursor:"pointer",
                      display:"flex", alignItems:"center", justifyContent:"space-between", gap:12,
                    }}>
                    <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                      <div style={{
                        width:36, height:36, borderRadius:18,
                        background:`linear-gradient(135deg, ${ac}33, ${ac}11)`,
                        border:`1px solid ${ac}55`,
                        display:"flex", alignItems:"center", justifyContent:"center",
                        fontSize:13, fontWeight:900, color:ac, letterSpacing:".04em",
                      }}>{(label[0] || "A").toUpperCase()}</div>
                      <div>
                        <div style={{ fontSize:14, fontWeight:800, color:T.text }}>{label}</div>
                        <div style={{ fontSize:10, color:T.muted, letterSpacing:".06em", marginTop:2 }}>{sub}</div>
                      </div>
                    </div>
                    <div style={{ fontSize:10, fontWeight:800, color:ac, letterSpacing:".14em" }}>SIGN IN →</div>
                  </motion.button>
                );
              })}
            </div>
          </motion.div>
        )}

        {/* Manual lookup */}
        <motion.div {...FX.up} style={{ width:"100%", maxWidth:360 }}>
          <GlassCard theme={theme} style={{ padding:"14px 16px", border:`1px solid ${ac}22` }}>
            <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
              EMAIL OR VAULT ALIAS
            </div>
            <input value={query}
              onChange={e => { setQuery(e.target.value); setErr(""); }}
              onKeyDown={e => { if (e.key === "Enter") tryLookup(); }}
              placeholder="you@domain.com"
              style={{ width:"100%", fontSize:17, fontWeight:600 }}/>
          </GlassCard>

          {err && (
            <div style={{ fontSize:11, color:T.red, marginTop:8, textAlign:"center", letterSpacing:".04em" }}>
              {err}
            </div>
          )}

          <div style={{ marginTop:12 }}>
            <ShimmerCTA
              label={scanning ? "Reading Signature…" : "Unlock Bio-Vault  ◉"}
              onClick={() => !scanning && tryLookup()}
              theme={theme} color={ac}
              disabled={scanning || !query.trim()}/>
          </div>

          {/* First-time link */}
          <div style={{ textAlign:"center", marginTop:16 }}>
            <div style={{ fontSize:10, color:T.faint, letterSpacing:".1em", marginBottom:6 }}>
              FIRST TIME ON RVN?
            </div>
            <motion.button whileTap={{ scale:.96 }}
              onClick={onNewUser}
              style={{
                background:"transparent", border:`1px solid ${T.border}`,
                borderRadius:20, padding:"8px 16px", cursor:"pointer",
                fontSize:11, fontWeight:800, color:T.text, letterSpacing:".1em",
              }}>
              CREATE BIO-IDENTITY →
            </motion.button>
          </div>
        </motion.div>
      </div>
    </Screen>
  );
}

