// Heat color ramp: cobalt (cool) → red (hot)
function rvnHeatColor(t) {
  // t ∈ [0,1]
  const clamp = Math.max(0, Math.min(1, t));
  if (clamp < 0.5) {
    // cobalt → amber
    const k = clamp / 0.5;
    const r = Math.round( 77 + (255 -  77)*k);
    const g = Math.round(140 + (196 - 140)*k);
    const b = Math.round(255 + ( 60 - 255)*k);
    return `rgb(${r},${g},${b})`;
  }
  // amber → red
  const k = (clamp - 0.5) / 0.5;
  const r = Math.round(255 + (255 - 255)*k);
  const g = Math.round(196 + ( 60 - 196)*k);
  const b = Math.round( 60 + ( 60 -  60)*k);
  return `rgb(${r},${g},${b})`;
}

// ─── Segmented control ──────────────────────────────────────────────────────
function TGSegmented({ value, onChange, options, theme, accent }) {
  const T = D[theme];
  return (
    <div style={{
      display:"inline-flex", padding:3,
      background: T.glass,
      border:`1px solid ${T.border}`,
      borderRadius:10, gap:2,
    }}>
      {options.map(o => {
        const active = o.value === value;
        return (
          <motion.button key={o.value}
            whileTap={{ scale:.94 }}
            onClick={() => onChange(o.value)}
            style={{
              padding:"6px 12px", borderRadius:8,
              background: active ? accent : "transparent",
              border:"none", cursor:"pointer",
              fontSize:10, fontWeight:800, letterSpacing:".1em",
              color: active ? (theme==="dark" ? "#000" : "#fff") : T.muted,
              transition:"background .2s, color .2s",
            }}>
            {o.label}
          </motion.button>
        );
      })}
    </div>
  );
}

// ─── Heat intensity bar (card footer) ───────────────────────────────────────
function TGHeatBar({ value, max, theme }) {
  const T = D[theme];
  const t = max > 0 ? value / max : 0;
  const color = rvnHeatColor(t);
  return (
    <div style={{ marginTop:10 }}>
      <div style={{
        position:"relative", height:4, borderRadius:2,
        background: `${T.border}`, overflow:"hidden",
      }}>
        <motion.div
          initial={{ width:0 }}
          animate={{ width:`${Math.round(t*100)}%` }}
          transition={{ duration:.7, ease:[.22,1,.36,1] }}
          style={{
            position:"absolute", inset:0, width:`${Math.round(t*100)}%`,
            background: `linear-gradient(90deg, ${color}, ${color}cc)`,
            boxShadow: `0 0 12px ${color}88`,
          }}/>
      </div>
      <div style={{
        display:"flex", justifyContent:"space-between",
        fontSize:8.5, fontWeight:800, letterSpacing:".12em",
        color: T.faint, marginTop:5,
      }}>
        <span>HEAT</span>
        <span style={{ color }}>{Math.round(t*100)}%</span>
      </div>
    </div>
  );
}

// ─── Gym: NFC floor grid + top-3 ranking ────────────────────────────────────
function TGGymHeatMap({ data, theme, accent }) {
  const T = D[theme];
  const stations = data?.stations || [];
  const maxTaps = stations.reduce((m, s) => Math.max(m, s.taps), 0) || 1;

  // Build grid dimensions
  const cols = 4, rows = 3;

  // Top 3 rank
  const top3 = stations.slice().sort((a, b) => b.taps - a.taps).slice(0, 3);
  const top3Ids = new Set(top3.map(s => s.id));

  return (
    <div>
      {/* Floor Grid */}
      <div style={{
        display:"grid",
        gridTemplateColumns:`repeat(${cols}, 1fr)`,
        gap:6,
        padding:10,
        background: `${T.bg}`,
        border:`1px solid ${T.border}`,
        borderRadius:14,
        marginBottom:14,
        position:"relative",
      }}>
        {/* Faint blueprint grid overlay */}
        <div style={{
          position:"absolute", inset:0, borderRadius:14, pointerEvents:"none",
          backgroundImage:`linear-gradient(${T.border} 1px, transparent 1px),
                            linear-gradient(90deg, ${T.border} 1px, transparent 1px)`,
          backgroundSize:"20px 20px",
          opacity:.18,
        }}/>
        {Array.from({ length: rows }).map((_, yi) =>
          Array.from({ length: cols }).map((_, xi) => {
            const s = stations.find(st => st.x === xi && st.y === yi);
            if (!s) {
              return (
                <div key={`${xi}-${yi}`} style={{
                  aspectRatio:"1/1", borderRadius:8,
                  background: "transparent",
                  border: `1px dashed ${T.border}`,
                  opacity:.4,
                }}/>
              );
            }
            const t = s.taps / maxTaps;
            const color = rvnHeatColor(t);
            const isTop = top3Ids.has(s.id);
            const rank = top3.findIndex(x => x.id === s.id) + 1;
            return (
              <motion.div key={s.id}
                initial={{ opacity:0, scale:.9 }}
                animate={{ opacity:1, scale:1 }}
                transition={{ duration:.35, delay:(yi*cols+xi)*.02 }}
                style={{
                  aspectRatio:"1/1", borderRadius:8,
                  position:"relative", overflow:"hidden",
                  background: `radial-gradient(circle at 50% 50%, ${color}66 0%, ${color}22 60%, transparent 100%)`,
                  border: isTop ? `1.5px solid ${color}` : `1px solid ${T.border}`,
                  boxShadow: isTop ? `0 0 18px ${color}88, inset 0 0 20px ${color}33` : "none",
                  padding:6,
                  display:"flex", flexDirection:"column", justifyContent:"space-between",
                }}>
                {isTop && (
                  <div style={{
                    position:"absolute", top:4, right:4,
                    fontSize:8, fontWeight:900, color,
                    background:`${T.bg}ee`, padding:"2px 5px", borderRadius:4,
                    letterSpacing:".1em",
                  }}>#{rank}</div>
                )}
                <div style={{
                  fontSize:8, fontWeight:800, color:T.faint, letterSpacing:".1em",
                }}>{s.zone}</div>
                <div>
                  <div style={{ fontSize:9.5, fontWeight:800, color:T.text, lineHeight:1.1 }}>
                    {s.label}
                  </div>
                  <div style={{ fontSize:10, fontWeight:900, color, marginTop:3 }}>
                    {s.taps.toLocaleString()}<span style={{ fontSize:7, color:T.faint, marginLeft:3, letterSpacing:".1em" }}>TAPS</span>
                  </div>
                </div>
              </motion.div>
            );
          })
        )}
      </div>

      {/* Top-3 High-Traffic Zones */}
      <div style={{ marginBottom:6 }}>
        <div style={{
          fontSize:9.5, fontWeight:800, color:T.faint,
          letterSpacing:".14em", marginBottom:8,
        }}>TOP 3 · HIGH-TRAFFIC ZONES</div>
        <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
          {top3.map((s, i) => {
            const t = s.taps / maxTaps;
            const color = rvnHeatColor(t);
            return (
              <motion.div key={s.id}
                initial={{ opacity:0, x:-10 }}
                animate={{ opacity:1, x:0 }}
                transition={{ delay:.1+i*.08 }}
                style={{
                  background: T.glass,
                  border: `1px solid ${color}55`,
                  borderRadius:12, padding:"10px 12px",
                  display:"flex", alignItems:"center", gap:12,
                }}>
                <div style={{
                  width:28, height:28, borderRadius:14,
                  background:`${color}22`,
                  border:`1px solid ${color}`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:11, fontWeight:900, color,
                }}>#{i+1}</div>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:12, fontWeight:800, color:T.text }}>{s.label}</div>
                  <div style={{ fontSize:9, color:T.faint, letterSpacing:".1em" }}>{s.zone}</div>
                </div>
                <div style={{ textAlign:"right" }}>
                  <div style={{ fontSize:14, fontWeight:900, color }}>
                    {s.taps.toLocaleString()}
                  </div>
                  <div style={{ fontSize:8, color:T.faint, letterSpacing:".14em" }}>TAP VELOCITY</div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── Store/Smoothie: velocity list (glowing horizontal bars) ────────────────
function TGVelocityList({ data, theme, accent, unitLabel = "UNITS" }) {
  const T = D[theme];
  const items = (data?.items || []).slice().sort((a, b) => b.units - a.units);
  const maxUnits = items.reduce((m, it) => Math.max(m, it.units), 0) || 1;

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
      {items.map((it, i) => {
        const t = it.units / maxUnits;
        const color = rvnHeatColor(t);
        return (
          <motion.div key={it.id}
            initial={{ opacity:0, x:-8 }}
            animate={{ opacity:1, x:0 }}
            transition={{ delay:i*.04, duration:.35 }}
            style={{
              background: T.glass,
              border:`1px solid ${T.border}`,
              borderRadius:12, padding:"11px 13px",
              position:"relative", overflow:"hidden",
            }}>
            {/* Row header */}
            <div style={{ display:"flex", alignItems:"baseline", justifyContent:"space-between", marginBottom:6 }}>
              <div style={{ display:"flex", alignItems:"baseline", gap:8 }}>
                <div style={{ fontSize:12, fontWeight:800, color:T.text }}>{it.name}</div>
                <div style={{ fontSize:8.5, fontWeight:800, color:T.faint, letterSpacing:".14em" }}>
                  {it.category}
                </div>
              </div>
              <div style={{ textAlign:"right" }}>
                <div style={{ fontSize:12, fontWeight:900, color }}>
                  {it.units.toLocaleString()} <span style={{ fontSize:8, color:T.faint, letterSpacing:".14em" }}>{unitLabel}</span>
                </div>
                {typeof it.revenue === "number" && (
                  <div style={{ fontSize:9, color:T.muted, marginTop:1 }}>
                    ${it.revenue.toLocaleString()}
                  </div>
                )}
              </div>
            </div>
            {/* Velocity bar (glowing) */}
            <div style={{
              position:"relative", height:7, borderRadius:4,
              background:`${T.border}`, overflow:"hidden",
            }}>
              <motion.div
                initial={{ width:0 }}
                animate={{ width:`${Math.round(t*100)}%` }}
                transition={{ duration:.7, ease:[.22,1,.36,1], delay:.04*i }}
                style={{
                  position:"absolute", inset:0, width:`${Math.round(t*100)}%`,
                  background:`linear-gradient(90deg, ${color} 0%, ${color}cc 100%)`,
                  boxShadow:`0 0 16px ${color}aa, 0 0 4px ${color}`,
                }}/>
            </div>
          </motion.div>
        );
      })}
    </div>
  );
}

// ─── Header KPI card ────────────────────────────────────────────────────────
function TGStatCard({ label, value, sub, accent, theme }) {
  const T = D[theme];
  return (
    <div style={{
      background: `${T.bg}`,
      border:`1px solid ${accent}55`,
      borderRadius:12, padding:"12px 14px",
      boxShadow:`inset 0 0 24px ${accent}11, 0 0 18px ${accent}22`,
      position:"relative", overflow:"hidden",
    }}>
      <div style={{
        position:"absolute", top:0, left:0, right:0, height:2,
        background:`linear-gradient(90deg, transparent, ${accent}, transparent)`,
      }}/>
      <div style={{ fontSize:9, fontWeight:800, color:T.faint, letterSpacing:".14em", marginBottom:6 }}>
        {label}
      </div>
      <div style={{ fontSize:22, fontWeight:900, color:T.text, letterSpacing:"-.01em" }}>
        {value}
      </div>
      {sub && (
        <div style={{ fontSize:9.5, color:accent, marginTop:3, letterSpacing:".06em", fontWeight:700 }}>
          {sub}
        </div>
      )}
    </div>
  );
}

// ─── MAIN: TelemetryGrid ────────────────────────────────────────────────────
function TelemetryGrid({ mode = "gym", theme = "dark", analyticsData }) {
  const T = D[theme];
  const COBALT = T.blue || "#4D8CFF";

  const [range, setRange] = useState("daily"); // daily · weekly · monthly

  const modeData = useMemo(() => {
    const ext = analyticsData?.[mode];
    const dflt = RVN_TELEMETRY_DEFAULTS[mode] || RVN_TELEMETRY_DEFAULTS.gym;
    return {
      daily:   ext?.daily   || dflt.daily,
      weekly:  ext?.weekly  || dflt.weekly,
      monthly: ext?.monthly || dflt.monthly,
    };
  }, [analyticsData, mode]);

  const current = modeData[range] || modeData.daily;

  // Range options
  const RANGES = [
    { value:"daily",   label:"DAILY"   },
    { value:"weekly",  label:"WEEKLY"  },
    { value:"monthly", label:"MONTHLY" },
  ];

  // Mode-aware KPIs
  let kpis = [];
  let bodyNode = null;

  if (mode === "gym") {
    const stations = current.stations || [];
    const topStation = stations.slice().sort((a, b) => b.taps - a.taps)[0];
    kpis = [
      { label:"TOTAL NFC TAPS",  value: (current.totalTaps || 0).toLocaleString(), sub:"ALL STATIONS" },
      { label:"UNIQUE MEMBERS",  value: (current.uniqueMembers || 0).toLocaleString(), sub:"DISTINCT SIGNATURES" },
      { label:"PEAK STATION",    value: topStation?.label || "—", sub:`${topStation?.taps?.toLocaleString() || 0} TAPS` },
    ];
    bodyNode = <TGGymHeatMap data={current} theme={theme} accent={COBALT}/>;
  } else {
    const items = current.items || [];
    const top = items.slice().sort((a, b) => b.units - a.units)[0];
    const totalUnits = items.reduce((s, i) => s + (i.units || 0), 0);
    const unitLabel = mode === "smoothie" ? "CUPS" : "UNITS";
    kpis = [
      { label:"TOTAL REVENUE",  value:`$${(current.totalRevenue || 0).toLocaleString()}`, sub:"GROSS" },
      { label:`${unitLabel} MOVED`, value: totalUnits.toLocaleString(), sub:"ALL SKUS" },
      { label:"TOP VELOCITY",   value: top?.name || "—", sub:`${top?.units?.toLocaleString() || 0} ${unitLabel}` },
    ];
    bodyNode = <TGVelocityList data={current} theme={theme} accent={COBALT} unitLabel={unitLabel}/>;
  }

  // Aggregate "heat intensity" for the whole deck = top value / mean ratio as proxy
  const heatRef = (() => {
    if (mode === "gym") {
      const sts = current.stations || [];
      const max = sts.reduce((m, s) => Math.max(m, s.taps), 0);
      const avg = sts.length ? sts.reduce((s, st) => s + st.taps, 0) / sts.length : 0;
      return { value: max, max: max + avg, label: "PEAK / MEAN" };
    } else {
      const its = current.items || [];
      const max = its.reduce((m, s) => Math.max(m, s.units), 0);
      const avg = its.length ? its.reduce((s, it) => s + it.units, 0) / its.length : 0;
      return { value: max, max: max + avg, label: "TOP SKU / MEAN" };
    }
  })();

  return (
    <motion.div
      initial={{ opacity:0, y:12 }}
      animate={{ opacity:1, y:0 }}
      transition={{ duration:.5, ease:[.22,1,.36,1] }}
      style={{
        marginTop:14,
        background: theme === "dark"
          ? `linear-gradient(180deg, ${T.bg} 0%, #05060A 100%)`
          : `linear-gradient(180deg, ${T.bg} 0%, #F2F5FA 100%)`,
        border:`1px solid ${COBALT}33`,
        borderRadius:16,
        padding:"14px 14px 16px",
        boxShadow:`inset 0 0 40px ${COBALT}10, 0 0 24px ${COBALT}14`,
      }}>
      {/* Header row */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <div style={{
            width:8, height:8, borderRadius:4, background:COBALT,
            boxShadow:`0 0 12px ${COBALT}`,
          }}/>
          <div>
            <div style={{ fontSize:11, fontWeight:900, color:T.text, letterSpacing:".12em" }}>
              TELEMETRY · {mode.toUpperCase()} MODE
            </div>
            <div style={{ fontSize:9, color:T.faint, letterSpacing:".12em", marginTop:1 }}>
              {mode === "gym"
                ? "NFC FLOOR HEAT MAP · RANKED BY TAP VELOCITY"
                : "SKU VELOCITY · RANKED BY UNITS MOVED"}
            </div>
          </div>
        </div>
        <TGSegmented
          value={range} onChange={setRange}
          options={RANGES} theme={theme} accent={COBALT}/>
      </div>

      {/* KPI row */}
      <div style={{
        display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8, marginBottom:14,
      }}>
        {kpis.map(k => (
          <TGStatCard key={k.label}
            label={k.label} value={k.value} sub={k.sub}
            accent={COBALT} theme={theme}/>
        ))}
      </div>

      {/* Mode-specific body */}
      {bodyNode}

      {/* Overall heat intensity — footer */}
      <TGHeatBar value={heatRef.value} max={heatRef.max} theme={theme}/>
    </motion.div>
  );
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║  RVN OS — SURGICAL VISION + CALORIE MONITOR                              ║
// ║                                                                          ║
// ║  • useSurgicalAgent()  multi-modal image → macros, ingredients,          ║
// ║                        BioScore cross-ref, NutritionState update,        ║
// ║                        structured Rationale output.                      ║
// ║                                                                          ║
// ║  • CalorieMonitor     cobalt progress bar with a desaturated 15%         ║
// ║                        "Ghost Segment" entropy buffer. AI prompts a      ║
// ║                        halt when consumed >= goal * 0.85.                ║
// ║                                                                          ║
// ║  Typography:  SF Mono on all numeric readouts for telemetry feel.        ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ─── Typography token ───────────────────────────────────────────────────────
const RVN_MONO = `"SF Mono", ui-monospace, "JetBrains Mono", "Roboto Mono", Menlo, Consolas, monospace`;

// ─── BMR / target calculator (Mifflin-St Jeor + activity + goal offset) ────
// activityKey: "sedentary" | "light" | "moderate" | "high" | "athlete"
// goalKey:     "cut" | "recomp" | "maintenance" | "lean_gain" | "bulk"
const ACTIVITY_MULT = {
  sedentary: 1.20,
  light:     1.375,
  moderate:  1.55,
  high:      1.725,
  athlete:   1.90,
};
const GOAL_OFFSET = {
  cut:         -500,
  recomp:      -250,
  maintenance:    0,
  lean_gain:   +300,
  bulk:        +500,
};
function calcBMR({ weightKg = 80, heightCm = 178, ageYears = 28, sex = "male" } = {}) {
  // Mifflin-St Jeor
  const base = 10 * weightKg + 6.25 * heightCm - 5 * ageYears;
  return Math.round(sex === "female" ? base - 161 : base + 5);
}
function calcCalorieTarget({
  weightKg = 80, heightCm = 178, ageYears = 28, sex = "male",
  activity = "moderate", goal = "recomp",
} = {}) {
  const bmr = calcBMR({ weightKg, heightCm, ageYears, sex });
  const tdee = Math.round(bmr * (ACTIVITY_MULT[activity] || 1.55));
  const target = tdee + (GOAL_OFFSET[goal] ?? 0);
  return {
    bmr, tdee, goalOffset: GOAL_OFFSET[goal] ?? 0,
    target: Math.max(1200, target),
  };
}

// ─── NutritionState helper (works with or without EnvProvider) ─────────────
function useNutritionState(seed) {
  const [state, setState] = useState(seed || {
    dayStartedAt: Date.now(),
    consumedKcal: 0,
    macros: { protein_g: 0, carbs_g: 0, fat_g: 0, fiber_g: 0, sugar_g: 0 },
    entries: [], // { t, source, name, kcal, macros, rationale, bioImpact }
  });

  const addEntry = (entry) => {
    setState((s) => ({
      ...s,
      consumedKcal: s.consumedKcal + (entry.kcal || 0),
      macros: {
        protein_g: s.macros.protein_g + (entry.macros?.protein_g || 0),
        carbs_g:   s.macros.carbs_g   + (entry.macros?.carbs_g   || 0),
        fat_g:     s.macros.fat_g     + (entry.macros?.fat_g     || 0),
        fiber_g:   s.macros.fiber_g   + (entry.macros?.fiber_g   || 0),
        sugar_g:   s.macros.sugar_g   + (entry.macros?.sugar_g   || 0),
      },
      entries: [{ ...entry, t: Date.now() }, ...s.entries].slice(0, 40),
    }));
  };

  const resetDay = () => setState({
    dayStartedAt: Date.now(),
    consumedKcal: 0,
    macros: { protein_g: 0, carbs_g: 0, fat_g: 0, fiber_g: 0, sugar_g: 0 },
    entries: [],
  });

  return { nutrition: state, addEntry, resetDay };
}

// ─── useSurgicalAgent — multi-modal image parser ────────────────────────────
// This hook abstracts the vision call so it can be backed by:
//   • window.RVN_VISION_API({ imageDataURL }) → Promise<{macros, items, ingredients, confidence}>
//   • a built-in heuristic demo ripple when no API is connected (sales-demo ready)
function useSurgicalAgent({ bioScore = 72, goals = "recomp", onUpdate } = {}) {
  const [status, setStatus]   = useState("idle"); // idle · capturing · analyzing · done · error
  const [result, setResult]   = useState(null);
  const [error,  setError]    = useState(null);

  const analyzeImage = async (imageDataURL, hint) => {
    setError(null);
    setStatus("analyzing");

    let raw;
    try {
      if (typeof window !== "undefined" && typeof window.RVN_VISION_API === "function") {
        raw = await window.RVN_VISION_API({ imageDataURL, hint });
      } else {
        raw = await demoVisionInference(hint);
      }
    } catch (e) {
      setStatus("error");
      setError(e?.message || "Vision agent failed");
      return null;
    }

    // Cross-reference with BioScore to produce a rationale + bio impact score
    const rationale = synthesizeRationale(raw, { bioScore, goals });
    const nutritionDelta = {
      kcal: raw.macros.kcal || 0,
      macros: {
        protein_g: raw.macros.protein_g || 0,
        carbs_g:   raw.macros.carbs_g   || 0,
        fat_g:     raw.macros.fat_g     || 0,
        fiber_g:   raw.macros.fiber_g   || 0,
        sugar_g:   raw.macros.sugar_g   || 0,
      },
      name: raw.name, source: raw.source || "vision",
      ingredients: raw.ingredients || [],
      rationale,
      bioImpact: rationale.bioImpact,
    };

    const payload = { raw, rationale, nutritionDelta, confidence: raw.confidence ?? 0.82 };
    setResult(payload);
    setStatus("done");
    if (onUpdate) {
      try { onUpdate(nutritionDelta); } catch (_) {}
    }
    return payload;
  };

  const reset = () => { setStatus("idle"); setResult(null); setError(null); };

  return { status, result, error, analyzeImage, reset };
}

// ─── Rationale synthesizer ──────────────────────────────────────────────────
function synthesizeRationale(parsed, ctx) {
  const { macros, name, ingredients = [] } = parsed;
  const { bioScore = 72, goals = "recomp" } = ctx || {};

  const flags = [];
  const wins  = [];

  // Ingredient heuristics (sales-demo: simple & strong)
  const flaggedIngredients = [
    "sucralose", "high fructose corn syrup", "palm oil",
    "maltodextrin", "artificial color", "soy protein isolate",
    "carrageenan", "partially hydrogenated",
  ];
  const bonusIngredients = [
    "whey isolate", "milk protein", "collagen", "creatine",
    "monk fruit", "stevia", "erythritol", "whole oats",
  ];
  for (const ing of ingredients) {
    const low = String(ing).toLowerCase();
    if (flaggedIngredients.some(fi => low.includes(fi))) flags.push(ing);
    if (bonusIngredients.some(bi => low.includes(bi)))   wins.push(ing);
  }

  // Macro heuristics vs goal
  const p = macros.protein_g || 0;
  const s = macros.sugar_g   || 0;
  const k = macros.kcal      || 0;
  if (p >= 20)                    wins.push(`${p}g protein hit`);
  if (s >= 18)                    flags.push(`${s}g sugar spike`);
  if (goals === "cut" && k > 300) flags.push(`${k} kcal — cut-phase heavy`);

  // BioScore modifier
  let bioImpact = 0;
  if (wins.length)  bioImpact += 2 * wins.length;
  if (flags.length) bioImpact -= 3 * flags.length;
  if (p >= 25)      bioImpact += 3;
  if (s >= 20)      bioImpact -= 4;

  const verdict =
    bioImpact >= 4  ? "GREEN · PROTOCOL-ALIGNED" :
    bioImpact >= 0  ? "AMBER · NEUTRAL"          :
                      "RED · DEVIATION";

  const summary = (() => {
    if (bioImpact >= 4) return `${name || "Item"} is dialled-in. Macros hit the ${goals} lane cleanly.`;
    if (bioImpact >= 0) return `${name || "Item"} is a lateral move — won't hurt, won't help.`;
    return `${name || "Item"} deviates from your ${goals} protocol. Consider a swap.`;
  })();

  return {
    verdict,
    bioImpact,
    summary,
    wins,
    flags,
    bioScoreNow: bioScore,
    bioScoreProjected: Math.max(0, Math.min(100, Math.round(bioScore + bioImpact * 0.6))),
  };
}

// ─── Demo inference (when no vision API wired) ─────────────────────────────
async function demoVisionInference(hint) {
  await new Promise(r => setTimeout(r, 1200));
  const archetypes = [
    {
      name: "RXBAR — Chocolate Sea Salt",
      source: "protein_bar",
      confidence: 0.88,
      ingredients: ["egg whites","dates","almonds","cashews","cocoa","natural flavor","sea salt"],
      macros: { kcal:210, protein_g:12, carbs_g:23, fat_g:9, fiber_g:3, sugar_g:13 },
    },
    {
      name: "Grilled Chicken · Rice · Broccoli",
      source: "meal",
      confidence: 0.81,
      ingredients: ["chicken breast","jasmine rice","broccoli","olive oil","sea salt","black pepper"],
      macros: { kcal:520, protein_g:52, carbs_g:58, fat_g:10, fiber_g:6, sugar_g:3 },
    },
    {
      name: "Quest Protein Bar — Cookies & Cream",
      source: "protein_bar",
      confidence: 0.85,
      ingredients: ["milk protein isolate","whey protein isolate","soluble corn fiber","almonds","sucralose","cocoa"],
      macros: { kcal:190, protein_g:21, carbs_g:22, fat_g:8, fiber_g:11, sugar_g:1 },
    },
    {
      name: "Creatine Monohydrate — 5g scoop",
      source: "supplement",
      confidence: 0.92,
      ingredients: ["creatine monohydrate"],
      macros: { kcal:0, protein_g:0, carbs_g:0, fat_g:0, fiber_g:0, sugar_g:0 },
    },
  ];
  // Hint-based selection so sales demo feels smart
  const hintLow = String(hint || "").toLowerCase();
  if (hintLow.includes("meal"))   return archetypes[1];
  if (hintLow.includes("suppl"))  return archetypes[3];
  if (hintLow.includes("quest"))  return archetypes[2];
  if (hintLow.includes("rx"))     return archetypes[0];
  return archetypes[Math.floor(Math.random() * archetypes.length)];
}

// ─── CalorieMonitor ─────────────────────────────────────────────────────────
// Props:
//   consumed: number (kcal)
//   goal:     number (kcal)   — default 2400
//   theme:    "dark" | "light"
//   goalsKey: string          — affects halt messaging
//   onHaltAck: () => void
function CalorieMonitor({
  consumed = 0,
  goal = 2400,
  theme = "dark",
  goalsKey = "recomp",
  onHaltAck,
}) {
  const T = D[theme];
  const COBALT = T.blue || "#4D8CFF";

  // Ghost segment = last 15% of goal (entropy buffer)
  const GHOST_FRACTION = 0.15;
  const ghostStart = goal * (1 - GHOST_FRACTION);     // kcal threshold where ghost begins
  const percent    = Math.max(0, Math.min(1.15, consumed / goal));
  const consumedPct = Math.min(1, percent);           // cap primary bar at 100% goal
  const overflowPct = Math.max(0, percent - 1);       // beyond-goal overflow

  const inGhost   = consumed >= ghostStart;           // hit entropy buffer
  const beyond    = consumed >= goal;                 // crossed goal line
  const remaining = goal - consumed;                  // can be negative

  // Halt messaging per goal
  const haltCopy = (() => {
    if (goalsKey === "cut")
      return `Stop eating. You're entering the ${Math.round(GHOST_FRACTION*100)}% entropy buffer — hidden logging error could push you over your cut deficit.`;
    if (goalsKey === "lean_gain" || goalsKey === "bulk")
      return `Primary fuel window closed. Remaining kcal should be clean protein only — the buffer accounts for hidden fats & sugars.`;
    return `You've hit the entropy buffer. Logging variance typically adds ~${Math.round(GHOST_FRACTION*100)}% hidden kcal — hold here to stay on target.`;
  })();

  // Gradient bar shell
  const shellH = 22;
  const desatCobalt = (theme === "dark")
    ? "rgba(77, 140, 255, 0.38)"  // lighter / desaturated
    : "rgba(77, 140, 255, 0.30)";

  return (
    <motion.div
      initial={{ opacity:0, y:8 }} animate={{ opacity:1, y:0 }}
      transition={{ duration:.45 }}
      style={{
        background: T.glass,
        border: `1px solid ${COBALT}33`,
        borderRadius: 16, padding: "14px 16px",
        boxShadow: `0 0 18px ${COBALT}14`,
      }}>

      {/* Header row */}
      <div style={{ display:"flex", alignItems:"baseline", justifyContent:"space-between", marginBottom:10 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{
            width:7, height:7, borderRadius:4, background:COBALT,
            boxShadow:`0 0 10px ${COBALT}`,
          }}/>
          <div style={{ fontSize:10, fontWeight:900, color:T.text, letterSpacing:".14em" }}>
            CALORIE MONITOR
          </div>
          <div style={{ fontSize:9, color:T.faint, letterSpacing:".1em" }}>
            · {goalsKey.toUpperCase()}
          </div>
        </div>
        <div style={{
          fontFamily: RVN_MONO, fontSize: 11, color: T.faint,
          letterSpacing:".06em",
        }}>
          {Math.round(percent*100)}%
        </div>
      </div>

      {/* The bar */}
      <div style={{
        position:"relative",
        height: shellH,
        background: `${T.bg}`,
        border: `1px solid ${T.border}`,
        borderRadius: shellH / 2,
        overflow: "hidden",
      }}>
        {/* Ghost segment (last 15%) — always rendered as a backdrop */}
        <div style={{
          position:"absolute", top:0, right:0, bottom:0,
          width: `${GHOST_FRACTION * 100}%`,
          background: `repeating-linear-gradient(
            45deg,
            ${desatCobalt} 0px,
            ${desatCobalt} 6px,
            transparent 6px,
            transparent 12px
          ), ${desatCobalt}`,
          borderLeft: `1px dashed ${COBALT}55`,
        }}/>

        {/* Ghost segment glow when entered */}
        {inGhost && (
          <motion.div
            initial={{ opacity:0 }} animate={{ opacity:1 }}
            style={{
              position:"absolute", top:0, right:0, bottom:0,
              width: `${GHOST_FRACTION * 100}%`,
              boxShadow: `inset 0 0 22px ${COBALT}77`,
              pointerEvents:"none",
            }}/>
        )}

        {/* Primary cobalt bar — consumed */}
        <motion.div
          initial={{ width: 0 }}
          animate={{ width: `${consumedPct * 100}%` }}
          transition={{ duration: .8, ease:[.22,1,.36,1] }}
          style={{
            position:"absolute", top:0, left:0, bottom:0,
            background: `linear-gradient(90deg, ${COBALT} 0%, ${COBALT}dd 100%)`,
            boxShadow: `0 0 18px ${COBALT}aa, inset 0 0 10px ${COBALT}33`,
          }}/>

        {/* Overflow (beyond goal) — red */}
        {overflowPct > 0 && (
          <motion.div
            initial={{ width:0 }} animate={{ width:`${overflowPct * 100}%` }}
            transition={{ duration:.4 }}
            style={{
              position:"absolute", top:0, left:"100%", bottom:0,
              background: `linear-gradient(90deg, ${T.red} 0%, ${T.red}cc 100%)`,
              boxShadow: `0 0 18px ${T.red}aa`,
              transform:`translateX(-${overflowPct * 100}%)`,
            }}/>
        )}

        {/* Goal line marker */}
        <div style={{
          position:"absolute", top:-2, bottom:-2,
          left: `${(1 - GHOST_FRACTION) * 100}%`,
          width: 1, background: `${COBALT}77`,
        }}/>
      </div>

      {/* Readouts (SF Mono) */}
      <div style={{
        display:"grid", gridTemplateColumns:"1fr 1fr 1fr",
        gap:10, marginTop:12,
      }}>
        <Readout label="CONSUMED" value={consumed} accent={COBALT} theme={theme} unit="kcal"/>
        <Readout label="REMAINING"
          value={remaining}
          accent={remaining < 0 ? T.red : (inGhost ? "#FFC43C" : T.green)}
          theme={theme} unit="kcal" signed/>
        <Readout label="GOAL" value={goal} accent={T.text} theme={theme} unit="kcal"/>
      </div>

      {/* Halt prompt — AI message when hitting ghost segment */}
      {inGhost && (
        <motion.div
          initial={{ opacity:0, y:8 }} animate={{ opacity:1, y:0 }}
          style={{
            marginTop:12, padding:"10px 12px",
            background: beyond ? `${T.red}1a` : `${COBALT}14`,
            border: `1px solid ${beyond ? T.red : COBALT}55`,
            borderRadius: 12,
            display:"flex", alignItems:"flex-start", gap:10,
          }}>
          <div style={{
            fontSize:14, fontWeight:900,
            color: beyond ? T.red : COBALT, letterSpacing:".1em",
            flexShrink:0, fontFamily: RVN_MONO,
          }}>
            {beyond ? "⚠" : "◉"}
          </div>
          <div style={{ flex:1 }}>
            <div style={{
              fontSize:10, fontWeight:900,
              color: beyond ? T.red : COBALT, letterSpacing:".16em", marginBottom:4,
            }}>
              {beyond ? "GOAL EXCEEDED · HALT FUEL" : "ENTROPY BUFFER · HOLD HERE"}
            </div>
            <div style={{ fontSize:12, color:T.text, lineHeight:1.5 }}>
              {haltCopy}
            </div>
            {onHaltAck && (
              <motion.button whileTap={{ scale:.96 }}
                onClick={onHaltAck}
                style={{
                  marginTop:8,
                  background:"transparent", border:`1px solid ${beyond ? T.red : COBALT}`,
                  color: beyond ? T.red : COBALT,
                  borderRadius:10, padding:"6px 12px",
                  fontSize:10, fontWeight:800, letterSpacing:".12em",
                  cursor:"pointer", fontFamily: RVN_MONO,
                }}>
                ACKNOWLEDGE
              </motion.button>
            )}
          </div>
        </motion.div>
      )}
    </motion.div>
  );
}

function Readout({ label, value, unit, accent, theme, signed }) {
  const T = D[theme];
  const display = (() => {
    if (typeof value !== "number") return value;
    const abs = Math.abs(Math.round(value));
    const sign = signed ? (value < 0 ? "−" : value > 0 ? "+" : "") : "";
    return `${sign}${abs.toLocaleString()}`;
  })();
  return (
    <div style={{
      padding:"8px 10px",
      background:`${T.bg}`,
      border:`1px solid ${T.border}`,
      borderRadius:10,
    }}>
      <div style={{
        fontSize:8.5, fontWeight:800, color:T.faint,
        letterSpacing:".16em", marginBottom:3,
      }}>{label}</div>
      <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
        <div style={{
          fontFamily: RVN_MONO,
          fontSize: 17, fontWeight: 800, color: accent,
          letterSpacing:".02em",
        }}>{display}</div>
        <div style={{
          fontFamily: RVN_MONO,
          fontSize: 9, color: T.faint, letterSpacing:".1em",
        }}>{unit}</div>
      </div>
    </div>
  );
}

// ─── SurgicalVisionScreen — full screen combining Agent + Monitor ───────────
function SurgicalVisionScreen({ onBack, theme = "dark", profile }) {
  const T = D[theme];
  const COBALT = T.blue || "#4D8CFF";

  // Derive target from profile (or defaults)
  const bodyProfile = profile?.perfData || {};
  const goalsKey    = profile?.goalsKey || profile?.goal || "recomp";
  const target = useMemo(() => calcCalorieTarget({
    weightKg: bodyProfile.weightKg || 80,
    heightCm: bodyProfile.heightCm || 178,
    ageYears: bodyProfile.age      || 28,
    sex:      bodyProfile.sex      || "male",
    activity: bodyProfile.activity || "moderate",
    goal:     goalsKey,
  }), [bodyProfile, goalsKey]);

  const { nutrition, addEntry, resetDay } = useNutritionState();

  const bioScore = profile?.bioScore || 72;

  const userEmail = (profile?.user?.email || "").trim().toLowerCase();

  const { status, result, error, analyzeImage, reset } = useSurgicalAgent({
    bioScore, goals: goalsKey,
    onUpdate: (delta) => {
      addEntry(delta);
      // Persist to Supabase nutrition log if email available
      if (userEmail) {
        try { rvnSaveNutritionEntry(userEmail, { ...delta, t: Date.now() }); } catch (_) {}
      }
    },
  });

  const fileRef  = useRef(null);
  const videoRef = useRef(null);
  const [cameraOn, setCameraOn] = useState(false);
  const streamRef = useRef(null);

  const openCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "environment" }, audio: false,
      });
      streamRef.current = s;
      if (videoRef.current) {
        videoRef.current.srcObject = s;
        await videoRef.current.play().catch(() => {});
      }
      setCameraOn(true);
    } catch (_) {
      // Fallback: file picker
      fileRef.current && fileRef.current.click();
    }
  };
  const stopCamera = () => {
    try { streamRef.current?.getTracks().forEach(t => t.stop()); } catch(_){}
    streamRef.current = null;
    setCameraOn(false);
  };
  useEffect(() => () => stopCamera(), []);

  const snapAndAnalyze = async () => {
    if (!videoRef.current) return;
    const v = videoRef.current;
    const canvas = document.createElement("canvas");
    canvas.width = v.videoWidth || 640;
    canvas.height = v.videoHeight || 480;
    const ctx = canvas.getContext("2d");
    ctx.drawImage(v, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL("image/jpeg", 0.85);
    await analyzeImage(dataUrl, "");
  };

  const onFilePick = async (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const reader = new FileReader();
    reader.onload = async () => {
      await analyzeImage(reader.result, f.name);
    };
    reader.readAsDataURL(f);
  };

  const rationale = result?.rationale;

  return (
    <Screen theme={theme} style={{ overflowY:"auto" }}>
      <div style={{ padding:"20px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <div style={{ fontSize:11, fontWeight:900, color:T.text, letterSpacing:".14em" }}>
          SURGICAL VISION
        </div>
        <RVNLogo size={28}/>
      </div>

      <div style={{ padding:"14px 18px 40px", display:"flex", flexDirection:"column", gap:14 }}>
        {/* Calorie monitor */}
        <CalorieMonitor
          consumed={nutrition.consumedKcal}
          goal={target.target}
          theme={theme}
          goalsKey={goalsKey}
        />

        {/* Target breakdown */}
        <div style={{
          display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8,
        }}>
          <MetaBlock label="BMR"     value={`${target.bmr.toLocaleString()}`}  unit="kcal" theme={theme}/>
          <MetaBlock label="TDEE"    value={`${target.tdee.toLocaleString()}`} unit="kcal" theme={theme}/>
          <MetaBlock label="OFFSET"
            value={`${target.goalOffset > 0 ? "+" : ""}${target.goalOffset}`}
            unit="kcal" theme={theme}
            accent={target.goalOffset < 0 ? T.red : (target.goalOffset > 0 ? T.green : T.text)}/>
        </div>

        {/* Capture panel */}
        <div style={{
          background: T.glass, border:`1px solid ${T.border}`, borderRadius:16,
          padding:14,
        }}>
          <div style={{ fontSize:10, fontWeight:900, color:T.text, letterSpacing:".16em", marginBottom:10 }}>
            AGENTIC VISION · MULTI-MODAL CAPTURE
          </div>

          {/* Camera viewport */}
          <div style={{
            position:"relative",
            aspectRatio: "16/10",
            background: "#000",
            borderRadius: 12, overflow:"hidden",
            border:`1px solid ${T.border}`,
            marginBottom:12,
          }}>
            <video ref={videoRef}
              playsInline muted autoPlay
              style={{
                width:"100%", height:"100%", objectFit:"cover",
                display: cameraOn ? "block" : "none",
              }}/>
            {!cameraOn && (
              <div style={{
                position:"absolute", inset:0,
                display:"flex", flexDirection:"column",
                alignItems:"center", justifyContent:"center",
                gap:8, color:T.muted, fontSize:11, letterSpacing:".14em",
              }}>
                <div style={{ fontSize:34, color:COBALT, fontFamily: RVN_MONO }}>◉</div>
                <div>AWAITING CAPTURE</div>
                <div style={{ fontSize:10, color:T.faint }}>
                  PROTEIN BAR · MEAL · SUPPLEMENT LABEL
                </div>
              </div>
            )}
            {/* Scan reticle */}
            {cameraOn && (
              <div style={{
                position:"absolute", inset:"12% 12%",
                border:`1px solid ${COBALT}99`, borderRadius:10,
                boxShadow:`inset 0 0 30px ${COBALT}44`,
                pointerEvents:"none",
              }}/>
            )}
          </div>

          {/* Action row */}
          <div style={{ display:"flex", gap:8 }}>
            {!cameraOn ? (
              <motion.button whileTap={{ scale:.96 }} onClick={openCamera}
                style={{
                  flex:1, padding:"11px 10px", borderRadius:12,
                  background: COBALT, border:`1px solid ${COBALT}`,
                  color: theme==="dark" ? "#000" : "#fff",
                  fontSize:11, fontWeight:900, letterSpacing:".14em",
                  cursor:"pointer", fontFamily: RVN_MONO,
                }}>
                START CAMERA
              </motion.button>
            ) : (
              <>
                <motion.button whileTap={{ scale:.96 }} onClick={snapAndAnalyze}
                  disabled={status === "analyzing"}
                  style={{
                    flex:1, padding:"11px 10px", borderRadius:12,
                    background: COBALT, border:`1px solid ${COBALT}`,
                    color: theme==="dark" ? "#000" : "#fff",
                    fontSize:11, fontWeight:900, letterSpacing:".14em",
                    cursor:"pointer", fontFamily: RVN_MONO,
                    opacity: status === "analyzing" ? .6 : 1,
                  }}>
                  {status === "analyzing" ? "ANALYZING…" : "SNAP + ANALYZE"}
                </motion.button>
                <motion.button whileTap={{ scale:.96 }} onClick={stopCamera}
                  style={{
                    padding:"11px 14px", borderRadius:12,
                    background:"transparent", border:`1px solid ${T.border}`,
                    color: T.muted, fontSize:11, fontWeight:800, letterSpacing:".1em",
                    cursor:"pointer", fontFamily: RVN_MONO,
                  }}>
                  STOP
                </motion.button>
              </>
            )}
            <motion.button whileTap={{ scale:.96 }}
              onClick={() => fileRef.current && fileRef.current.click()}
              style={{
                padding:"11px 14px", borderRadius:12,
                background:"transparent", border:`1px solid ${T.border}`,
                color: T.muted, fontSize:11, fontWeight:800, letterSpacing:".1em",
                cursor:"pointer", fontFamily: RVN_MONO,
              }}>
              UPLOAD
            </motion.button>
            <input ref={fileRef} type="file" accept="image/*"
              onChange={onFilePick} style={{ display:"none" }}/>
          </div>

          {/* Error */}
          {error && (
            <div style={{
              marginTop:10, padding:"8px 10px", borderRadius:10,
              background:`${T.red}18`, border:`1px solid ${T.red}55`,
              color:T.red, fontSize:11, letterSpacing:".06em", fontFamily: RVN_MONO,
            }}>
              VISION ERROR · {error}
            </div>
          )}
        </div>

        {/* Rationale card */}
        {result && rationale && (
          <motion.div
            initial={{ opacity:0, y:10 }} animate={{ opacity:1, y:0 }}
            style={{
              background: T.glass,
              border:`1px solid ${
                rationale.bioImpact >= 4 ? T.green :
                rationale.bioImpact >= 0 ? "#FFC43C" : T.red
              }66`,
              borderRadius:16, padding:14,
            }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
              <div style={{
                fontSize:9.5, fontWeight:900,
                color: rationale.bioImpact >= 4 ? T.green :
                       rationale.bioImpact >= 0 ? "#FFC43C" : T.red,
                letterSpacing:".16em",
              }}>
                {rationale.verdict}
              </div>
              <div style={{
                fontSize:10, fontFamily: RVN_MONO, color:T.faint, letterSpacing:".1em",
              }}>
                CONF {Math.round((result.confidence ?? 0.82) * 100)}%
              </div>
            </div>
            <div style={{ fontSize:15, fontWeight:800, color:T.text, letterSpacing:"-.01em" }}>
              {result.raw.name}
            </div>
            <div style={{ fontSize:12, color:T.muted, marginTop:6, lineHeight:1.55 }}>
              {rationale.summary}
            </div>

            {/* Macro strip */}
            <div style={{
              display:"grid", gridTemplateColumns:"repeat(5, 1fr)", gap:6, marginTop:10,
            }}>
              {[
                { k:"kcal",      label:"KCAL" },
                { k:"protein_g", label:"PROT" },
                { k:"carbs_g",   label:"CARB" },
                { k:"fat_g",     label:"FAT"  },
                { k:"sugar_g",   label:"SUG"  },
              ].map(({k,label}) => (
                <div key={k} style={{
                  background: T.bg, border:`1px solid ${T.border}`,
                  borderRadius:8, padding:"6px 4px", textAlign:"center",
                }}>
                  <div style={{
                    fontSize:8, fontWeight:800, color:T.faint, letterSpacing:".14em",
                  }}>{label}</div>
                  <div style={{
                    fontFamily: RVN_MONO, fontSize:13, fontWeight:800, color:T.text,
                  }}>
                    {result.raw.macros[k] ?? 0}
                    {k !== "kcal" && <span style={{ fontSize:8, color:T.faint }}>g</span>}
                  </div>
                </div>
              ))}
            </div>

            {/* Wins + Flags */}
            {(rationale.wins.length || rationale.flags.length) ? (
              <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginTop:10 }}>
                {rationale.wins.map((w, i) => (
                  <span key={`w${i}`} style={{
                    fontSize:9.5, fontWeight:800, color:T.green, letterSpacing:".06em",
                    padding:"3px 8px", borderRadius:14,
                    background:`${T.green}14`, border:`1px solid ${T.green}55`,
                  }}>+ {w}</span>
                ))}
                {rationale.flags.map((f, i) => (
                  <span key={`f${i}`} style={{
                    fontSize:9.5, fontWeight:800, color:T.red, letterSpacing:".06em",
                    padding:"3px 8px", borderRadius:14,
                    background:`${T.red}14`, border:`1px solid ${T.red}55`,
                  }}>− {f}</span>
                ))}
              </div>
            ) : null}

            {/* BioScore delta */}
            <div style={{
              display:"flex", alignItems:"center", gap:12,
              marginTop:12, paddingTop:10, borderTop:`1px solid ${T.border}`,
            }}>
              <div>
                <div style={{ fontSize:8.5, fontWeight:800, color:T.faint, letterSpacing:".16em" }}>
                  BIOSCORE
                </div>
                <div style={{ fontFamily: RVN_MONO, fontSize:15, fontWeight:900, color:T.text }}>
                  {rationale.bioScoreNow} → {rationale.bioScoreProjected}
                </div>
              </div>
              <div style={{
                fontFamily: RVN_MONO, fontSize:11, fontWeight:900,
                letterSpacing:".08em",
                color: rationale.bioImpact >= 0 ? T.green : T.red,
                background: rationale.bioImpact >= 0 ? `${T.green}18` : `${T.red}18`,
                border:`1px solid ${(rationale.bioImpact >= 0 ? T.green : T.red)}55`,
                borderRadius:10, padding:"4px 10px",
              }}>
                {rationale.bioImpact >= 0 ? "+" : ""}{rationale.bioImpact} IMPACT
              </div>
              <button onClick={reset}
                style={{
                  marginLeft:"auto",
                  background:"transparent", border:`1px solid ${T.border}`,
                  color:T.muted, fontSize:10, fontWeight:800, letterSpacing:".1em",
                  borderRadius:10, padding:"5px 10px", cursor:"pointer",
                  fontFamily: RVN_MONO,
                }}>
                CLEAR
              </button>
            </div>
          </motion.div>
        )}

        {/* Today's entries */}
        {nutrition.entries.length > 0 && (
          <div>
            <div style={{
              fontSize:9.5, fontWeight:900, color:T.faint,
              letterSpacing:".16em", marginBottom:8, paddingLeft:4,
            }}>
              TODAY · LOGGED {nutrition.entries.length}
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
              {nutrition.entries.slice(0, 6).map((e, i) => (
                <div key={i} style={{
                  background: T.glass, border:`1px solid ${T.border}`,
                  borderRadius:12, padding:"9px 12px",
                  display:"flex", alignItems:"center", gap:10,
                }}>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:12, fontWeight:800, color:T.text }}>{e.name}</div>
                    <div style={{ fontSize:9.5, color:T.faint, letterSpacing:".08em" }}>
                      {new Date(e.t).toLocaleTimeString([], { hour:"2-digit", minute:"2-digit" })}
                      · {(e.source || "vision").toUpperCase()}
                    </div>
                  </div>
                  <div style={{
                    fontFamily: RVN_MONO, fontSize:13, fontWeight:900, color:COBALT,
                  }}>
                    {e.kcal}<span style={{ fontSize:9, color:T.faint, marginLeft:2 }}>kcal</span>
                  </div>
                </div>
              ))}
            </div>
            {nutrition.entries.length > 0 && (
              <button onClick={resetDay}
                style={{
                  marginTop:10,
                  background:"transparent", border:`1px solid ${T.border}`,
                  color:T.muted, fontSize:10, fontWeight:800, letterSpacing:".12em",
                  borderRadius:10, padding:"6px 12px", cursor:"pointer",
                  fontFamily: RVN_MONO,
                }}>
                RESET DAY
              </button>
            )}
          </div>
        )}
      </div>
    </Screen>
  );
}

function MetaBlock({ label, value, unit, accent, theme }) {
  const T = D[theme];
  return (
    <div style={{
      padding:"10px 12px",
      background: T.glass,
      border:`1px solid ${T.border}`,
      borderRadius:12,
    }}>
      <div style={{
        fontSize:8.5, fontWeight:800, color:T.faint, letterSpacing:".16em", marginBottom:3,
      }}>{label}</div>
      <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
        <div style={{
          fontFamily: RVN_MONO, fontSize:16, fontWeight:800,
          color: accent || T.text,
        }}>{value}</div>
        <div style={{
          fontFamily: RVN_MONO, fontSize:9, color:T.faint, letterSpacing:".1em",
        }}>{unit}</div>
      </div>
    </div>
  );
}

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║  RVN OS — SUPABASE INTEGRATION                                           ║
// ║                                                                          ║
// ║  • Loads @supabase/supabase-js via CDN at runtime                        ║
// ║  • Replaces localStorage vault with cloud DB (profiles table)            ║
// ║  • Syncs nutrition log entries per user                                  ║
// ║  • localStorage fallback if network unavailable                          ║
// ║                                                                          ║
// ║  SQL to run in Supabase Dashboard → SQL Editor:                          ║
// ║  (copy block at bottom of this file)                                     ║
// ╚══════════════════════════════════════════════════════════════════════════╝

const RVN_SUPA_URL  = "https://pstqlqiitylggqchkzyh.supabase.co";
const RVN_SUPA_ANON = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBzdHFscWlpdHlsZ2dxY2hrenloIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzYxNzk1MjQsImV4cCI6MjA5MTc1NTUyNH0.7Y-ZgSjLvc6yekWOFBjQnNKVRqpK8q3Iqm4UXLI6tqA";

// ─── Singleton client loader ─────────────────────────────────────────────────
// Injects supabase-js from CDN once, returns the same client on every call.
let _supaPromise = null;

function getSupaClient() {
  if (_supaPromise) return _supaPromise;
  _supaPromise = new Promise((resolve, reject) => {
    if (typeof window === "undefined") { reject(new Error("no window")); return; }
    // Already loaded?
    if (window.supabase && window.supabase.createClient) {
      resolve(window.supabase.createClient(RVN_SUPA_URL, RVN_SUPA_ANON, {
        auth: { persistSession: true, autoRefreshToken: true },
      }));
      return;
    }
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.js";
    s.onload = () => {
      try {
        const client = window.supabase.createClient(RVN_SUPA_URL, RVN_SUPA_ANON, {
          auth: { persistSession: true, autoRefreshToken: true },
        });
        window.__rvnSupaClient = client;
        resolve(client);
      } catch (e) { reject(e); }
    };
    s.onerror = () => reject(new Error("supabase CDN load failed"));
    document.head.appendChild(s);
  });
  return _supaPromise;
}

// ─── useSupabase hook — gives any component the live client ─────────────────
function useSupabase() {
  const [client, setClient] = useState(null);
  const [supaReady, setSupaReady] = useState(false);
  useEffect(() => {
    getSupaClient()
      .then(c => { setClient(c); setSupaReady(true); })
      .catch(() => { setSupaReady(true); /* offline — fallback to localStorage */ });
  }, []);
  return { client, supaReady };
}

// ─── useRVNAuth — session, magic-link sign-in, sign-out ─────────────────────
// Works even if app is served from file:// (falls back to email-only lookup).
function useRVNAuth() {
  const { client, supaReady } = useSupabase();
  const [session,  setSession]  = useState(null);
  const [authUser, setAuthUser] = useState(null);
  const [checking, setChecking] = useState(true);

  useEffect(() => {
    if (!client) return;
    // Restore existing session (e.g. returned from magic-link click)
    client.auth.getSession().then(({ data }) => {
      setSession(data?.session || null);
      setAuthUser(data?.session?.user || null);
      setChecking(false);
    }).catch(() => setChecking(false));

    const { data: { subscription } } = client.auth.onAuthStateChange((_, s) => {
      setSession(s);
      setAuthUser(s?.user || null);
    });
    return () => subscription.unsubscribe();
  }, [client]);

  // Magic-link OTP (works when app is hosted on a URL)
  const sendMagicLink = async (email) => {
    if (!client) throw new Error("Supabase not ready");
    const { error } = await client.auth.signInWithOtp({
      email,
      options: {
        shouldCreateUser: true,
        emailRedirectTo: window.location.href,
      },
    });
    if (error) throw error;
  };

  // Email + password sign-up / sign-in (works everywhere)
  const signUpWithPassword = async (email, password) => {
    if (!client) throw new Error("Supabase not ready");
    const { data, error } = await client.auth.signUp({ email, password });
    if (error) throw error;
    return data;
  };

  const signInWithPassword = async (email, password) => {
    if (!client) throw new Error("Supabase not ready");
    const { data, error } = await client.auth.signInWithPassword({ email, password });
    if (error) throw error;
    return data;
  };

  const signOut = async () => {
    if (!client) return;
    await client.auth.signOut();
    setSession(null);
    setAuthUser(null);
  };

  return {
    client, supaReady, session, authUser, checking,
    sendMagicLink, signUpWithPassword, signInWithPassword, signOut,
  };
}

// ─── Profile CRUD (replaces in-memory rvnVault functions) ───────────────────
// These shadow/replace the originals declared in v5_login.jsx.
// They write to Supabase first, mirror to localStorage as offline cache.

async function rvnSaveProfile(profile) {
  // Always update localStorage cache
  __rvn_mem_vault.data = null; // bust cache so next read re-fetches
  try {
    if (typeof window !== "undefined" && window.localStorage) {
      const v = JSON.parse(window.localStorage.getItem(RVN_VAULT_KEY) || '{"profiles":[]}');
      const key = (profile.user?.email || profile.user?.name || "").trim().toLowerCase();
      if (key) {
        const idx = v.profiles.findIndex(p =>
          ((p.user?.email || p.user?.name || "").trim().toLowerCase()) === key);
        const stamped = { ...profile, updatedAt: Date.now() };
        if (idx >= 0) v.profiles[idx] = stamped; else v.profiles.push(stamped);
        window.localStorage.setItem(RVN_VAULT_KEY, JSON.stringify(v));
      }
    }
  } catch (_) {}

  // Cloud save
  try {
    const client = await getSupaClient();
    const email = (profile.user?.email || "").trim().toLowerCase();
    if (!email) return;
    await client.from("rvn_profiles").upsert({
      email,
      user_json:    profile.user     || {},
      biology:      profile.biology  || null,
      archetype_id: profile.archetypeId || null,
      perf_data:    profile.perfData || {},
      goals_key:    profile.goalsKey || null,
      updated_at:   new Date().toISOString(),
    }, { onConflict: "email" });
  } catch (_) { /* network unavailable — localStorage is source of truth */ }
}

async function rvnFindProfile(emailOrName) {
  const key = (emailOrName || "").trim().toLowerCase();
  if (!key) return null;

  // Try cloud first
  try {
    const client = await getSupaClient();
    const { data, error } = await client
      .from("rvn_profiles")
      .select("*")
      .eq("email", key)
      .single();
    if (!error && data) {
      // Shape back to the profile schema the app expects
      return {
        user:        data.user_json || {},
        biology:     data.biology   || null,
        archetypeId: data.archetype_id || null,
        perfData:    data.perf_data || {},
        goalsKey:    data.goals_key || null,
        updatedAt:   new Date(data.updated_at).getTime(),
      };
    }
  } catch (_) {}

  // Fallback to localStorage
  const v = rvnReadVault();
  const profiles = Array.isArray(v.profiles) ? v.profiles : [];
  return profiles.find(p => {
    const e = (p.user?.email || "").trim().toLowerCase();
    const n = (p.user?.name  || "").trim().toLowerCase();
    return e === key || n === key;
  }) || null;
}

// Fetch all saved profiles for the "SAVED PROFILES · THIS DEVICE" picker,
// merging cloud + local (cloud wins on conflict).
async function rvnListProfiles() {
  let cloud = [];
  try {
    const client = await getSupaClient();
    const { data } = await client
      .from("rvn_profiles")
      .select("*")
      .order("updated_at", { ascending: false })
      .limit(20);
    cloud = (data || []).map(d => ({
      user:        d.user_json || {},
      biology:     d.biology   || null,
      archetypeId: d.archetype_id || null,
      perfData:    d.perf_data || {},
      goalsKey:    d.goals_key || null,
      updatedAt:   new Date(d.updated_at).getTime(),
    }));
  } catch (_) {}

  // Merge with localStorage
  const v = rvnReadVault();
  const local = Array.isArray(v.profiles) ? v.profiles : [];
  const seen = new Set(cloud.map(p => (p.user?.email || "").toLowerCase()));
  const merged = [...cloud];
  for (const p of local) {
    const e = (p.user?.email || "").toLowerCase();
    if (e && !seen.has(e)) { merged.push(p); seen.add(e); }
  }
  return merged.sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));
}

// ─── Nutrition log sync ──────────────────────────────────────────────────────
async function rvnSaveNutritionEntry(email, entry) {
  if (!email) return;
  try {
    const client = await getSupaClient();
    await client.from("rvn_nutrition_log").insert({
      profile_email: email.trim().toLowerCase(),
      entry,
      logged_at: new Date().toISOString(),
    });
  } catch (_) { /* offline — local state still tracks it */ }
}

async function rvnLoadTodayNutrition(email) {
  if (!email) return [];
  try {
    const client = await getSupaClient();
    const dayStart = new Date();
    dayStart.setHours(0, 0, 0, 0);
    const { data } = await client
      .from("rvn_nutrition_log")
      .select("*")
      .eq("profile_email", email.trim().toLowerCase())
      .gte("logged_at", dayStart.toISOString())
      .order("logged_at", { ascending: false });
    return (data || []).map(r => r.entry);
  } catch (_) { return []; }
}

// ─── WORKOUT PERSISTENCE ─────────────────────────────────────────────────────
// SQL (run once in Supabase dashboard or migration):
// -------------------------------------------------------------------------
// create table workouts (
//   id            uuid primary key default gen_random_uuid(),
//   user_id       uuid references auth.users(id) on delete cascade,
//   profile_email text not null,
//   archetype_id  text not null,
//   mode          text not null default 'gym',
//   bio_score     int2 check (bio_score between 0 and 100),
//   exercises     jsonb not null default '[]',
//   sets_done     jsonb not null default '{}',
//   velocity_data jsonb,
//   notes         text,
//   logged_at     timestamptz not null default now()
// );
// alter table workouts enable row level security;
// create policy "Users see own workouts"
//   on workouts for select using (auth.uid() = user_id);
// create policy "Users insert own workouts"
//   on workouts for insert with check (auth.uid() = user_id);
// -------------------------------------------------------------------------

async function saveWorkoutSession({
  email, userId, archetypeId, mode = "gym",
  bioScore, exercises, setsDone, velocityData, notes,
}) {
  // Server-side validation — never trust raw client values
  const safeEmail    = sanitize(email || "").toLowerCase();
  const safeArchId   = sanitize(archetypeId || "");
  const safeBioScore = validateBioScore(bioScore);
  const safeNotes    = sanitize(notes || "");

  // Validate each exercise entry
  const safeExercises = (Array.isArray(exercises) ? exercises : []).map(ex => ({
    name:    sanitize(ex.name  || ""),
    sets:    sanitize(ex.sets  || ""),
    cue:     sanitize(ex.cue   || ""),
    rest:    validateNum(ex.rest, 0, 600, 0),
  }));

  // Validate setsDone — keys are "exIdx_setIdx", values are booleans
  const safeSets = {};
  for (const [k, v] of Object.entries(setsDone || {})) {
    if (/^\d+_\d+$/.test(k)) safeSets[k] = Boolean(v);
  }

  // Validate velocity data
  const safeVelocity = Array.isArray(velocityData)
    ? velocityData.map(d => validateSetData(d))
    : null;

  const record = {
    profile_email: safeEmail,
    user_id:       userId || null,
    archetype_id:  safeArchId,
    mode:          sanitize(mode),
    bio_score:     safeBioScore,
    exercises:     safeExercises,
    sets_done:     safeSets,
    velocity_data: safeVelocity,
    notes:         safeNotes,
    logged_at:     new Date().toISOString(),
  };

  // Offline cache — store up to 30 sessions in localStorage
  try {
    if (typeof window !== "undefined") {
      const raw   = JSON.parse(window.localStorage.getItem("rvn_workouts") || "[]");
      const local = Array.isArray(raw) ? raw : [];
      local.unshift(record);
      window.localStorage.setItem("rvn_workouts", JSON.stringify(local.slice(0, 30)));
    }
  } catch (_) {}

  // Cloud persist
  try {
    const client = await getSupaClient();
    const { error } = await client.from("workouts").insert(record);
    if (error) console.warn("[RVN] Workout save error:", error.message);
  } catch (e) { console.warn("[RVN] Workout save offline:", e.message); }
}

// fetchWorkoutHistory — returns last N sessions for a user (cloud → local fallback)
async function fetchWorkoutHistory(email, limit = 10) {
  const safeEmail = sanitize(email || "").toLowerCase();
  if (!safeEmail) return [];

  try {
    const client = await getSupaClient();
    const { data, error } = await client
      .from("workouts")
      .select("id, archetype_id, mode, bio_score, exercises, sets_done, logged_at, notes")
      .eq("profile_email", safeEmail)
      .order("logged_at", { ascending: false })
      .limit(limit);
    if (!error && data?.length) return data;
  } catch (_) {}

  // Fallback: localStorage
  try {
    const raw = JSON.parse(window.localStorage.getItem("rvn_workouts") || "[]");
    return (Array.isArray(raw) ? raw : [])
      .filter(r => r.profile_email === safeEmail)
      .slice(0, limit);
  } catch (_) { return []; }
}

// useHistory — React hook for session history (used in NarrativeScreen + HistoryFeed)
function useHistory(email) {
  const [sessions, setSessions] = useState([]);
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState(null);

  useEffect(() => {
    if (!email) return;
    setLoading(true);
    fetchWorkoutHistory(email)
      .then(data => { setSessions(data); setError(null); })
      .catch(err  => setError(err.message))
      .finally(() => setLoading(false));
  }, [email]);

  return { sessions, loading, error };
}

// ─── EMAIL AUTOMATION (Resend via Supabase Edge Function) ────────────────────
// These call a Supabase Edge Function "rvn-mailer" which holds the Resend secret.
// Never call Resend directly from the client (key would be exposed).
//
// Edge function endpoint: supabase/functions/rvn-mailer/index.ts
// Expected body: { type: "password_reset"|"apex_milestone"|"welcome", email, payload }
//
// Trigger apex milestone email when bio_score crosses RVN_PROD.apexBioScoreThreshold.

async function sendApexMilestoneEmail({ email, name, bioScore, archetypeId }) {
  try {
    const client = await getSupaClient();
    await client.functions.invoke("rvn-mailer", {
      body: {
        type:    "apex_milestone",
        email:   sanitize(email),
        payload: {
          name:        sanitize(name),
          bio_score:   validateBioScore(bioScore),
          archetype:   sanitize(archetypeId),
          unlock_url:  `${window.location.origin}?rvn_apex=1`,
        },
      },
    });
  } catch (e) { console.warn("[RVN] Apex email failed:", e.message); }
}

async function sendPasswordResetEmail(email) {
  try {
    const client = await getSupaClient();
    // Supabase Auth handles password reset emails natively
    const { error } = await client.auth.resetPasswordForEmail(sanitize(email), {
      redirectTo: `${window.location.origin}?rvn_reset=1`,
    });
    if (error) throw error;
  } catch (e) { console.warn("[RVN] Password reset email failed:", e.message); }
}

// ─── FEEDBACK / BUG REPORT ───────────────────────────────────────────────────
// SQL: create table rvn_feedback (
//   id uuid primary key default gen_random_uuid(),
//   profile_email text, screen text, state_snapshot jsonb,
//   message text, created_at timestamptz default now()
// );
// alter table rvn_feedback enable row level security;
// create policy "Anyone can insert feedback"
//   on rvn_feedback for insert with check (true);

async function submitBugReport({ email, screen, stateSnapshot, message }) {
  const record = {
    profile_email:  sanitize(email  || "anonymous"),
    screen:         sanitize(screen || "unknown"),
    state_snapshot: stateSnapshot || {},
    message:        sanitize(message || ""),
    created_at:     new Date().toISOString(),
  };
  try {
    const client = await getSupaClient();
    await client.from("rvn_feedback").insert(record);
  } catch (_) {}
  // Always log locally too
  try {
    const raw  = JSON.parse(window.localStorage.getItem("rvn_feedback") || "[]");
    const list = Array.isArray(raw) ? raw : [];
    list.unshift(record);
    window.localStorage.setItem("rvn_feedback", JSON.stringify(list.slice(0, 20)));
  } catch (_) {}
  track("Bug Report Submitted", { screen: record.screen });
}

// ─── SupaStatusBadge — shows DB connection status in manager hub ─────────────
function SupaStatusBadge({ theme }) {
  const T = D[theme];
  const [status, setStatus] = useState("connecting"); // connecting | online | offline

  useEffect(() => {
    getSupaClient()
      .then(async (client) => {
        // Ping by fetching zero rows
        const { error } = await client.from("rvn_profiles").select("email").limit(1);
        setStatus(error ? "offline" : "online");
      })
      .catch(() => setStatus("offline"));
  }, []);

  const color = status === "online" ? T.green : status === "offline" ? T.red : T.blue;
  const label = status === "online" ? "SUPABASE · LIVE" :
                status === "offline" ? "SUPABASE · OFFLINE" : "SUPABASE · …";

  return (
    <div style={{
      display:"inline-flex", alignItems:"center", gap:6,
      padding:"4px 10px", borderRadius:10,
      background:`${color}14`, border:`1px solid ${color}55`,
    }}>
      <div style={{
        width:6, height:6, borderRadius:3, background:color,
        boxShadow: status === "online" ? `0 0 8px ${color}` : "none",
        animation: status === "connecting" ? "os_pulse 1.2s ease-in-out infinite" : "none",
      }}/>
      <span style={{ fontSize:9, fontWeight:800, color, letterSpacing:".14em" }}>{label}</span>
    </div>
  );
}

// ─── CloudSignInScreen — Supabase email + password auth ─────────────────────
function CloudSignInScreen({ onSignIn, onNewUser, onBack, theme = "dark", mode = "gym" }) {
  const T = D[theme];
  const M = OS_MODES[mode] || OS_MODES.gym;
  const ac = T[M.accentKey];

  // phases: lookup → password
  const [email,     setEmail]     = useState("");
  const [password,  setPassword]  = useState("");
  const [showPass,  setShowPass]  = useState(false);
  const [phase,     setPhase]     = useState("lookup");
  const [msg,       setMsg]       = useState("");
  const [busy,      setBusy]      = useState(false);
  const [profiles,  setProfiles]  = useState([]);
  const [loadingList, setLoadingList] = useState(true);

  useEffect(() => {
    setLoadingList(true);
    rvnListProfiles()
      .then(list => { setProfiles(list); setLoadingList(false); })
      .catch(() => setLoadingList(false));
  }, []);

  // Step 1: verify profile exists, then ask for password
  const handleLookup = async () => {
    if (!email.trim()) return;
    setBusy(true); setMsg("");
    const found = await rvnFindProfile(email.trim());
    if (found) { setPhase("password"); setBusy(false); }
    else { setMsg("No vault found for that email. Create one below."); setBusy(false); }
  };

  // Tap saved card — pre-fill email, jump to password phase
  const pickProfile = (prof) => {
    const e = (prof.user?.email || "").trim();
    if (e) { setEmail(e); setMsg(""); setPhase("password"); }
  };

  // Step 2: Supabase signInWithPassword
  const handleSignIn = async () => {
    if (!password.trim()) { setMsg("Please enter your password."); return; }
    setBusy(true); setMsg("");
    try {
      const client = await getSupaClient();
      const { error } = await client.auth.signInWithPassword({
        email: email.trim(),
        password: password.trim(),
      });
      if (error) throw error;
      const profile = await rvnFindProfile(email.trim());
      setBusy(false);
      onSignIn && onSignIn(profile || { user: { email: email.trim() } });
    } catch (e) {
      setBusy(false);
      setMsg(e.message === "Invalid login credentials"
        ? "Wrong password. Try again."
        : (e.message || "Sign-in failed."));
    }
  };

  return (
    <Screen theme={theme}>
      <div style={{ padding:"20px 22px 0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <BackBtn onBack={onBack} theme={theme}/>
        <RVNLogo size={30}/>
      </div>

      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", padding:"8px 24px 36px" }}>
        <motion.div {...FX.up} style={{ textAlign:"center", marginTop:14, marginBottom:18 }}>
          <Pill label="◉  BIO-VAULT · CLOUD SYNC" color={ac} theme={theme}/>
          <div style={{ fontSize:28, fontWeight:900, letterSpacing:"-.02em", color:T.text, marginTop:14, lineHeight:1.02 }}>
            Welcome<br/>Back.
          </div>
          <div style={{ fontSize:12, color:T.muted, marginTop:6, maxWidth:280 }}>
            Protected by Supabase Auth. Your data syncs across every device.
          </div>
          <div style={{ marginTop:8 }}>
            <SupaStatusBadge theme={theme}/>
          </div>
        </motion.div>

        {/* ── LOOKUP phase ─────────────────────────────────────────────────── */}
        {phase === "lookup" && (
          <>
            {/* Saved profiles list */}
            {!loadingList && profiles.length > 0 && (
              <motion.div {...FX.up} style={{ width:"100%", maxWidth:360, marginBottom:14 }}>
                <div style={{ fontSize:9.5, fontWeight:800, color:T.faint, letterSpacing:".14em", marginBottom:8, paddingLeft:4 }}>
                  SAVED PROFILES · CLOUD + DEVICE
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {profiles.slice(0, 5).map((prof, i) => {
                    const label = prof.user?.name  || prof.user?.email || "Athlete";
                    const sub   = prof.user?.email || (prof.archetypeId || "").replace(/_/g," ").toUpperCase();
                    return (
                      <motion.button key={i} whileTap={{ scale:.98 }}
                        onClick={() => pickProfile(prof)}
                        style={{
                          textAlign:"left", background:T.glass,
                          border:`1px solid ${T.border}`,
                          borderRadius:14, padding:"12px 14px", cursor:"pointer",
                          display:"flex", alignItems:"center", justifyContent:"space-between", gap:12,
                        }}>
                        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                          <div style={{
                            width:36, height:36, borderRadius:18,
                            background:`linear-gradient(135deg, ${ac}33, ${ac}11)`,
                            border:`1px solid ${ac}55`,
                            display:"flex", alignItems:"center", justifyContent:"center",
                            fontSize:13, fontWeight:900, color:ac,
                          }}>{(label[0] || "A").toUpperCase()}</div>
                          <div>
                            <div style={{ fontSize:14, fontWeight:800, color:T.text }}>{label}</div>
                            <div style={{ fontSize:10, color:T.muted, letterSpacing:".06em", marginTop:2 }}>{sub}</div>
                          </div>
                        </div>
                        <div style={{ fontSize:10, fontWeight:800, color:ac, letterSpacing:".14em" }}>SIGN IN →</div>
                      </motion.button>
                    );
                  })}
                </div>
              </motion.div>
            )}

            {loadingList && (
              <div style={{ color:T.faint, fontSize:11, letterSpacing:".12em", marginBottom:14 }}>
                SYNCING VAULT…
              </div>
            )}

            {/* Email lookup */}
            <motion.div {...FX.up} style={{ width:"100%", maxWidth:360 }}>
              <GlassCard theme={theme} style={{ padding:"14px 16px", border:`1px solid ${ac}22`, marginBottom:10 }}>
                <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                  EMAIL
                </div>
                <input value={email} type="email"
                  onChange={e => { setEmail(e.target.value); setMsg(""); }}
                  onKeyDown={e => e.key === "Enter" && !busy && handleLookup()}
                  placeholder="you@domain.com"
                  style={{ width:"100%", fontSize:17, fontWeight:600 }}/>
              </GlassCard>

              {msg && <div style={{ fontSize:11, color:T.red, marginBottom:8, textAlign:"center" }}>{msg}</div>}

              <ShimmerCTA
                label={busy ? "Searching…" : "Find My Vault  ◉"}
                onClick={() => !busy && handleLookup()}
                theme={theme} color={ac}
                disabled={busy || !email.trim()}/>

              <div style={{ textAlign:"center", marginTop:14 }}>
                <div style={{ fontSize:10, color:T.faint, letterSpacing:".1em", marginBottom:6 }}>FIRST TIME ON RVN?</div>
                <motion.button whileTap={{ scale:.96 }} onClick={onNewUser}
                  style={{
                    background:"transparent", border:`1px solid ${T.border}`,
                    borderRadius:20, padding:"8px 16px", cursor:"pointer",
                    fontSize:11, fontWeight:800, color:T.text, letterSpacing:".1em",
                  }}>
                  CREATE BIO-IDENTITY →
                </motion.button>
              </div>
            </motion.div>
          </>
        )}

        {/* ── PASSWORD phase ───────────────────────────────────────────────── */}
        {phase === "password" && (
          <motion.div {...FX.up} style={{ width:"100%", maxWidth:360 }}>
            {/* Account pill */}
            <GlassCard theme={theme} style={{ padding:"12px 14px", marginBottom:10, border:`1px solid ${ac}33` }}>
              <div style={{ fontSize:9, color:T.faint, letterSpacing:".14em", marginBottom:3 }}>VAULT FOUND</div>
              <div style={{ fontSize:15, fontWeight:800, color:T.text }}>{email}</div>
            </GlassCard>

            {/* Password field */}
            <GlassCard theme={theme} style={{ padding:"14px 16px", marginBottom:8, border:`1px solid ${ac}22` }}>
              <div style={{ fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".12em", marginBottom:5 }}>
                PASSWORD
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                <input
                  type={showPass ? "text" : "password"}
                  value={password}
                  onChange={e => { setPassword(e.target.value); setMsg(""); }}
                  onKeyDown={e => e.key === "Enter" && !busy && handleSignIn()}
                  placeholder="••••••••"
                  autoFocus
                  style={{
                    flex:1, fontSize:18, fontWeight:600,
                    letterSpacing: showPass ? ".02em" : ".24em",
                  }}/>
                <button onClick={() => setShowPass(s => !s)}
                  style={{
                    background:"transparent", border:`1px solid ${T.border}`,
                    borderRadius:8, padding:"4px 9px", cursor:"pointer",
                    fontSize:9.5, fontWeight:700, color:T.faint, letterSpacing:".08em",
                    flexShrink:0,
                  }}>
                  {showPass ? "HIDE" : "SHOW"}
                </button>
              </div>
            </GlassCard>

            {msg && (
              <div style={{ fontSize:11, color:T.red, marginBottom:8, textAlign:"center", letterSpacing:".04em" }}>
                {msg}
              </div>
            )}

            <ShimmerCTA
              label={busy ? "Verifying…" : "Unlock Bio-Vault  ◉"}
              onClick={() => !busy && handleSignIn()}
              theme={theme} color={ac}
              disabled={busy || !password.trim()}/>

            <div style={{ textAlign:"center", marginTop:10 }}>
              <button onClick={() => { setPhase("lookup"); setPassword(""); setMsg(""); }}
                style={{
                  background:"transparent", border:"none",
                  color:T.muted, fontSize:11, cursor:"pointer", letterSpacing:".08em",
                }}>
                ← DIFFERENT ACCOUNT
              </button>
            </div>
          </motion.div>
        )}
      </div>
    </Screen>
  );
}

