// ── SubscriptionGate ──────────────────────────────────────────────────────────
// Wrap any screen that requires an active subscription.
// If sub is loading → spinner. If not active → show SubscriptionScreen.
function SubscriptionGate({ userId, email, onBack, theme, children }) {
  const { isActive, subLoading } = useSubscription(userId);

  if (subLoading) {
    return (
      <div style={{
        display: "flex", alignItems: "center", justifyContent: "center",
        minHeight: "100vh", background: "#0a0a0a",
        fontFamily: RVN_MONO,
      }}>
        <div style={{ color: "#333", fontSize: 10, letterSpacing: 4 }}>
          VERIFYING ACCESS…
        </div>
      </div>
    );
  }

  if (!isActive) {
    return (
      <SubscriptionScreen
        userId={userId}
        email={email}
        onBack={onBack}
        theme={theme}
      />
    );
  }

  return children;
}

