// ── useSurgicalVisionRecs — recommend content based on user data ──────────────
function useSurgicalVisionRecs(bioLogic) {
  const readiness  = bioLogic?.readiness  || 75;
  const soreness   = bioLogic?.soreness   || 0;
  const avgProtein = bioLogic?.avgProtein || 0;

  return RVN_SEED_CONTENT.filter(c => {
    if (!c.svRecommended || !c.svRecommended.length) return false;
    for (const rule of c.svRecommended) {
      if (rule === "pregame") return true;
      if (rule === "pre-workout") return true;
      if (rule.includes("readiness <") && readiness < parseInt(rule.split("<")[1])) return true;
      if (rule.includes("readiness >") && readiness > parseInt(rule.split(">")[1])) return true;
      if (rule.includes("soreness >") && soreness > parseInt(rule.split(">")[1])) return true;
      if (rule.includes("avg_protein <") && avgProtein < parseInt(rule.split("<")[1])) return true;
    }
    return false;
  });
}

// ── VideoPlayer ────────────────────────────────────────────────────────────────
function RVNVideoPlayer({ video, onClose, theme }) {
  const T = D[theme];
  const [playing, setPlaying] = useState(false);
  const videoRef = useRef(null);

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (playing) {
      videoRef.current.pause();
    } else {
      videoRef.current.play();
    }
    setPlaying(p => !p);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 20 }}
      style={{
        position: "fixed", inset: 0, zIndex: 200,
        background: "#000",
        display: "flex", flexDirection: "column",
      }}
    >
      {/* Header */}
      <div style={{
        display: "flex", justifyContent: "space-between", alignItems: "center",
        padding: "16px 20px",
        background: "rgba(0,0,0,.8)",
      }}>
        <div>
          <div style={{ fontSize: 13, fontWeight: 700, color: "#fff" }}>{video.title}</div>
          <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>
            {video.creator === "RVN" ? "⚡ RVN Original" : `🏋️ ${video.creator}`} · {video.duration}
          </div>
        </div>
        <motion.button
          whileTap={{ scale: .9 }}
          onClick={onClose}
          style={{ background: "none", border: "none", color: "#fff", fontSize: 22, cursor: "pointer" }}
        >✕</motion.button>
      </div>

      {/* Video Area */}
      <div style={{
        flex: 1, display: "flex", alignItems: "center", justifyContent: "center",
        background: "#0a0a0a", position: "relative",
      }}>
        {video.videoUrl ? (
          <video
            ref={videoRef}
            src={video.videoUrl}
            style={{ width: "100%", maxHeight: "70vh", objectFit: "contain" }}
            onClick={togglePlay}
            onPlay={() => setPlaying(true)}
            onPause={() => setPlaying(false)}
          />
        ) : (
          // Placeholder when no video is uploaded yet
          <div style={{
            display: "flex", flexDirection: "column", alignItems: "center", gap: 12,
            color: "#444",
          }}>
            <div style={{ fontSize: 48 }}>▶</div>
            <div style={{ fontSize: 13 }}>Video coming soon</div>
            <div style={{ fontSize: 11, color: "#333" }}>Upload via Manager Hub → Content</div>
          </div>
        )}
      </div>

      {/* Description */}
      <div style={{
        padding: "16px 20px",
        background: "rgba(0,0,0,.9)",
      }}>
        <p style={{ fontSize: 12, color: "#888", margin: 0, lineHeight: 1.6 }}>
          {video.description}
        </p>
        <div style={{ display: "flex", gap: 8, marginTop: 10, flexWrap: "wrap" }}>
          {(video.tags || []).map(tag => (
            <span key={tag} style={{
              padding: "3px 8px", borderRadius: 20,
              background: "rgba(255,255,255,.05)",
              fontSize: 10, color: "#666",
              border: "1px solid #222",
            }}>{tag}</span>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

