// ── ContentScreen (Main) ───────────────────────────────────────────────────────
function ContentScreen({ profile, gymContent, onBack, theme }) {
  const T = D[theme];
  const bioLogic = profile?.bioLogic || {};
  const [category, setCategory] = useState("all");
  const [activeVideo, setActiveVideo] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");

  const svRecs = useSurgicalVisionRecs(bioLogic);
  const gymContentList = gymContent || [];

  // Merge RVN + gym content
  const allContent = [...RVN_SEED_CONTENT, ...gymContentList];

  const filtered = allContent.filter(v => {
    const matchCat = category === "all" || v.category === category;
    const matchSearch = !searchQuery || v.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (v.tags || []).some(t => t.includes(searchQuery.toLowerCase()));
    return matchCat && matchSearch;
  });

  const svRecIds = new Set(svRecs.map(v => v.id));

  return (
    <>
      <AnimatePresence>
        {activeVideo && (
          <RVNVideoPlayer
            key="video-player"
            video={activeVideo}
            onClose={() => setActiveVideo(null)}
            theme={theme}
          />
        )}
      </AnimatePresence>

      <div style={{
        background: T.bg, color: T.fg,
        padding: 20,
        fontFamily: FONT_SANS,
        minHeight: "100vh",
        paddingBottom: 100,
      }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div>
            <h2 style={{ fontSize: 20, fontWeight: 800, margin: 0 }}>Content</h2>
            <p style={{ fontSize: 11, color: T.muted, margin: "3px 0 0 0" }}>RVN Originals + Your Gym's Library</p>
          </div>
          <button onClick={onBack} style={{ background: "none", border: "none", color: T.fg, fontSize: 20, cursor: "pointer" }}>✕</button>
        </div>

        {/* Search */}
        <input
          type="text"
          placeholder="Search workouts, nutrition, recovery…"
          value={searchQuery}
          onChange={e => setSearchQuery(e.target.value)}
          style={{
            width: "100%",
            padding: "10px 14px",
            border: `1px solid ${T.border}`,
            borderRadius: 10,
            background: T.card,
            color: T.fg,
            fontSize: 13,
            marginBottom: 16,
            fontFamily: FONT_SANS,
          }}
        />

        {/* Category tabs */}
        <div style={{ display: "flex", gap: 8, overflowX: "auto", marginBottom: 20, paddingBottom: 4 }}>
          {CONTENT_CATEGORIES.map(cat => (
            <motion.button
              key={cat.id}
              whileTap={{ scale: .93 }}
              onClick={() => setCategory(cat.id)}
              style={{
                padding: "6px 14px", borderRadius: 20, whiteSpace: "nowrap",
                background: category === cat.id ? T.blue : T.card,
                border: `1px solid ${category === cat.id ? T.blue : T.border}`,
                color: category === cat.id ? "#fff" : T.muted,
                fontSize: 10, fontWeight: 700, letterSpacing: ".06em",
                cursor: "pointer",
              }}
            >
              {cat.icon} {cat.label}
            </motion.button>
          ))}
        </div>

        {/* Surgical Vision Recommendations */}
        {svRecs.length > 0 && category === "all" && !searchQuery && (
          <div style={{ marginBottom: 24 }}>
            <div style={{
              fontSize: 10, fontWeight: 800, color: T.muted,
              letterSpacing: ".14em", marginBottom: 12,
            }}>
              ⚡ RECOMMENDED FOR YOU · BASED ON YOUR DATA
            </div>
            {svRecs.map(v => (
              <ContentCard
                key={v.id}
                video={v}
                onPlay={setActiveVideo}
                theme={theme}
                highlighted={true}
              />
            ))}
          </div>
        )}

        {/* All / Filtered Content */}
        <div style={{ fontSize: 10, fontWeight: 800, color: T.muted, letterSpacing: ".14em", marginBottom: 12 }}>
          {category === "all" && !searchQuery ? "ALL CONTENT" : "RESULTS"} ({filtered.length})
        </div>
        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", color: T.muted, fontSize: 13, marginTop: 40 }}>
            No content found. Try a different category or ask your gym to upload more.
          </div>
        ) : (
          filtered.map(v => (
            <ContentCard
              key={v.id}
              video={v}
              onPlay={setActiveVideo}
              theme={theme}
              highlighted={svRecIds.has(v.id)}
            />
          ))
        )}
      </div>
    </>
  );
}

// ── GymContentManager — Manager Hub tab for uploading content ─────────────────
function GymContentManager({ gymContent, onAddContent, onRemoveContent, theme }) {
  const T = D[theme];
  const [title, setTitle]         = useState("");
  const [category, setCategory]   = useState("workout");
  const [duration, setDuration]   = useState("");
  const [description, setDesc]    = useState("");
  const [videoFile, setVideoFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [uploaded, setUploaded]   = useState(false);

  const handleUpload = async () => {
    if (!title || !videoFile) return;
    setUploading(true);
    try {
      // In production: upload to Supabase storage
      // const { data } = await supabase.storage.from("gym-content").upload(`${Date.now()}-${videoFile.name}`, videoFile);
      // const videoUrl = data?.path ? supabase.storage.from("gym-content").getPublicUrl(data.path).data.publicUrl : null;
      const videoUrl = URL.createObjectURL(videoFile); // Local preview
      const newContent = {
        id: `gym-${Date.now()}`,
        title,
        creator: "Gym",
        category,
        duration: duration || "Unknown",
        description,
        videoUrl,
        thumbnail: null,
        tags: [category],
        svRecommended: [],
      };
      onAddContent && onAddContent(newContent);
      setTitle(""); setCategory("workout"); setDuration(""); setDesc(""); setVideoFile(null);
      setUploaded(true);
      setTimeout(() => setUploaded(false), 3000);
    } catch (e) {
      console.error("Upload failed:", e);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div style={{ padding: "16px 0" }}>
      <div style={{ fontSize: 10, fontWeight: 800, color: T.faint, letterSpacing: ".14em", marginBottom: 14 }}>
        UPLOAD CONTENT
      </div>

      <input
        type="text"
        placeholder="Video title"
        value={title}
        onChange={e => setTitle(e.target.value)}
        style={{
          width: "100%", padding: "10px 12px", borderRadius: 8,
          background: T.glass, border: `1px solid ${T.border}`,
          color: T.text, fontSize: 13, marginBottom: 10,
        }}
      />

      <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
        <select
          value={category}
          onChange={e => setCategory(e.target.value)}
          style={{
            flex: 1, padding: "10px 12px", borderRadius: 8,
            background: T.glass, border: `1px solid ${T.border}`,
            color: T.text, fontSize: 13,
          }}
        >
          {CONTENT_CATEGORIES.filter(c => c.id !== "all").map(c => (
            <option key={c.id} value={c.id}>{c.label}</option>
          ))}
        </select>
        <input
          type="text"
          placeholder="Duration (e.g. 20 min)"
          value={duration}
          onChange={e => setDuration(e.target.value)}
          style={{
            flex: 1, padding: "10px 12px", borderRadius: 8,
            background: T.glass, border: `1px solid ${T.border}`,
            color: T.text, fontSize: 13,
          }}
        />
      </div>

      <textarea
        placeholder="Short description…"
        value={description}
        onChange={e => setDesc(e.target.value)}
        rows={2}
        style={{
          width: "100%", padding: "10px 12px", borderRadius: 8,
          background: T.glass, border: `1px solid ${T.border}`,
          color: T.text, fontSize: 13, resize: "none",
          marginBottom: 10, fontFamily: FONT_SANS,
        }}
      />

      {/* File upload */}
      <label style={{
        display: "block", padding: "10px 12px",
        border: `1px dashed ${videoFile ? T.green : T.border}`,
        borderRadius: 8, cursor: "pointer", textAlign: "center",
        fontSize: 12, color: videoFile ? T.green : T.muted,
        marginBottom: 10,
      }}>
        {videoFile ? `✓ ${videoFile.name}` : "Tap to upload video file"}
        <input
          type="file"
          accept="video/*"
          onChange={e => setVideoFile(e.target.files[0] || null)}
          style={{ display: "none" }}
        />
      </label>

      <motion.button
        whileTap={{ scale: .96 }}
        onClick={handleUpload}
        disabled={uploading || !title || !videoFile}
        style={{
          width: "100%", padding: 12,
          background: uploaded ? T.green : (title && videoFile ? T.blue : T.glass),
          color: uploaded ? "#000" : (title && videoFile ? "#fff" : T.faint),
          border: "none", borderRadius: 8,
          fontSize: 13, fontWeight: 700, cursor: title && videoFile ? "pointer" : "not-allowed",
        }}
      >
        {uploading ? "Uploading…" : uploaded ? "✓ Uploaded!" : "Upload Content"}
      </motion.button>

      {/* Existing gym content list */}
      {(gymContent || []).length > 0 && (
        <div style={{ marginTop: 20 }}>
          <div style={{ fontSize: 10, fontWeight: 800, color: T.faint, letterSpacing: ".14em", marginBottom: 10 }}>
            YOUR CONTENT ({gymContent.length})
          </div>
          {gymContent.map(v => (
            <div key={v.id} style={{
              display: "flex", justifyContent: "space-between", alignItems: "center",
              padding: "10px 12px", background: T.glass, borderRadius: 8,
              border: `1px solid ${T.border}`, marginBottom: 6,
            }}>
              <div>
                <div style={{ fontSize: 12, fontWeight: 700, color: T.text }}>{v.title}</div>
                <div style={{ fontSize: 10, color: T.faint }}>{v.category} · {v.duration}</div>
              </div>
              <motion.button
                whileTap={{ scale: .9 }}
                onClick={() => onRemoveContent && onRemoveContent(v.id)}
                style={{ background: "none", border: "none", color: T.red || "#f87171", cursor: "pointer", fontSize: 16 }}
              >✕</motion.button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

