// ─── MANAGER PIN ──────────────────────────────────────────────────────────────
function ManagerPIN({ onUnlock, onBack, theme }) {
  const T = D[theme];
  const [pin, setPin] = useState("");
  const [shake, setShake] = useState(false);
  const [attempts, setAttempts] = useState(0);
  const CORRECT = "0000";

  const press = (d) => {
    if (pin.length >= 4) return;
    const next = pin + String(d);
    setPin(next);
    if (next.length === 4) {
      if (next === CORRECT) {
        setTimeout(onUnlock, 280);
      } else {
        setAttempts(a => a+1);
        setShake(true);
        setTimeout(() => { setPin(""); setShake(false); }, 700);
      }
    }
  };

  return (
    <Screen theme={theme}>
      <div style={{ padding:"22px 22px 0" }}>
        <BackBtn onBack={onBack} theme={theme}/>
      </div>
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:32 }}>
        <RVNLogo size={48} style={{ marginBottom:18 }}/>
        <div style={{ fontSize:10, fontWeight:700, letterSpacing:".18em", color:T.faint, marginBottom:6 }}>
          MANAGER ACCESS
        </div>
        <div style={{ fontSize:28, fontWeight:900, color:T.text, marginBottom:8 }}>Command Center</div>
        {attempts > 0 && (
          <div style={{ fontSize:11, color:T.red, marginBottom:12 }}>
            Incorrect PIN ({attempts} attempt{attempts>1?"s":""})
          </div>
        )}

        {/* Dots */}
        <motion.div animate={shake ? { x:[-10,10,-10,10,0] } : {}}
          transition={{ duration:.4 }}
          style={{ display:"flex", gap:16, margin:"16px 0 32px" }}>
          {[0,1,2,3].map(i => (
            <motion.div key={i}
              animate={{ scale: i < pin.length ? 1.2 : 1 }}
              transition={{ type:"spring", stiffness:400, damping:20 }}
              style={{
                width:14, height:14, borderRadius:"50%",
                background: i < pin.length ? T.blue : T.glass,
                border:`1.5px solid ${i < pin.length ? T.blue : T.border}`,
                boxShadow: i < pin.length ? `0 0 14px ${T.blue}88` : "none",
              }}/>
          ))}
        </motion.div>

        {/* Keypad */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,74px)", gap:10 }}>
          {[1,2,3,4,5,6,7,8,9,"",0,"⌫"].map((d, i) => (
            <motion.button key={i}
              whileTap={d !== "" ? { scale:.85 } : {}}
              onClick={() => {
                if (d === "⌫") setPin(p => p.slice(0,-1));
                else if (d !== "") press(d);
              }}
              style={{
                width:74, height:74, borderRadius:17,
                background: d === "" ? "transparent" : T.glass,
                backdropFilter: d !== "" ? "blur(12px)" : "none",
                border: d === "" ? "none" : `1px solid ${T.border}`,
                fontSize: d === "⌫" ? 18 : 24, fontWeight:700, color:T.text,
                cursor: d !== "" ? "pointer" : "default",
              }}>
              {d}
            </motion.button>
          ))}
        </div>

        <div style={{ marginTop:20, fontSize:11, color:T.faint }}>Default PIN: 0000</div>
      </div>
    </Screen>
  );
}

// ─── ANALYTICS MINI CHART ────────────────────────────────────────────────────
function AnalyticsBar({ label, value, max, color, theme }) {
  const T = D[theme];
  const pct = (value/max)*100;
  return (
    <div style={{ marginBottom:8 }}>
      <div style={{ display:"flex", justifyContent:"space-between", marginBottom:3 }}>
        <span style={{ fontSize:10, color:T.muted, fontWeight:600 }}>{label}</span>
        <span style={{ fontSize:10, color, fontWeight:800 }}>{value}</span>
      </div>
      <div style={{ height:4, background:T.glass, borderRadius:2, overflow:"hidden" }}>
        <motion.div
          style={{ height:"100%", background:color, borderRadius:2, boxShadow:`0 0 8px ${color}88` }}
          initial={{ width:0 }}
          animate={{ width:`${pct}%` }}
          transition={{ duration:1, ease:[.22,1,.36,1] }}/>
      </div>
    </div>
  );
}

